function monitorValue(v,type="number"){if(v==null)return '<span class="monitor-na">N/A</span>';if(type==="money")return UI.money(v);if(type==="percent")return UI.percent(v,2);return UI.displayNumber(v,{maximumFractionDigits:2})}

function intradayMonitorValue(r,field,type="money"){const value=r[field];if(value!=null)return monitorValue(value,type);const reason=r.intraday_estimate_unavailable_reason||"Estimate unavailable";return `<span class="monitor-na" title="${UI.escapeHtml(reason)}">${UI.escapeHtml(reason)}</span>`}

function costValue(v){return v==null?"Unavailable":UI.displayNumber(v,{style:"currency",currency:"USD",minimumFractionDigits:2,maximumFractionDigits:4})}

function isPendingAdmission(s){return s?.membership_state==="approved_pending"||s?.current_operational_status==="PRE_OPERATIONAL"||s?.operational_state==="approved_pending"||s?.operational_state==="PRE_OPERATIONAL"}

function pendingProposedWeight(c,s){return s.proposed_post_admission_sleeve_weight??s.proposed_post_admission_weight??c.capital_reconciliation?.pending_post_admission_sleeve_weight??c.portfolio_summary?.approved_equal_weight}

function allocationCurrentValue(s){return isPendingAdmission(s)?"N/A":UI.percent(s.current_weight,2)}

function allocationChangeValue(s,p){return isPendingAdmission(s)?"N/A":UI.percent(p-(s.current_weight||0),2)}

function allocationCostValue(s){return isPendingAdmission(s)?"N/A":UI.money(s.total_cost)}

function allocationAction(s,current,proposed){return isPendingAdmission(s)?"ADMISSION BLOCKED / PENDING EVIDENCE":proposed!==current?"PAPER REBALANCE REVIEW":"ACTIVE PAPER SLEEVE"}

function allocationStateLabel(s){return isPendingAdmission(s)?"PENDING ADMISSION":"ACTIVE PAPER SLEEVE"}

function strategyPrimaryState(s){if(isPendingAdmission(s))return "APPROVED_PENDING / PRE_OPERATIONAL";if(s.internal_id==="COMBINED_PORTFOLIO")return "Active Composite";return s.membership_state==="executed"?"Active Paper":operationalDisplayLabel(s)}

function strategyPrimaryTone(s){return isPendingAdmission(s)?"pending":s.internal_id==="COMBINED_PORTFOLIO"?"info":"ok"}

function strategySecondaryState(s){if(isPendingAdmission(s))return "Current Sleeve: N/A | Operational NAV/P&L: N/A | Paper Fill: No Paper Fill | Live Fill: No Live Brokerage Fill | Next Action: Pending admission evidence";if(s.internal_id==="COMBINED_PORTFOLIO")return "Execution Mode: Derived | Provenance: Derived from ordinary strategy net returns | Live Fill: No | No separate Combined paper fills | No cost double count";return "Execution Mode: Paper Only | Provenance: Pending | Live Fill: No"}

function strategyRawDataState(r){return r.data_state||r.data_status}

function strategyMonitorDataState(s){if(isPendingAdmission(s))return "Pending evidence";if(s.internal_id==="COMBINED_PORTFOLIO")return "Derived Complete";return "Paper ledger loaded"}

function monitorHead(label,key){return `<th data-sort="${key}" class="${state.sortKey===key?"sorted":""}">${label}${state.sortKey===key?` <span>${state.sortDir>0?"ASC":"DESC"}</span>`:""}</th>`}

function monitorFilterBar(rows){const families=[...new Set(monitorEntities().map(r=>r.family))].sort(),statuses=[["","All statuses"],["executed","Active paper"]],data=[...new Set(monitorEntities().map(r=>r.data_status).filter(Boolean))].sort();return `<div class="monitor-filterbar"><label class="search-control"><span aria-hidden="true">&#9906;</span><input id="strategyFilter" type="search" value="${UI.escapeHtml(state.strategyFilter)}" placeholder="Search strategy, ID, family" aria-label="Search strategies"></label><select id="familyFilter"><option value="">All families</option>${families.map(x=>`<option ${state.familyFilter===x?"selected":""}>${x}</option>`).join("")}</select><select id="stateFilter">${statuses.map(([v,l])=>`<option value="${v}" ${state.membershipFilter===v?"selected":""}>${l}</option>`).join("")}</select><select id="dataFilter"><option value="">All data states</option>${data.map(x=>`<option ${state.dataFilter===x?"selected":""}>${x}</option>`).join("")}</select><span id="filterCount">${rows.length} current rows</span><span class="monitor-freshness">${freshnessLabel(state.contract)} | ${refreshStatusLabel(state.contract)}</span></div>`}

function strategyPanel(){const rows=monitorFiltered(),pending=currentPendingRows(state.contract),active=currentActiveRows(state.contract),inv=state.contract.strategy_entity_inventory||{},headers=[["Display only","display_id"],["Strategy Name","display_name"],["Family","family"],["Status","current_operational_status"],["Effective","strategy_effective_date"],["Sleeve Wt.","sleeve_weight"],["Daily Ret.","daily_return"],["Daily P&L","daily_pnl"],["Intraday Est. P&L","intraday_estimated_pnl"],["Intraday Est. NAV","intraday_estimated_nav"],["Cum. Ret.","cumulative_return"],["Cum. P&L","cumulative_pnl"],["Portfolio Contrib.","combined_portfolio_contribution"],["Current DD","current_drawdown"],["Max DD","max_drawdown"],["Daily Turn.","daily_turnover"],["Ann. Turn.","annualized_turnover"],["Daily Cost","daily_cost"],["Cum. Cost","cumulative_cost"],["Gross Exp.","gross_exposure"],["Net Exp.","net_exposure"],["L / S","long_count"],["Holdings","holdings_count"],["Last Signal","last_signal"],["Last Rebalance","last_rebalance"],["Last Execution","last_execution"],["Data State","data_state"],["Action","display_id"]];const body=rows.map(r=>`<tr class="${r.internal_id===state.selectedStrategy?"selected":""} ${r.internal_id==="COMBINED_PORTFOLIO"?"combined-strategy-row":""} ${r.strategy_factory_phase2?"phase2-unallocated-row":""}" data-row-id="${r.internal_id}"><td><strong class="display-id">${UI.escapeHtml(r.display_id||"Display only")}</strong><small>Display-only label</small></td><td><strong>${UI.escapeHtml(r.ui_name)}</strong></td><td>${UI.escapeHtml(r.family||"N/A")}</td><td>${UI.StatusBadge({label:strategyPrimaryState(r),tone:strategyPrimaryTone(r),dot:true})}</td><td>${r.strategy_effective_date||"N/A"}</td><td>${monitorValue(r.sleeve_weight,"percent")}</td><td class="tone-${UI.toneForNumber(r.daily_return)}">${monitorValue(r.daily_return,"percent")}</td><td class="tone-${UI.toneForNumber(r.daily_pnl)}">${monitorValue(r.daily_pnl,"money")}</td><td class="tone-${UI.toneForNumber(r.intraday_estimated_pnl)}">${intradayMonitorValue(r,"intraday_estimated_pnl","money")}</td><td class="tone-${UI.toneForNumber(r.intraday_estimated_pnl)}">${intradayMonitorValue(r,"intraday_estimated_nav","money")}</td><td class="tone-${UI.toneForNumber(r.cumulative_return)}">${monitorValue(r.cumulative_return,"percent")}</td><td class="tone-${UI.toneForNumber(r.cumulative_pnl)}">${monitorValue(r.cumulative_pnl,"money")}</td><td class="tone-${UI.toneForNumber(r.combined_portfolio_contribution)}">${monitorValue(r.combined_portfolio_contribution,"money")}</td><td>${monitorValue(r.current_drawdown,"percent")}</td><td>${monitorValue(r.max_drawdown,"percent")}</td><td>${monitorValue(r.daily_turnover,"percent")}</td><td>${monitorValue(r.annualized_turnover,"percent")}</td><td>${r.internal_id==="COMBINED_PORTFOLIO"?"N/A":monitorValue(r.daily_cost,"money")}</td><td>${r.internal_id==="COMBINED_PORTFOLIO"?"N/A":monitorValue(r.cumulative_cost,"money")}</td><td>${monitorValue(r.gross_exposure)}</td><td>${monitorValue(r.net_exposure)}</td><td>${r.long_count==null?"N/A":`${r.long_count} / ${r.short_count}`}</td><td>${r.holdings_count??"N/A"}</td><td>${r.last_signal||"N/A"}</td><td>${r.last_rebalance||"N/A"}</td><td>${r.last_execution||"N/A"}</td><td>${UI.StatusBadge({label:strategyMonitorDataState(r),tone:strategyPrimaryTone(r)})}</td><td><button class="view-row" data-view-id="${r.internal_id}">VIEW</button></td></tr>`).join("");return `<section class="panel strategy-monitor-panel" id="strategyPanel">${UI.SectionHeader({title:"Strategy operational registry",meta:`Current active ${active.length}: ${inv.ordinary_operational_ledgers??"N/A"} ordinary + Combined; ${pending.length} pending / inactive rows separated. Display-only label; canonical identity uses strategy_uid.`,action:'<span class="live-label"><i></i> snapshot-linked</span>'})}${monitorFilterBar(rows)}<div class="monitor-table-wrap" id="strategyTable"><table class="monitor-table"><thead><tr>${headers.map(x=>monitorHead(x[0],x[1])).join("")}</tr></thead><tbody>${body}</tbody></table></div><footer class="monitor-table-footer"><span>Intraday Est. values use delayed market prices and are not Official Ledger. Display-only label; canonical identity uses strategy_uid.</span><b>${rows.length} visible current rows</b><span>${pending.length} pending / inactive rows separated</span></footer></section>`}

function alerts(c){const active=currentActiveRows(c).length,pending=currentPendingRows(c).length;return UI.Panel({title:"Data & reconciliation alerts",meta:`${c.alerts.length} open`,className:"alerts-panel",body:`<div class="alert-row warning"><b>MED</b><span><strong>Official promotion review</strong><small>${promotionValue(c)}</small></span><em>REVIEW</em></div><div class="alert-row info"><b>INFO</b><span><strong>Brokerage execution disabled</strong><small>Paper-only decision support. Real Funded Brokerage Capital: $0. No live fills.</small></span><em>ACK</em></div><div class="alert-row positive"><b>PASS</b><span><strong>Current operating set reconciled</strong><small>${active} active sleeves; ${pending} pending current candidates.</small></span><em>OK</em></div><div class="pending-card compact"><div>${UI.StatusBadge({label:pending?"PENDING REVIEW":"NO PENDING CANDIDATE",tone:pending?"pending":"ok",dot:true})}<strong>Current membership</strong><span>Paper holdings and official ledger remain separate from delayed estimates.</span></div><b>${active} active</b></div>`})}

function timeline(c){const pending=currentPendingRows(c),pendingDate=c.pending_membership?.effective_from||c.portfolio_summary.as_of_date;return UI.Panel({title:"Membership timeline",meta:"Date-effective operational truth",className:"timeline-panel",body:`<div class="timeline"><div class="timeline-line"></div><div class="timeline-event done"><i></i><b>${c.portfolio_daily[0].date}</b><strong>N=${currentActiveRows(c).length} active paper sleeves</strong><span>Equal sleeve ${UI.percent(c.portfolio_summary.current_equal_weight,2)}</span></div><div class="timeline-event done"><i></i><b>${c.portfolio_summary.as_of_date}</b><strong>Combined contains ${c.portfolio_summary.current_underlying_n}</strong><span>Current active underlyings</span></div><div class="timeline-event ${pending.length?"pending":"done"}"><i></i><b>${pendingDate}</b><strong>${pending.length} pending / inactive rows separated</strong><span>Registry status controls whether rows are active, pending, or inactive.</span></div></div>`})}

function commandStrategyTable(c){const rows=currentStrategyRows(c).map(s=>{const pending=isPendingAdmission(s);return `<tr><td><strong>${s.ui_name}</strong><small>${s.internal_id}</small></td><td>${UI.StatusBadge({label:strategyPrimaryState(s),tone:strategyPrimaryTone(s)})}<small>${strategySecondaryState(s)}</small></td><td>${pending?"N/A":UI.percent(s.current_weight,2)}</td><td class="tone-${UI.toneForNumber(s.daily_pnl)}">${pending?"N/A":UI.money(s.daily_pnl)}</td><td class="tone-${UI.toneForNumber(s.cumulative_pnl)}">${pending?"N/A":UI.money(s.cumulative_pnl)}</td><td class="tone-unavailable">${pending?"N/A":UI.percent(s.current_drawdown,2)}</td><td>${strategyMonitorDataState(s)}</td></tr>`});return `<section class="panel command-strategies">${UI.SectionHeader({title:"Strategy performance",meta:"Current active operating members"})}<div class="work-table-wrap"><table class="work-table"><thead><tr>${["Strategy","State","Weight","Daily P&L","Cumulative P&L","Current DD","Data"].map(x=>`<th>${x}</th>`).join("")}</tr></thead><tbody>${rows.join("")}</tbody></table></div></section>`}

function commandDecision(c){const active=currentActiveRows(c).length,pending=currentPendingRows(c).length;return UI.Panel({title:"Rebalance decision",meta:"Human governance gate",className:"command-decision",body:`<div class="decision-status"><span class="decision-code">${pending?"PENDING REVIEW":"NO PENDING CANDIDATE"}</span><strong>${active} active current rows; paper-only decision support</strong><p>Current operating membership excludes removed research candidates. Brokerage execution is disabled and no live fills are represented.</p><div><b>Live allocation</b><em>0%</em></div><div><b>Execution authority</b><em>DISABLED</em></div><div><b>Required action</b><em class="${pending?"tone-pending":"tone-positive"}">${pending?"Review pending evidence":"Monitor current set"}</em></div></div>`})}

function styleMix(c,scope="active"){const rows=c.strategies.filter(s=>s.membership_state==="executed"&&s.internal_id!=="COMBINED_PORTFOLIO"),total=rows.reduce((n,s)=>n+Number(s.current_weight||0),0)||1,m={};rows.forEach(s=>{const k=s.family||"Unclassified";m[k]=(m[k]||0)+Number(s.current_weight||0)});return Object.entries(m).sort((a,b)=>b[1]-a[1]).map(([family,weight])=>({family,weight:weight/total,count:rows.filter(s=>s.family===family).length}))}

function styleExposurePanel(c,{compact=false,title="Strategy Family Mix - Proxy Only, Not a Validated Factor Model"}={}){const mix=styleMix(c),rows=mix.map(x=>`<div class="style-row"><span>${x.family}<small>${x.count} strategies</small></span><b>${UI.percent(x.weight,1)}</b><i style="width:${Math.max(3,x.weight*100)}%"></i></div>`).join("");return UI.Panel({title,meta:"Derived from active strategy families, not a validated factor model. Proxy-only family mix; not real factor exposure.",className:`style-exposure-panel ${compact?"compact":""}`,body:`<div class="style-mix">${rows}<div class="model-status"><strong>PROXY ONLY / NOT VALIDATED FACTOR MODEL</strong><span>This is a portfolio construction proxy derived from active strategy families. It is not a Barra model, factor loading model, covariance model, VaR model, or ES model.</span><em>Factor contribution, scenario shock, and macro regime analytics remain Blocked / Not loaded.</em></div></div>`})}

function commandFactor(c){return styleExposurePanel(c,{compact:true,title:"Strategy Family Mix - Proxy Only, Not a Validated Factor Model"})}

function riskFactorValue(v,type){if(v==null||v==="")return "N/A";if(v==="Missing Metadata"||v==="Data Pending"||v==="Not Available")return v;if(type==="money")return UI.money(v);if(type==="percent")return UI.percent(v,2);return UI.escapeHtml(String(v))}

function factorSourceValue(r,keys){for(const key of keys){const value=r?.[key];if(value!=null&&value!=="")return value}return "Missing Metadata"}

function riskFactorCell(value,r){const pending=r.primary_status==="APPROVED_PENDING / PRE_OPERATIONAL",missing=value==null||value===""||["Missing Metadata","Data Pending","Not Available","N/A"].includes(value),numeric=Number.isFinite(Number(value)),qualitative=!numeric&&!missing;if(missing)return `<span class="factor-cell missing">Missing Metadata</span>`;if(pending)return `<span class="factor-cell pending">${UI.escapeHtml(String(value))}</span>`;if(numeric){const intensity=Math.min(1,Math.abs(Number(value))),sign=Number(value)<0?"negative":"positive";return `<span class="factor-cell loaded ${sign}" style="--heat:${intensity.toFixed(2)}">${UI.displayNumber(value,{maximumFractionDigits:3})}</span>`}return `<span class="factor-cell proxy">${UI.escapeHtml(String(value))}<small>metadata / expected</small></span>`}

function riskFactorEvidenceCell(r){const warning=r.missing_data_warning||"Missing Metadata",source=r.evidence_artifact_source||"Not Available";return `<span class="evidence-warning ${warning.includes("missing")||warning.includes("Missing")?"missing":"proxy"}">${UI.escapeHtml(warning)}</span><small>${UI.escapeHtml(source)}</small>`}

function riskDynamicMissingRowFromStrategy(s){const id=s.strategy_uid||s.strategy_id||s.internal_id,name=s.ui_name||s.display_name||s.name||id,phase2=!!s.strategy_factory_phase2;return {strategy_id:id,display_id:phase2?"Display only":s.display_id||"Display only",display_name:name,sleeve_type:phase2?"ACTIVE_UNALLOCATED_ZERO_WEIGHT":s.family||"CURRENT_ACTIVE_MISSING_FACTOR_EVIDENCE",primary_status:phase2?"ACTIVE_UNALLOCATED / PENDING_REBALANCE":strategyPrimaryState(s),capital_weight:Number(s.current_weight??s.sleeve_weight??0),nav:0,market_exposure:"Missing Metadata",size_exposure:"Missing Metadata",value_exposure:"Missing Metadata",momentum_exposure:"Missing Metadata",quality_exposure:"Missing Metadata",volatility_exposure:"Missing Metadata",liquidity_exposure:"Missing Metadata",event_filing_exposure:"Missing Metadata",microstructure_exposure:"Missing Metadata",crowding_concentration_exposure:"Missing Metadata",sector_bias:"Missing Metadata",position_source:phase2?"ACTIVE_UNALLOCATED_NO_POSITION_IMPACT":"MISSING_FACTOR_ARTIFACT",missing_data_warning:phase2?"Missing Evidence / Pending Rebalance / No portfolio impact":"Missing factor evidence for active strategy",evidence_artifact_source:s.evidence_status||"Missing Evidence",primary_risk_driver:phase2?"Active-unallocated Strategy Factory row; 0.00% current weight; no portfolio contribution until rebalance.":"Active strategy missing validated factor metadata",economic_logic:phase2?"No borrowed factor exposure; no fake metrics; pending rebalance.":"Missing factor artifact",strategy_factory_phase2:phase2,no_portfolio_impact:phase2,current_weight:Number(s.current_weight??s.sleeve_weight??0),spy_beta:"Not Available",spy_correlation:"Not Available",realized_vol_20d:"Not Available",realized_vol_60d:"Not Available",current_drawdown:s.current_drawdown??"Not Available",momentum_20d:"Not Available",liquidity_score:"Not Available",sector_top_exposure:"Not Available",price_coverage:"Not Available",warnings:phase2?"Missing Evidence / Pending Rebalance / No portfolio impact":"Missing factor evidence"}}

function riskDynamicUniverseRows(c,baseRows){const removed=riskRemovedStrategyIds(c),rows=[...(baseRows||[])].filter(r=>!removed.has(r.strategy_id)),seen=new Set(rows.map(r=>r.strategy_id));currentActiveRows(c).forEach(s=>{const id=s.strategy_uid||s.strategy_id||s.internal_id;if(!id||removed.has(id)||seen.has(id))return;rows.push(riskDynamicMissingRowFromStrategy(s));seen.add(id)});return rows}

function riskFactorRows(c){const rows=riskDynamicUniverseRows(c,c.risk_factor_big_table||[]);if(!rows.length)return '<tr><td colspan="18">Data Pending</td></tr>';return rows.map(r=>`<tr class="${r.strategy_id==="COMBINED_PORTFOLIO"?"combined-strategy-row":r.strategy_factory_phase2?"phase2-unallocated-row":r.primary_status==="APPROVED_PENDING / PRE_OPERATIONAL"?"pending-row":""}"><td><strong>${r.display_id||"N/A"}</strong><small>${r.strategy_id||"N/A"}</small></td><td><strong>${UI.escapeHtml(r.display_name||"N/A")}</strong><small>${UI.escapeHtml(r.primary_risk_driver||r.economic_logic||"Missing Metadata")}</small></td><td>${r.sleeve_type||"N/A"}</td><td>${UI.StatusBadge({label:r.primary_status||"N/A",tone:r.primary_status==="APPROVED_PENDING / PRE_OPERATIONAL"||r.strategy_factory_phase2?"pending":r.primary_status==="Active Composite"?"info":"ok"})}</td><td>${riskFactorValue(r.capital_weight,"percent")}<small>${riskFactorValue(r.nav,"money")}</small></td><td>${riskFactorCell(r.market_exposure,r)}</td><td>${riskFactorCell(r.size_exposure,r)}</td><td>${riskFactorCell(r.value_exposure,r)}</td><td>${riskFactorCell(r.momentum_exposure,r)}</td><td>${riskFactorCell(r.quality_exposure,r)}</td><td>${riskFactorCell(r.volatility_exposure,r)}</td><td>${riskFactorCell(r.liquidity_exposure,r)}</td><td>${riskFactorCell(factorSourceValue(r,["event_filing_exposure","event_filing_risk","event_filing_metadata"]),r)}</td><td>${riskFactorCell(factorSourceValue(r,["microstructure_exposure","microstructure_risk","microstructure_metadata"]),r)}</td><td>${riskFactorCell(factorSourceValue(r,["crowding_concentration_exposure","crowding_concentration_risk","correlation_diversification_note"]),r)}</td><td>${riskFactorCell(factorSourceValue(r,["sector_bias","sector_exposure","sector_metadata"]),r)}</td><td><strong>${r.position_source||"N/A"}</strong><small>${r.no_portfolio_impact?"No portfolio impact until rebalance":r.legacy_artifact_position_estimate_authoritative===false?"legacy artifact estimate not authoritative":""}</small></td><td>${riskFactorEvidenceCell(r)}</td></tr>`).join("")}

function riskFactorBigTable(c){const rows=riskDynamicUniverseRows(c,c.risk_factor_big_table||[]),counts=phase2UniverseCounts(c),combined=rows.find(r=>r.strategy_id==="COMBINED_PORTFOLIO"),source=rows[0]?.position_source||"committed_shadow_holdings";return `<section class="panel span-12 risk-factor-big-table-panel risk-factor-matrix-v2">${UI.SectionHeader({title:"Risk Factor Matrix v2",meta:`Dynamic strategy universe; ${rows.length} visible rows; ordinary ${counts.ordinary_active_count} + Combined ${counts.combined_active_count}; active-unallocated ${counts.active_unallocated_count}; position source ${source}`})}<div class="matrix-legend"><span><i class="missing"></i>Missing Metadata</span><span><i class="pending"></i>Pending / pre-operational</span><span><i class="proxy"></i>Metadata / expected, not quantitative beta</span><span><i class="loaded"></i>Loaded exposure value</span></div>${table(["Strategy / Sleeve","Display Name","Sleeve Type","Primary Status","Weight / Capital","Market","Size","Value","Momentum","Quality","Volatility","Liquidity","Event / Filing","Microstructure","Crowding / Concentration","Sector Bias","Position Source","Evidence / Missing Warning"],riskFactorRows(c),"risk-factor-big-table risk-factor-matrix")}<footer class="monitor-table-footer"><span>Factor cells show Missing Metadata where validated strategy-level factor metadata is absent; active-unallocated rows are 0.00% current weight and no portfolio impact until rebalance.</span><b>Combined: ${combined?.primary_status||"N/A"} / ${combined?.sleeve_type||"N/A"}</b></footer></section>`}

function marketProxyValue(v,type){if(v==null||v==="")return "Not Available";if(typeof v==="object")return UI.escapeHtml(`${v.priced??"N/A"}/${v.total??"N/A"} ${v.status||""}`);if(["Insufficient History","Data Pending","Not Available","Coverage Missing","Not Applicable","Constituent-Derived Pending"].includes(v))return UI.escapeHtml(v);if(type==="percent")return UI.percent(v,2);if(type==="money")return UI.money(v);if(type==="number")return UI.displayNumber(v,{maximumFractionDigits:3});return UI.escapeHtml(String(v))}

function marketProxyCell(v,type){const numeric=Number.isFinite(Number(v)),pending=["Data Pending","Pending / Pre-operational","Not Applicable"].includes(v),missing=v==null||v===""||["Insufficient History","Not Available","Coverage Missing","Constituent-Derived Pending"].includes(v);if(pending)return `<span class="proxy-cell pending">${marketProxyValue(v,type)}</span>`;if(missing)return `<span class="proxy-cell missing">${marketProxyValue(v,type)}</span>`;if(numeric){const intensity=Math.min(1,Math.abs(Number(v))),sign=Number(v)<0?"negative":"positive";return `<span class="proxy-cell loaded ${sign}" style="--heat:${intensity.toFixed(2)}">${marketProxyValue(v,type)}</span>`}return `<span class="proxy-cell label">${marketProxyValue(v,type)}</span>`}

function marketProxyStateLabel(r){if(r.primary_status==="APPROVED_PENDING / PRE_OPERATIONAL")return "Pending / Pre-operational";return r.primary_status||r.sleeve_type||"N/A"}

function marketProxyRowIssues(r){const issues=[];if(r.spy_beta==="Insufficient History"||r.spy_correlation==="Insufficient History"||r.realized_vol_20d==="Insufficient History")issues.push("Insufficient return history");if(["Coverage Missing","Not Available"].includes(r.momentum_20d)||["Coverage Missing","Not Available"].includes(r.weighted_avg_dollar_volume))issues.push("Coverage missing");if(r.sector_top_exposure==="Not Available")issues.push("Sector unavailable");if(r.proxy_status==="Pending / Pre-operational")issues.push("Pending / pre-operational");if(!r.holdings_count)issues.push("No holdings");return [...new Set(issues)].join(" | ")||"Loaded"}

function marketProxyRows(c){const removed=riskRemovedStrategyIds(c),rows=(c.risk_factor_market_proxy_table||[]).filter(r=>!removed.has(r.strategy_id));if(!rows.length)return '<tr><td colspan="8">Data Pending</td></tr>';return rows.map(r=>{const pending=r.primary_status==="APPROVED_PENDING / PRE_OPERATIONAL",combined=r.strategy_id==="COMBINED_PORTFOLIO";return `<tr class="${combined?"combined-strategy-row":pending?"pending-row":""}"><td><strong>${r.display_id||"N/A"}</strong><small>${UI.escapeHtml(r.display_name||"N/A")} | ${r.strategy_id||"N/A"}</small></td><td>${UI.StatusBadge({label:marketProxyStateLabel(r),tone:pending?"pending":combined?"info":"ok"})}<small>${UI.escapeHtml(r.sleeve_type||"N/A")}</small></td><td>${marketProxyValue(r.current_weight,"percent")}<small>${marketProxyValue(r.capital,"money")}</small></td><td>${marketProxyCell(r.current_drawdown,"percent")}</td><td>${marketProxyCell(r.momentum_20d,"percent")}<small>63D ${marketProxyValue(r.momentum_63d,"percent")}</small></td><td>${marketProxyCell(r.liquidity_score)}<small>ADV ${marketProxyValue(r.weighted_avg_dollar_volume,"money")}</small></td><td>${marketProxyCell(r.top_holding_concentration,"percent")}<small>Top 5 ${marketProxyValue(r.top_5_concentration,"percent")}</small></td><td><strong>${UI.escapeHtml(r.data_status||"N/A")}</strong><small>${marketProxyValue(r.price_coverage)} | ${UI.escapeHtml(marketProxyRowIssues(r))}</small></td></tr>`}).join("")}

function marketReadinessPanel(rows){const total=rows.length||1,betaReady=rows.filter(r=>Number.isFinite(Number(r.spy_beta))).length,volReady=rows.filter(r=>Number.isFinite(Number(r.realized_vol_20d))).length,sectorReady=rows.filter(r=>String(r.sector_top_exposure||"").includes(":")).length,numericMomentum=rows.filter(r=>Number.isFinite(Number(r.momentum_20d))).length;return `<div class="market-readiness-strip"><div><span>SPY beta / corr</span><b>${betaReady}/${total} ready</b><em>Insufficient History until >=20 overlapping observations</em></div><div><span>Volatility</span><b>${volReady}/${total} ready</b><em>20D / 60D require enough strategy return observations</em></div><div><span>Momentum / liquidity</span><b>${numericMomentum}/${total} populated</b><em>Cached delayed yfinance holdings overlay</em></div><div><span>Sector</span><b>${sectorReady}/${total} cached</b><em>Not Available unless cached metadata exists</em></div><div><span>Model type</span><b>Market Data Proxy</b><em>Not validated Barra / institutional model; no live brokerage positions/fills</em></div></div>`}

function marketProxyTable(c){const removed=riskRemovedStrategyIds(c),rows=(c.risk_factor_market_proxy_table||[]).filter(r=>!removed.has(r.strategy_id)),combined=rows.find(r=>r.strategy_id==="COMBINED_PORTFOLIO");return `<section class="panel span-12 market-proxy-panel risk-factor-matrix-v2">${UI.SectionHeader({title:"Market Data Risk Proxy Matrix",meta:`risk_factor_market_proxy_table; ${rows.length} current strategy/sleeve rows; populated proxy fields prioritized`})}<div class="proxy-disclosure"><span>Market-data proxy from cached delayed yfinance overlay. Not a validated Barra / institutional factor model. Not live market data. No live brokerage positions/fills.</span></div>${marketReadinessPanel(rows)}${table(["Strategy","Status","Weight","Drawdown","Momentum","Liquidity / ADV","Concentration","Data / Coverage"],marketProxyRows(c),"market-proxy-table risk-factor-matrix")}<footer class="monitor-table-footer"><span>SPY beta/correlation and volatility readiness are summarized above; missing values remain status labels, not zero.</span><b>Combined: ${combined?.primary_status||"N/A"} / ${combined?.proxy_status||"N/A"}</b></footer></section>`}

const RISK_HEATMAP_COLUMNS=[{group:"Identity",label:"Strategy",kind:"strategy"},{group:"Operational",label:"Status",kind:"status"},{group:"Paper Allocation / Ledger",label:"Weight",kind:"weight"},{group:"Research / Backtest Metric",label:"Sharpe",kind:"research",metric:"net_sharpe",type:"number"},{group:"Research / Backtest Metric",label:"Ann Ret",kind:"research",metric:"annualized_return",type:"percent"},{group:"Research / Backtest Metric",label:"Max DD",kind:"research",metric:"max_drawdown",type:"percent"},{group:"Research / Backtest Metric",label:"Beta",kind:"market",keys:["research_beta","spy_beta"],type:"number"},{group:"Research / Backtest Metric",label:"Corr",kind:"market",keys:["research_correlation","spy_correlation"],type:"number"},{group:"Research / Backtest Metric",label:"Vol",kind:"market",keys:["research_volatility","realized_vol_20d","realized_vol_60d"],type:"percent"},{group:"Paper Allocation / Ledger",label:"Curr DD",kind:"market",keys:["current_drawdown"],type:"percent"},{group:"Loaded Numeric Market Proxy",label:"Mom20",kind:"market",keys:["momentum_20d"],type:"percent"},{group:"Loaded Numeric Market Proxy",label:"Mom63",kind:"market",keys:["momentum_63d"],type:"percent"},{group:"Loaded Numeric Market Proxy",label:"Liquidity",kind:"liquidity"},{group:"Loaded Numeric Market Proxy",label:"Top Hold",kind:"market",keys:["top_holding_concentration"],type:"percent"},{group:"Loaded Numeric Market Proxy",label:"Top5",kind:"market",keys:["top_5_concentration"],type:"percent"},{group:"Design Proxy",label:"Family",kind:"design"},{group:"Reference / Status",label:"Quality",kind:"quality"}]

function riskRemovedStrategyIds(c){return new Set(c.removed_from_current_workstation_strategy_ids||c.risk_factors?.removed_from_current_workstation_strategy_ids||[])}

function riskHeatmapSourceRows(c){const removed=riskRemovedStrategyIds(c),marketRows=(c.risk_factor_market_proxy_table||[]).filter(r=>!removed.has(r.strategy_id)),fallback=(c.risk_factor_big_table||[]).filter(r=>!removed.has(r.strategy_id)).map(fullHeatmapFromBigRow);return riskDynamicUniverseRows(c,marketRows.length?marketRows:fallback)}

function riskStrategiesById(c){return Object.fromEntries((c.strategies||[]).map(s=>[s.internal_id,s]))}

function riskResearchMetrics(s){return s?.research_evidence?.research_metrics||{}}

function riskAllDecisionRows(c){const strategies=riskStrategiesById(c);return riskHeatmapSourceRows(c).map(r=>({row:r,strategy:strategies[r.strategy_id]||{},research:riskResearchMetrics(strategies[r.strategy_id])})).sort((a,b)=>{const rank=x=>x.row.strategy_id==="COMBINED_PORTFOLIO"?0:(x.row.primary_status==="APPROVED_PENDING / PRE_OPERATIONAL"?2:1);return rank(a)-rank(b)})}

function riskExcludedRows(c){return riskAllDecisionRows(c).filter(d=>d.row.primary_status==="APPROVED_PENDING / PRE_OPERATIONAL")}

function riskDecisionRows(c){return riskAllDecisionRows(c).filter(d=>d.row.primary_status!=="APPROVED_PENDING / PRE_OPERATIONAL")}

function riskHeatmapFallbackValue(r,key){if(Object.prototype.hasOwnProperty.call(r,key))return r[key];if(["size_exposure","value_exposure","quality_exposure","momentum_exposure"].includes(key))return "Proxy Only";if(["tech_exposure","financials_exposure","energy_exposure","healthcare_exposure"].includes(key))return "Current S&P 500 reference universe Not Loaded";if(["inflation_exposure","duration_exposure","credit_exposure","fx_exposure","commodities_exposure"].includes(key))return "Future Layer";return "Data Pending"}

function riskHeatmapColumnValue(r,col){if(col.evidence==="status"){if(r.primary_status==="APPROVED_PENDING / PRE_OPERATIONAL")return "Pending / Pre-operational";return marketProxyRowIssues(r)==="Loaded"?"Loaded":"Review"}for(const key of col.keys||[col.key]){const value=riskHeatmapFallbackValue(r,key);if(value!=null&&value!==""&&!["Data Pending","Not Available","Unavailable","Coverage Missing","Not Loaded","Future Layer","Proxy Only","Current S&P 500 reference universe Not Loaded"].includes(value))return value}return col.benchmark?"Current S&P 500 reference universe Not Loaded":col.future?"Future Layer":col.evidence==="design"?"Proxy Only":"Data Pending"}

function riskHeatmapEvidenceClass(v,col){if(["Pending / Pre-operational","Not Applicable"].includes(v))return "pending";if(v==="Insufficient History")return "insufficient";if(col.future||v==="Future Layer")return "future";if(String(v).includes("S&P 500 reference universe Not Loaded")||["Not Available","Unavailable","Coverage Missing","Not Loaded","Missing Metadata","Constituent-Derived Pending"].includes(v))return "missing";if(col.evidence==="design"||v==="Proxy Only")return "design";if(col.evidence==="benchmark"||col.benchmark)return "benchmark";if(v==="Review")return "pending";return "loaded"}

function riskHeatmapDisplayValue(v,type){if(v==="Research Metric Missing"||v==="No Paper Weight")return "N/A";if(v==="Insufficient History")return "I/H";if(v==="Data Pending")return "Pending";if(["Not Available","Unavailable","Coverage Missing","Not Loaded","Current S&P 500 reference universe Not Loaded"].includes(v))return "N/A";if(v==="Future Layer")return "Future";if(v==="Proxy Only")return "Proxy";if(v==="Pending / Pre-operational")return "Pending";if(v==="Not Applicable")return "N/A";return fullHeatmapValue(v,type)}

function riskHeatmapCell(r,col){const v=riskHeatmapColumnValue(r,col),numeric=Number.isFinite(Number(v)),cls=riskHeatmapEvidenceClass(v,col),title=`${col.label}: ${fullHeatmapValue(v,col.type)}`;if(numeric&&cls==="loaded"){const intensity=Math.min(1,Math.abs(Number(v))*2.4),sign=Number(v)<0?"negative":"positive";return `<span class="risk-heat-cell loaded ${sign}" title="${UI.escapeHtml(title)}" data-evidence="Loaded Numeric Proxy" style="--heat:${intensity.toFixed(2)}">${riskHeatmapDisplayValue(v,col.type)}</span>`}if(numeric&&cls==="benchmark"){const intensity=Math.min(1,Math.abs(Number(v))*2.4),sign=Number(v)<0?"negative":"positive";return `<span class="risk-heat-cell benchmark ${sign}" title="${UI.escapeHtml(title)}" data-evidence="S&P / Benchmark Reference Proxy" style="--heat:${intensity.toFixed(2)}">${riskHeatmapDisplayValue(v,col.type)}</span>`}const evidence={benchmark:"S&P / Benchmark Reference Proxy",design:"Design Proxy",future:"Not Loaded / Future Layer",insufficient:"Insufficient History",pending:"Pending / Pre-operational",missing:"Not Loaded / Future Layer",loaded:"Loaded Numeric Proxy"}[cls];return `<span class="risk-heat-cell ${cls}" title="${UI.escapeHtml(title)}" data-evidence="${evidence}">${riskHeatmapDisplayValue(v,col.type)}</span>`}

function riskHeatmapNumeric(v){return v!==null&&v!==undefined&&v!==""&&Number.isFinite(Number(v))}

function riskHeatmapLargestConcentrationValue(r){const values=[r.top_5_concentration,r.top_holding_concentration].filter(riskHeatmapNumeric).map(Number);return values.length?Math.max(...values):null}

function riskPortfolioExposureCard(c){const p=c.portfolio_summary||{};return `<article class="exposure-card"><span>Net Exposure</span><b>${riskHeatmapNumeric(p.net_exposure)?`${UI.displayNumber(p.net_exposure,{minimumFractionDigits:2,maximumFractionDigits:2})}x`:"N/A"}</b><em>Gross ${riskHeatmapNumeric(p.gross_exposure)?`${UI.displayNumber(p.gross_exposure,{minimumFractionDigits:2,maximumFractionDigits:2})}x`:"N/A"}</em></article>`}

function riskActiveResearchMetrics(c){return (c.strategies||[]).filter(s=>s.internal_id!=="COMBINED_PORTFOLIO"&&!isPendingAdmission(s)).map(s=>riskResearchMetrics(s)).filter(m=>m&&Object.keys(m).length)}

function riskAverage(values){const clean=values.filter(riskHeatmapNumeric).map(Number);return clean.length?clean.reduce((a,b)=>a+b,0)/clean.length:null}

function riskMedian(values){const clean=values.filter(riskHeatmapNumeric).map(Number).sort((a,b)=>a-b);if(!clean.length)return null;const mid=Math.floor(clean.length/2);return clean.length%2?clean[mid]:(clean[mid-1]+clean[mid])/2}

function riskResearchSummary(c){const s=c.research_summary||{};if(Object.keys(s).length)return s;const combined=(c.strategies||[]).find(row=>row.internal_id==="COMBINED_PORTFOLIO"),combinedMetrics=riskResearchMetrics(combined),active=riskActiveResearchMetrics(c),activeDrawdowns=active.map(m=>m.max_drawdown).filter(riskHeatmapNumeric).map(Number),activeAvgSharpe=riskAverage(active.map(m=>m.net_sharpe));return {combined_sharpe_available:riskHeatmapNumeric(combinedMetrics.net_sharpe),combined_mdd_available:riskHeatmapNumeric(combinedMetrics.max_drawdown),combined_sharpe:combinedMetrics.net_sharpe,combined_max_drawdown:combinedMetrics.max_drawdown,active_strategy_metrics_count:active.length,active_avg_sharpe:activeAvgSharpe,active_median_sharpe:riskMedian(active.map(m=>m.net_sharpe)),worst_active_mdd:activeDrawdowns.length?Math.min(...activeDrawdowns):null,labels:{active_avg_sharpe:"Active Avg / Research",active_median_sharpe:"Active Median / Research",worst_active_mdd:"Worst Active / Research"},quality_flags:{active_avg_sharpe:riskHeatmapNumeric(activeAvgSharpe)&&Number(activeAvgSharpe)<0.8?"Below 0.80 target":null}}}

function riskResearchSharpeCard(c){const summary=riskResearchSummary(c),quality=summary.quality_flags?.active_avg_sharpe;if(summary.combined_sharpe_available&&riskHeatmapNumeric(summary.combined_sharpe))return `<article class="research-card"><span>Research Sharpe</span><b>${UI.displayNumber(summary.combined_sharpe,{minimumFractionDigits:2,maximumFractionDigits:2})}</b><em>Combined / Research</em></article>`;if(riskHeatmapNumeric(summary.active_avg_sharpe))return `<article class="research-card" title="${UI.escapeHtml(quality||"Active strategy research fallback")}"><span>Research Sharpe</span><b>${UI.displayNumber(summary.active_avg_sharpe,{minimumFractionDigits:2,maximumFractionDigits:2})}</b><em>${UI.escapeHtml(summary.labels?.active_avg_sharpe||"Active Avg / Research")}</em></article>`;if(riskHeatmapNumeric(summary.active_median_sharpe))return `<article class="research-card"><span>Research Sharpe</span><b>${UI.displayNumber(summary.active_median_sharpe,{minimumFractionDigits:2,maximumFractionDigits:2})}</b><em>${UI.escapeHtml(summary.labels?.active_median_sharpe||"Active Median / Research")}</em></article>`;return `<article class="research-card"><span>Research Sharpe</span><b>N/A</b><em>Research</em></article>`}

function riskDrawdownCard(c){const summary=riskResearchSummary(c);if(summary.combined_mdd_available&&riskHeatmapNumeric(summary.combined_max_drawdown))return `<article class="drawdown-card"><span>Drawdown</span><b>${UI.percent(summary.combined_max_drawdown,1)}</b><em>Combined / Research</em></article>`;return `<article class="drawdown-card"><span>Drawdown</span><b>${riskHeatmapNumeric(summary.worst_active_mdd)?UI.percent(summary.worst_active_mdd,1):"N/A"}</b><em>${riskHeatmapNumeric(summary.worst_active_mdd)?UI.escapeHtml(summary.labels?.worst_active_mdd||"Worst Active / Research"):"Research"}</em></article>`}

function riskSpyBenchmarkCard(c){const b=c.benchmark_reference||{};return `<article class="benchmark-card"><span>SPY Benchmark</span><b>${riskHeatmapNumeric(b.return_20d)?UI.percent(b.return_20d,1):"N/A"}</b><em>${riskHeatmapNumeric(b.return_63d)?`63D ${UI.percent(b.return_63d,1)}`:riskHeatmapNumeric(b.volatility_20d)?`20D Vol ${UI.percent(b.volatility_20d,1)}`:"Delayed proxy"}</em></article>`}

function riskHeatmapSummaryCards(c){return `<section class="risk-workstation-cards">${riskPortfolioExposureCard(c)}${riskResearchSharpeCard(c)}${riskDrawdownCard(c)}${riskSpyBenchmarkCard(c)}</section>`}

function riskBenchmarkStrip(c){const b=c.benchmark_reference||{},u=c.sp500_reference_universe||{};const item=(label,value)=>`<span><em>${label}</em><b>${value}</b></span>`;return `<section class="risk-benchmark-strip">${item("Benchmark",UI.escapeHtml(b.benchmark_symbol||"SPY"))}${item("SPY 20D",riskHeatmapNumeric(b.return_20d)?UI.percent(b.return_20d,1):"N/A")}${item("SPY 63D",riskHeatmapNumeric(b.return_63d)?UI.percent(b.return_63d,1):"N/A")}${item("SPY 20D Vol",riskHeatmapNumeric(b.volatility_20d)?UI.percent(b.volatility_20d,1):"N/A")}${item("Obs",riskHeatmapNumeric(b.observations)?UI.displayNumber(b.observations,{maximumFractionDigits:0}):"N/A")}${item("S&P 500",riskHeatmapNumeric(u.constituent_count)?UI.displayNumber(u.constituent_count,{maximumFractionDigits:0}):"N/A")}</section>`}

function riskCell(title,value,type,cls,evidence){return `<span class="risk-heat-cell ${cls}" title="${UI.escapeHtml(`${title}: ${fullHeatmapValue(value,type)}`)}" data-evidence="${evidence}">${riskHeatmapDisplayValue(value,type)}</span>`}

function riskShortMetricValue(v,type,title=""){if(!riskHeatmapNumeric(v))return riskHeatmapDisplayValue(v,type);if(type==="percent")return UI.percent(v,["Max DD","Curr DD","Top Hold","Top5"].includes(title)?1:2);if(type==="number")return UI.displayNumber(v,{minimumFractionDigits:2,maximumFractionDigits:2});return UI.displayNumber(v,{maximumFractionDigits:2})}

function riskMetricCell(title,value,type,cls,evidence){if(riskHeatmapNumeric(value)){const n=Number(value),intensity=Math.min(1,Math.abs(n)*(type==="percent"?2.8:0.8)),sign=n<0?"negative":"positive";return `<span class="risk-heat-cell ${cls} ${sign}" title="${UI.escapeHtml(`${title}: ${fullHeatmapValue(value,type)}`)}" data-evidence="${evidence}" style="--heat:${intensity.toFixed(2)}">${riskShortMetricValue(value,type,title)}</span>`}return riskCell(title,value,type,value==="Insufficient History"?"insufficient":value==="Pending / Pre-operational"?"pending":"missing",evidence)}

function riskResearchFactorCell(kind,value,type){const titles={Beta:"Research beta vs SPY; operational beta insufficient history",Corr:"Research corr vs SPY; operational corr insufficient history",Vol:"Research annualized vol; operational vol insufficient history"},display=type==="percent"&&riskHeatmapNumeric(value)?UI.percent(value,1):riskShortMetricValue(value,type,kind);if(riskHeatmapNumeric(value)){const n=Number(value),intensity=Math.min(1,Math.abs(n)*(type==="percent"?2.8:0.8)),sign=n<0?"negative":"positive";return `<span class="risk-heat-cell research ${sign}" title="${UI.escapeHtml(`${titles[kind]}: ${fullHeatmapValue(value,type)}`)}" data-evidence="Research / Backtest Metric" style="--heat:${intensity.toFixed(2)}">${display}</span>`}return riskCell(titles[kind],value,type,value==="Insufficient History"?"insufficient":"missing","Insufficient History")}

function riskCompactMoney(v){if(!riskHeatmapNumeric(v))return "Coverage Missing";const n=Number(v),abs=Math.abs(n);if(abs>=1e9)return `$${(n/1e9).toFixed(1)}B`;if(abs>=1e6)return `$${(n/1e6).toFixed(1)}M`;if(abs>=1e3)return `$${(n/1e3).toFixed(1)}K`;return UI.money(n)}

function riskLiquidityCell(r){const score=r.liquidity_score,adv=r.weighted_avg_dollar_volume;if(!riskHeatmapNumeric(score)&&!riskHeatmapNumeric(adv))return riskCell("Liquidity / ADV","Not Available",null,"missing","Loaded Numeric Market Proxy");const title=`Liquidity / ADV: score ${riskHeatmapNumeric(score)?UI.displayNumber(score,{maximumFractionDigits:3}):"Not Available"}; ADV ${riskHeatmapNumeric(adv)?UI.money(adv):"Coverage Missing"}`,intensity=riskHeatmapNumeric(score)?Math.min(1,Math.abs(Number(score))*0.8):0.25,display=riskHeatmapNumeric(score)?UI.displayNumber(score,{maximumFractionDigits:2}):riskCompactMoney(adv);return `<span class="risk-heat-cell loaded positive liquidity-cell" title="${UI.escapeHtml(title)}" data-evidence="Loaded Numeric Market Proxy" style="--heat:${intensity.toFixed(2)}">${display}</span>`}

function riskDecisionCell(d,col){const r=d.row,s=d.strategy,m=d.research;if(col.kind==="strategy")return `<div class="risk-strategy-cell"><strong>${r.display_id||"N/A"}</strong><small>${UI.escapeHtml(r.display_name||s.display_name||"N/A")}</small></div>`;if(col.kind==="status")return riskCell(col.label,marketProxyStateLabel(r),null,r.primary_status==="APPROVED_PENDING / PRE_OPERATIONAL"?"pending":r.strategy_id==="COMBINED_PORTFOLIO"?"benchmark":"loaded","Paper Allocation / Ledger Metric");if(col.kind==="weight"){const value=r.current_weight??s.current_weight??"No Paper Weight";return riskMetricCell(col.label,value,"percent","paper","Paper Allocation / Ledger Metric")}if(col.kind==="research"){return riskMetricCell(col.label,riskHeatmapNumeric(m[col.metric])?m[col.metric]:"Research Metric Missing",col.type,"research","Research / Backtest Metric")}if(col.kind==="market"){const value=riskHeatmapColumnValue(r,col);return ["Beta","Corr","Vol"].includes(col.label)?riskResearchFactorCell(col.label,value,col.type):riskMetricCell(col.label,value,col.type,"loaded","Loaded Numeric Market Proxy")}if(col.kind==="liquidity")return riskLiquidityCell(r);if(col.kind==="design"){return riskCell(col.label,`${UI.escapeHtml(s.family||r.sleeve_type||"Design Proxy")}`,null,"design","Design Proxy")}if(col.kind==="quality"){const issues=marketProxyRowIssues(r);return riskCell(col.label,issues==="Loaded"?"Loaded":"Review",null,issues==="Loaded"?"loaded":"pending",issues==="Loaded"?"Loaded Numeric Market Proxy":"Insufficient History")}if(col.kind==="fallback")return riskCell(col.label,"Design Proxy",null,"design","Design Proxy");if(col.kind==="sector")return riskCell(col.label,r.sector_top_exposure==="Not Available"?"Future Layer":r.sector_top_exposure,null,"future","Not Loaded / Future Layer");return riskCell(col.label,"Future Layer",null,"future","Not Loaded / Future Layer")}

function riskHeatmapRows(c){const rows=riskDecisionRows(c),columns=RISK_HEATMAP_COLUMNS;if(!rows.length)return `<tr><td colspan="${columns.length}">Data Pending</td></tr>`;return rows.map(r=>riskHeatmapRow(r,columns)).join("")}

function riskHeatmapRow(d,columns){const pending=d.row.primary_status==="APPROVED_PENDING / PRE_OPERATIONAL",combined=d.row.strategy_id==="COMBINED_PORTFOLIO",phase2=d.row.strategy_factory_phase2;return `<tr class="${combined?"combined-strategy-row":phase2?"phase2-unallocated-row":pending?"pending-row":""}">${columns.map(col=>`<td data-group="${UI.escapeHtml(col.group)}">${riskDecisionCell(d,col)}</td>`).join("")}</tr>`}

function riskHeatmapLegend(){return `<div class="risk-exposure-scale"><div class="risk-scale-labels"><span>-2.0</span><span>-1.0</span><span>0</span><span>+1.0</span><span>+2.0</span></div><div class="risk-scale-bar"></div><div class="risk-scale-copy"><b>Negative / Low / Short Exposure</b><span>Neutral</span><strong>Positive / High / Long Exposure</strong></div></div><div class="risk-heatmap-legend"><span><i class="loaded"></i>Loaded Numeric Market Proxy</span><span><i class="research"></i>Research / Backtest Metric</span><span><i class="paper"></i>Paper Allocation / Ledger Metric</span><span><i class="proxy"></i>Design Proxy</span><span><i class="insufficient"></i>Insufficient History</span><span><i class="future"></i>Not Loaded / Future Layer</span><span><i class="pending"></i>Pending / Pre-operational</span></div>`}

function riskReferenceUniverseNote(c){const u=c.sp500_reference_universe||{};return `<div class="risk-reference-note"><strong>S&P 500 Reference</strong><span>${UI.escapeHtml(u.description||"Current S&P 500 reference universe, not historical constituent-corrected.")}</span><b>${UI.escapeHtml(u.status||"NOT_LOADED")}</b></div>`}

function riskExcludedPendingSection(c){const rows=riskExcludedRows(c);if(!rows.length)return "";const body=rows.map(d=>`<tr><td>${d.row.display_id||"N/A"}</td><td>${UI.escapeHtml(d.row.display_name||d.strategy.display_name||"N/A")}</td><td>Pending / Pre-operational</td><td>Not active paper strategy / insufficient research evidence</td></tr>`).join("");return `<details class="risk-compact-detail"><summary>Excluded / Pending Research (${rows.length})</summary>${table(["ID","Strategy","Status","Reason"],body,"risk-excluded-table")}</details>`}

function riskFutureLayersSection(){const rows=["Value","Size","Credit","Duration","Inflation","FX","Commodities","Sector"].map(x=>`<tr><td>${x}</td><td>Not Loaded / Future Layer</td><td>Excluded from default active matrix until validated inputs exist.</td></tr>`).join("");return `<details class="risk-compact-detail"><summary>Future Institutional Factor Layers</summary>${table(["Layer","Status","Default handling"],rows,"risk-future-table")}</details>`}

function riskFactorHeatmap(c){const rows=riskDecisionRows(c),excluded=riskExcludedRows(c),counts=phase2UniverseCounts(c),source=(c.risk_factor_market_proxy_table||[]).length?"risk_factor_market_proxy_table + dynamic active universe":"risk_factor_big_table fallback + dynamic active universe",headers=RISK_HEATMAP_COLUMNS.map(x=>x.label);return `<section class="panel span-12 risk-factor-heatmap-v3">${UI.SectionHeader({title:"Risk Factor Exposure Matrix",meta:`${source}; ${rows.length} active visible rows; ordinary ${counts.ordinary_active_count} + Combined ${counts.combined_active_count}; active-unallocated ${counts.active_unallocated_count}; ${excluded.length} pending/excluded`})}<div class="risk-heatmap-toolbar"><span>Paper-only shadow-live portfolio. Active-unallocated rows remain 0.00% current weight with no portfolio impact until rebalance. Missing values remain explicit labels, not zero. Not a validated Barra / institutional factor model.</span><button type="button" disabled>Refresh status only</button><button type="button" disabled>Export Heatmap</button></div><div class="risk-heatmap-wrap">${table(headers,riskHeatmapRows(c),"risk-heatmap-table")}</div>${riskHeatmapLegend()}<footer class="monitor-table-footer"><span>Default matrix includes confirmed active rows from Strategy Monitor; missing factor exposure is neutral/missing evidence, never borrowed or fabricated.</span></footer></section>`}

function fullHeatmapValue(v,type){if(v==null||v==="")return "Not Available";if(typeof v==="object")return UI.escapeHtml(`${v.priced??"N/A"}/${v.total??"N/A"} ${v.status||""}`);if(v==="Missing Metadata")return "Not Loaded";if(["Insufficient History","Data Pending","Not Available","Coverage Missing","Not Applicable","Not Loaded","Constituent-Derived Pending"].includes(v))return UI.escapeHtml(v);if(type==="percent")return UI.percent(v,2);if(type==="money")return UI.money(v);if(type==="number")return UI.displayNumber(v,{maximumFractionDigits:3});return UI.escapeHtml(String(v))}

function fullHeatmapFromBigRow(r){return {strategy_id:r.strategy_id,display_id:r.display_id,display_name:r.display_name,sleeve_type:r.sleeve_type,primary_status:r.primary_status,current_weight:r.capital_weight,spy_beta:"Not Loaded",spy_correlation:"Not Loaded",realized_vol_20d:"Not Loaded",realized_vol_60d:"Not Loaded",current_drawdown:r.drawdown_risk_note||"Not Available",momentum_20d:r.momentum_exposure,liquidity_score:r.liquidity_exposure,sector_top_exposure:factorSourceValue(r,["sector_bias","sector_exposure","sector_metadata"]),size_exposure:r.size_exposure,value_exposure:r.value_exposure,quality_exposure:r.quality_exposure,event_filing_exposure:factorSourceValue(r,["event_filing_exposure","event_filing_risk","event_filing_metadata"]),microstructure_exposure:factorSourceValue(r,["microstructure_exposure","microstructure_risk","microstructure_metadata"]),crowding_concentration_exposure:factorSourceValue(r,["crowding_concentration_exposure","crowding_concentration_risk","correlation_diversification_note"]),price_coverage:"Not Available",warnings:r.missing_data_warning||"Not Available"}}

function riskSecondaryPanels(c,p){return `<section class="risk-secondary-strip compact">${UI.Panel({title:"Portfolio Exposure Summary",meta:"Latest canonical portfolio row",body:`<div class="risk-exposure-summary"><span><em>Gross</em><b>${UI.displayNumber(p.gross_exposure,{maximumFractionDigits:2})}</b></span><span><em>Net</em><b>${UI.displayNumber(p.net_exposure,{maximumFractionDigits:2})}</b></span><span><em>Long</em><b>${UI.displayNumber(p.long_exposure,{maximumFractionDigits:2})}</b></span><span><em>Short</em><b>${UI.displayNumber(p.short_exposure,{maximumFractionDigits:2})}</b></span></div>`})}${styleExposurePanel(c,{compact:true,title:"Strategy Family Mix - Proxy Only, Not a Validated Factor Model"})}${UI.Panel({title:"Model Readiness",meta:"Blocked institutional models",body:`<div class="risk-model-tags"><span><b>BLOCKED</b> VaR Not loaded</span><span><b>BLOCKED</b> ES Not loaded</span><span><b>BLOCKED</b> Scenario shock Not loaded</span><span><b>BLOCKED</b> Institutional factor model Not loaded</span><em>Proxy metrics do not substitute for Barra, VaR, ES, scenario, macro regime, or stress analytics.</em></div>`})}<details class="risk-governance-disclosure"><summary>Refresh Scheme B disclosure</summary><ul class="rule-list compact"><li><b>PASS</b> Rows come from risk_factor_market_proxy_table in /api/operational-snapshot when available; rendering does not hard-code strategy count.</li><li><b>PASS</b> Rows come from risk_factor_big_table in /api/operational-snapshot; rendering does not hard-code strategy count.</li><li><b>PASS</b> Rows come from risk_factor_big_table in /api/operational-snapshot as secondary metadata/fallback; rendering does not hard-code strategy count.</li><li><b>PASS</b> Combined Portfolio is displayed as Active Composite / Composite, separate from ordinary alpha strategies.</li><li><b>PASS</b> Removed research candidates are not active, pending, or excluded current Risk Factors rows.</li><li><b>PASS</b> position_source = committed_shadow_holdings when loaded from committed shadow holdings</li><li><b>PASS</b> legacy_artifact_position_estimate_authoritative = false</li><li><b>PASS</b> No live brokerage positions or fills are represented</li></ul></details></section>`}

function commandRisk(c){const latest=c.portfolio_daily.at(-1),pendingDate=c.pending_membership?.effective_from||"None";return UI.Panel({title:"Risk limits & alerts",meta:`${c.alerts.length} open`,className:"command-risk",body:`<div class="limit-list"><div><span>Gross exposure</span><b>${UI.displayNumber(latest.gross_exposure,{maximumFractionDigits:2})}</b><em class="ok">RECORDED</em></div><div><span>Net exposure</span><b>${UI.displayNumber(latest.net_exposure,{maximumFractionDigits:2})}</b><em class="ok">NEUTRAL</em></div><div><span>Current drawdown</span><b>Unavailable</b><em class="warn">REVIEW</em></div><div><span>Live allocation</span><b>0%</b><em class="ok">DISABLED</em></div><div><span>Membership transition</span><b>${pendingDate}</b><em class="ok">CLOSED</em></div></div>`})}

function commandCorrelation(){return UI.Panel({title:"Correlation summary",meta:"Shadow-live returns only",className:"command-correlation",body:`<div class="na-block"><strong>INSUFFICIENT HISTORY</strong><span>Correlation history does not meet the validated minimum. Missing correlations remain N/A.</span><div><b>Required history</b><em>20 observations</em></div><div><b>Average |corr|</b><em>N/A</em></div><div><b>Duplicate pairs</b><em>N/A</em></div></div>`})}

function commandRegime(c){return UI.Panel({title:"Market / regime status",meta:"Model status",className:"command-regime",body:`<div class="regime-block"><strong>MODEL NOT AVAILABLE</strong><span>No validated macro-regime field exists in the canonical contract.</span><div><b>Required data</b><em>Macro regime feed</em></div><div><b>As of</b><em>${c.portfolio_summary.as_of_date}</em></div><div><b>Fallback policy</b><em>BLOCKED</em></div></div>`})}

function commandRecommendation(c,title="Rebalance recommendation"){const rows=c.strategies.slice(0,5).map(s=>{const pending=isPendingAdmission(s),p=pending?pendingProposedWeight(c,s):c.portfolio_summary.approved_equal_weight;return `<tr><td>${s.ui_name}</td><td>${allocationCurrentValue(s)}</td><td>${UI.percent(p,2)}${pending?"<small>post-admission proposal</small>":""}</td><td class="${pending?"":p-(s.current_weight||0)>=0?"tone-positive":"tone-negative"}">${allocationChangeValue(s,p)}</td><td>${allocationAction(s,s.current_weight,p)}</td></tr>`});return `<section class="panel">${UI.SectionHeader({title,meta:"Post-admission proposal only where labeled"})}${table(["Strategy","Current %","Proposed %","Change %","Action"],rows)}</section>`}

function commandRebalanceCenter(c){const proposed=c.proposal_state?.proposed_weights||{},cr=c.capital_reconciliation||{},activeCount=currentActiveRows(c).length,rows=currentStrategyRows(c).slice(0,8).map(s=>{const pending=isPendingAdmission(s),p=pending?pendingProposedWeight(c,s):proposed[s.internal_id]??c.portfolio_summary.approved_equal_weight,current=s.current_weight,change=pending?null:p-current,costReason=pending?"pending admission / evidence required":s.internal_id==="COMBINED_PORTFOLIO"?"derived sleeve; no separate Combined paper fills":null;return `<tr><td>${s.ui_name}</td><td>${allocationCurrentValue(s)}</td><td>${UI.percent(p,2)}<small>${pending||p!==current?"paper proposal":"current"}</small></td><td class="${change==null?"":change>=0?"tone-positive":"tone-negative"}">${allocationChangeValue(s,p)}</td><td>${costReason||"N/A"}</td><td>${costReason?"N/A":allocationCostValue(s)}</td><td>${allocationAction(s,current,p)}</td></tr>`});return `<section class="panel rebalance-center">${UI.SectionHeader({title:"Rebalance decision center",meta:`Current ${UI.percent(cr.top_level_sleeve_weight,2)}; pending rows separated by status`})}${table(["Strategy","Current %","Proposed %","Change %","Reason","Est. cost","Action"],rows)}<div class="rebalance-subgrid"><div class="action-tiles"><button data-decision-action="APPROVE" class="approve-tile" ${state.decisionBusy?"disabled":""}>APPROVE<span>Paper review</span></button><button data-decision-action="REJECT" class="reject-tile" ${state.decisionBusy?"disabled":""}>REJECT<span>Paper review</span></button><button data-decision-action="MODIFY" class="modify-tile" ${state.decisionBusy?"disabled":""}>MODIFY<span>Paper review</span></button></div><div class="mini-summary"><strong>Paper rebalance governance</strong><div><span>Brokerage execution</span><b>Disabled</b></div><div><span>Live orders</span><b>No</b></div><div><span>Authority</span><b class="tone-pending">No execution authority</b></div></div><div class="mini-summary"><strong>Risk improvement summary</strong><div><span>Current drawdown</span><b>N/A</b></div><div><span>Correlation</span><b>N/A</b></div><div><span>Execution authorized</span><b>NO</b></div></div></div><div class="ai-summary"><strong>Paper rebalance governance</strong><span>Current allocation remains ${activeCount} active top-level sleeves from the registry. Paper review only; brokerage execution is disabled and no live orders are submitted.</span></div></section>`}

function commandHumanAlerts(c){const pendingDate=c.pending_membership?.effective_from||"None";return UI.Panel({title:"Human review alerts",meta:`${c.alerts.length} open`,className:"human-alerts",body:`<div class="limit-list"><div><span>Candidate admission</span><b>${pendingDate}</b><em class="${c.pending_membership?"warn":"ok"}">${c.pending_membership?"OPEN":"CLOSED"}</em></div><div><span>MED - Drawdown evidence</span><b>N/A</b><em class="warn">REVIEW</em></div><div><span>LOW - Correlation history</span><b>INSUFFICIENT</b><em class="warn">OPEN</em></div><div><span>LOW - Execution authority</span><b>DISABLED</b><em class="ok">PASS</em></div></div>`})}

function commandCosts(c){const cost=currentStrategyRows(c).reduce((n,s)=>n+s.total_cost,0);return UI.Panel({title:"Transaction cost impact",meta:"Paper Execution",body:`<div class="limit-list"><div><span>Transaction costs</span><b>${UI.money(cost)}</b><em class="warn">PAPER FILLS</em></div><div><span>Broker commissions</span><b>N/A</b><em class="warn">N/A</em></div><div><span>Market impact</span><b>N/A</b><em class="warn">N/A</em></div><div><span>Net benefit after costs</span><b>N/A</b><em class="warn">N/A</em></div></div>`})}

function commandLowerPanels(c){const nameById=Object.fromEntries(c.strategies.map(s=>[s.internal_id,s.ui_name||s.display_name])),latest=c.portfolio_daily.at(-1),promo=promotionReadiness(c),tradeRows=c.trades.slice(-7).reverse().map(t=>`<tr><td>${t.execution_date}</td><td>${nameById[t.strategy_id]||t.strategy_id}</td><td class="${t.action==="BUY"?"tone-positive":"tone-negative"}">${t.action}</td><td>${t.ticker}</td><td>${UI.money(t.simulated_notional)}</td><td>${UI.money(t.transaction_cost_amount)}</td></tr>`),holdings=[...c.holdings].sort((a,b)=>Math.abs(b.simulated_notional)-Math.abs(a.simulated_notional)).slice(0,7).map(h=>`<tr><td>${h.ticker}</td><td>${nameById[h.strategy_id]||h.strategy_id}</td><td>${UI.percent(h.target_weight,2)}</td><td>${UI.money(h.simulated_notional)}</td><td>${h.simulated_quantity==null?"Unavailable":UI.displayNumber(h.simulated_quantity,{maximumFractionDigits:1})}</td></tr>`);return `<div class="command-lower"><section class="panel">${UI.SectionHeader({title:"Recent Paper Execution activity",meta:"No Live Brokerage Fill"})}${table(["Date","Strategy","Action","Ticker","Notional","Cost"],tradeRows)}</section><section class="panel">${UI.SectionHeader({title:"Largest current holdings",meta:"Shadow-Live paper notional"})}${table(["Ticker","Strategy","Weight","Notional","Quantity"],holdings)}</section><section class="panel">${UI.SectionHeader({title:"Portfolio controls & limits",meta:"Canonical operating state"})}<div class="control-grid"><div><span>Gross exposure</span><b>${UI.displayNumber(latest.gross_exposure,{maximumFractionDigits:2})}</b><em class="ok">Within record</em></div><div><span>Net exposure</span><b>${UI.displayNumber(latest.net_exposure,{maximumFractionDigits:2})}</b><em class="ok">Neutral</em></div><div><span>Real funded allocation</span><b>0%</b><em class="warning">Disabled</em></div><div><span>Official ledger promotion</span><b>${promo.can_promote?"Dry-run available":"Manual dry-run only"}</b><em class="warning">Execute disabled</em></div><div><span>Current drawdown</span><b class="tone-pending">Unavailable</b><em class="warning">Review</em></div><div><span>Correlation</span><b class="tone-pending">Unavailable</b><em class="warning">Insufficient history</em></div><div><span>Execution</span><b>Disabled</b><em class="ok">Governance pass</em></div></div></section></div>`}

// Visible portfolio date uses paper_performance_daily when available; official close/data_as_of are audit metadata only.

function chartLegendMarkup(){return `<div class="chart-legend"><span class="legend-item"><i class="nav-line"></i>Portfolio NAV</span><span class="legend-item"><i class="pnl-bar"></i>Daily P&L</span><span class="legend-item"><i class="dd-line"></i>Drawdown</span><span class="legend-item"><i class="est-dot"></i>Delayed Est.</span><span class="legend-item"><i class="official-dot"></i>Official Marker</span></div>`}

function commandChart(c){const series=commandChartSeries(c),rows=series.rows,last=rows.at(-1),detail=last?chartDetailMarkup({date:chartDateLabel(last.date).replace(" 0"," "),source:series.label,nav:last.ending_nav,pnl:last.net_pnl,drawdown:last.current_drawdown}):chartDetailMarkup();return `<section class="panel chart-panel primary-chart">${UI.SectionHeader({title:"Master Portfolio Daily Performance",meta:chartSubtitle(series,c)})}<div class="chart-control-row">${chartStatusChips(series,c)}${chartLegendMarkup()}</div><div class="panel-body chart-body"><canvas id="navChart" width="1000" height="210" aria-label="Master Portfolio Daily Performance chart"></canvas><div class="chart-tooltip" id="navChartTooltip" aria-hidden="true"></div></div><div class="chart-detail-strip" id="navChartDetail" aria-live="polite">${detail}</div></section>`}

function page(){const c=state.contract;return `<main class="main-stage"><div class="page command-center">${metrics(c)}<div class="command-board"><div class="cmd-allocation">${allocation(c)}</div><div class="cmd-contributors">${contributors(c)}</div><div class="cmd-chart">${commandChart(c)}</div><div class="cmd-strategies">${commandStrategyTable(c)}</div><div class="cmd-left-reco">${commandRecommendation(c)}</div><div class="cmd-rebalance">${commandRebalanceCenter(c)}</div><div class="cmd-factor">${commandFactor(c)}</div><div class="cmd-alerts">${commandHumanAlerts(c)}</div><div class="cmd-costs">${commandPerformanceSummary(c)}</div><div class="cmd-risk">${commandRisk(c)}</div><div class="cmd-correlation">${commandCorrelation()}</div><div class="cmd-regime">${commandRegime(c)}</div></div></div></main>`}

function table(headers,rows,cls=""){const body=Array.isArray(rows)?rows.join(""):rows;return `<div class="work-table-wrap"><table class="work-table ${cls}"><thead><tr>${headers.map(x=>`<th>${x}</th>`).join("")}</tr></thead><tbody>${body}</tbody></table></div>`}

function pageTitle(title,detail){const release=PAGE_RELEASE_STATUS[state.selectedPage]||{status:"IN_DEVELOPMENT",reason:"Release state not classified."},tone=release.status==="READY"?"ok":release.status==="MVP_READY"?"info":release.status==="BLOCKED"?"negative":"warning";return `<div class="workspace-title"><div><strong>${title}</strong><span>${detail}</span></div><div>${UI.StatusBadge({label:release.status,tone,dot:true})}${UI.StatusBadge({label:"Canonical local",tone:"ok",dot:true})}${UI.StatusBadge({label:"Research only",tone:"warning",dot:true})}</div></div>`}

function workflowTestingTitle(){return `<div class="workspace-title"><div><strong>Workflow & Shadow-Live Testing</strong><span>Operating workflow for strategy development, paper-only testing, admission gates, risk review, and release control.</span></div><div>${UI.StatusBadge({label:"MVP_READY",tone:"info",dot:true})}${UI.StatusBadge({label:"CANONICAL_LOCAL",tone:"ok",dot:true})}${UI.StatusBadge({label:"RESEARCH_ONLY",tone:"warning",dot:true})}${UI.StatusBadge({label:"NO_LIVE_BROKERAGE",tone:"pending",dot:true})}</div></div>`}

function unavailable(title,detail){return UI.Panel({title,meta:"Data readiness",className:"unavailable-panel",body:`<div class="readiness-table"><div><span>Current value</span><b class="tone-pending">Unavailable</b></div><div><span>Canonical source</span><b>Not loaded</b></div><div><span>Fallback policy</span><b>Blocked</b></div><div><span>Decision use</span><b>Human review</b></div><p>${detail}</p></div>`})}

function secondaryStageNote(title,items){return UI.Panel({title,meta:"Secondary tab staging",className:"unavailable-panel",body:`<ul class="rule-list">${items.map(([status,text])=>`<li><b>${status}</b> ${text}</li>`).join("")}</ul>`})}

function releasePanel(page=state.selectedPage){return ""}

function median(values){const v=values.filter(x=>x!=null).map(Number).sort((a,b)=>a-b);if(!v.length)return null;const m=Math.floor(v.length/2);return v.length%2?v[m]:(v[m-1]+v[m])/2}

function riskPage(){const c=state.contract,p=c.portfolio_daily.at(-1),rows=c.strategies.map(s=>{const pending=isPendingAdmission(s);return `<tr><td>${s.ui_name}</td><td>${pending?"N/A":UI.percent(s.daily_return,2)}</td><td>${pending?"N/A":UI.money(s.daily_pnl)}</td><td>${pending?"N/A":UI.percent(s.current_drawdown,2)}</td><td>${pending?"N/A":s.holdings_count}</td><td>${pending?"Pending admission":s.validation_status}</td><td>${UI.StatusBadge({label:pending?"Not loaded":s.current_drawdown==null?"Unavailable":"Available",tone:pending||s.current_drawdown==null?"pending":"ok"})}</td></tr>`});return `<main class="main-stage"><div class="page workflow-page">${pageTitle("Risk Factors & Exposure","Canonical exposure records, style/family proxy, and blocked institutional analytics")}${releasePanel()}${secondaryStageNote("Risk tab staging status",[["LOADED","Gross, net, long, and short exposure are read from the latest canonical portfolio record."],["PROXY","STYLE / FAMILY EXPOSURE PROXY is derived from active strategy families and is not a factor model."],["BLOCKED","Institutional factor model, VaR, ES, scenario shock, macro regime, and stress analytics are Blocked / Not loaded."]])}<section class="metric-grid">${[["Gross exposure",UI.displayNumber(p.gross_exposure,{maximumFractionDigits:2}),"Latest portfolio record","info"],["Net exposure",UI.displayNumber(p.net_exposure,{maximumFractionDigits:2}),"Latest portfolio record","info"],["Long exposure",UI.displayNumber(p.long_exposure,{maximumFractionDigits:2}),"Paper holdings","positive"],["Short exposure",UI.displayNumber(p.short_exposure,{maximumFractionDigits:2}),"Paper holdings","negative"],["Cash",UI.money(p.cash),"Latest record","info"],["Current drawdown","Unavailable","Preserved null","unavailable"],["VaR","Blocked / Not loaded","Validated VaR model absent","unavailable"],["Expected Shortfall","Blocked / Not loaded","Validated ES model absent","unavailable"],["Factor contribution","Blocked / Not loaded","Institutional model absent","unavailable"],["Data status",p.data_quality_status,"Latest record","positive"]].map(x=>UI.MetricCard({label:x[0],value:String(x[1]),detail:x[2],tone:x[3]})).join("")}</section><div class="workflow-grid"><section class="panel span-8">${UI.SectionHeader({title:"Strategy risk monitor",meta:"Operating records only; no validated factor sensitivities"})}${table(["Strategy","Daily return","Daily P&L","Current DD","Holdings","Validation","Risk evidence"],rows)}</section><div class="span-4 stack-panels">${styleExposurePanel(c)}${alerts(c)}</div><div class="span-4">${unavailable("Scenario shock","Blocked / Not loaded. No validated scenario definitions or exposure model exist in the canonical operational bundle.")}</div><div class="span-4">${unavailable("Macro regime","Blocked / Not loaded. No validated macro feed or regime model is loaded.")}</div><div class="span-4">${UI.Panel({title:"Data gaps / readiness notes",meta:"Current operating record",body:`<ul class="rule-list"><li><b>PASS</b> Gross, net, long, and short exposure are loaded from the portfolio record</li><li><b>PASS</b> Live allocation remains 0%</li><li><b>PASS</b> Execution authority disabled</li><li><b>PASS</b> ${p.active_count} active sleeves reconciled</li><li><b>BLOCKED</b> Institutional factor, VaR, ES, scenario shock, and macro regime models are Not loaded</li></ul>`})}</div></div></div></main>`}

function riskPageV1(){const c=state.contract,p=c.portfolio_daily.at(-1),hasMarketProxy=(c.risk_factor_market_proxy_table||[]).length>0;return `<main class="main-stage"><div class="page workflow-page risk-factor-page">${pageTitle("Risk Factors",hasMarketProxy?"Heatmap-first market-data proxy view with data-derived rows and no hard-coded strategy count":"Strategy x Factor Matrix from risk_factor_big_table; missing metadata remains explicit")}${releasePanel()}${riskHeatmapSummaryCards(c)}${riskBenchmarkStrip(c)}<div class="risk-matrix-primary">${riskFactorHeatmap(c)}</div>${riskSecondaryPanels(c,p)}</div></main>`}

function correlationPage(){const c=state.contract,o=c.operational_status.correlation||{},names=c.strategies.slice(0,8),hasEvidence=s=>s.research_evidence?.research_status==="CONNECTED"||s.research_evidence_available;return `<main class="main-stage"><div class="page workflow-page">${pageTitle("Correlation & Diversification","Operational correlation requires sufficient aligned live-history observations")}${releasePanel()}${secondaryStageNote("Correlation tab staging status",[["INSUFFICIENT HISTORY",`${o.observations||0} aligned observations loaded; minimum required is ${o.minimum_observations||"N/A"}.`],["BLOCKED","No correlation matrix, duplicate-pair heatmap, cluster map, or diversification score is rendered or inferred."],["SEPARATE","Research evidence and operational returns remain separate; research correlation is not substituted for operational correlation."]])}<div class="workflow-grid"><div class="span-4">${UI.Panel({title:"Correlation readiness",meta:"Canonical status",body:`<div class="decision-box"><strong>${o.status||"Unavailable"}</strong><span>${o.observations||0} observations available. Minimum required: ${o.minimum_observations||"Unavailable"}.</span><em>Research and operational returns remain separate</em></div>`})}</div><div class="span-8">${unavailable("Operational correlation matrix","The canonical contract does not fabricate correlation from insufficient observations.")}</div><section class="panel span-8">${UI.SectionHeader({title:"Diversification inventory",meta:"Distinct operational strategies"})}${table(["Display ID","Strategy","Weight","Holdings","Daily return","Evidence"],names.map(s=>`<tr><td>${s.display_id}</td><td><strong>${s.ui_name}</strong></td><td>${UI.percent(s.current_weight,2)}</td><td>${s.holdings_count}</td><td>${UI.percent(s.daily_return,2)}</td><td>${hasEvidence(s)?"Available":"Unavailable"}</td></tr>`))}</section><div class="span-4 stack-panels">${unavailable("Duplicate exposure warnings","Pairwise strategy correlation is unavailable until the minimum observation threshold is met.")}${timeline(c)}</div></div></div></main>`}

