function allocationActiveSleeves(c){return currentActiveRows(c)}

function allocationStorageKey(c){return `risk-workstation.paper-allocation.${allocationActiveSleeves(c).map(s=>s.internal_id).join("|")}`}

function allocationPlanStorageKey(c){return `${allocationStorageKey(c)}.planStatus`}

function allocationEqualWeights(c){const sleeves=allocationActiveSleeves(c),w=sleeves.length?1/sleeves.length:0;return Object.fromEntries(sleeves.map(s=>[s.internal_id,w]))}

function allocationReadSaved(c){try{const raw=localStorage.getItem(allocationStorageKey(c));if(!raw)return null;const parsed=JSON.parse(raw),ids=new Set(allocationActiveSleeves(c).map(s=>s.internal_id));if(!parsed||typeof parsed!=="object")return null;for(const id of Object.keys(parsed)){if(!ids.has(id)||!Number.isFinite(Number(parsed[id]))||Number(parsed[id])<0)return null}return Object.fromEntries([...ids].map(id=>[id,Number(parsed[id]??0)]))}catch{return null}}

function allocationDraft(c){if(!state.allocationDraftWeights){state.allocationDraftWeights=allocationReadSaved(c)||allocationEqualWeights(c);try{state.allocationPlanStatus=localStorage.getItem(allocationPlanStorageKey(c))||"Draft / Review"}catch{state.allocationPlanStatus="Draft / Review"}}return state.allocationDraftWeights}

function allocationTargetTotal(weights){return Object.values(weights||{}).reduce((n,v)=>n+Number(v||0),0)}

function allocationShadowCapital(c){return Number(c.portfolio_summary?.nav??c.capital_reconciliation?.initial_shadow_capital??1000000)}

const ALLOCATION_DUST_NOTIONAL=100,ALLOCATION_DUST_DRIFT=0.0001

function allocationPlanRows(c){const weights=allocationDraft(c),capital=allocationShadowCapital(c);return allocationActiveSleeves(c).map(s=>{const currentRaw=s.current_weight??s.sleeve_weight,targetRaw=weights[s.internal_id],current=Number(currentRaw),target=Number(targetRaw),hasData=Number.isFinite(current)&&Number.isFinite(target),currentNotional=hasData?current*capital:null,targetNotional=Number.isFinite(target)?target*capital:null,trade=hasData?targetNotional-currentNotional:null,drift=hasData?target-current:null,material=hasData&&Math.abs(trade)>=ALLOCATION_DUST_NOTIONAL&&Math.abs(drift)>=ALLOCATION_DUST_DRIFT,cost=material?Math.abs(trade)*0.0005:0;return {s,current:hasData?current:null,target:Number.isFinite(target)?target:null,currentNotional,targetNotional,trade,drift,material,cost,hasData}})}

function allocationMaterialRows(c){return allocationPlanRows(c).filter(r=>r.material)}

function allocationDecision(r){if(!r.hasData)return "REVIEW";if(!r.material)return "HOLD";return r.drift>0?"INCREASE":"REDUCE"}

function allocationDecisionTone(action){return action==="INCREASE"?"positive":action==="REDUCE"?"negative":action==="REVIEW"?"warning":"info"}

function allocationPlanValidation(total){const eps=0.0001;if(total>1+eps)return {state:"OVER-ALLOCATED",tone:"negative",ok:false,residual:0,overUnder:total-1,detail:"Normalize to 100% before Save / Generate"};if(total<1-eps)return {state:"RESIDUAL CASH",tone:"warning",ok:true,residual:1-total,overUnder:total-1,detail:"Unallocated cash remains in paper target"};return {state:"READY",tone:"positive",ok:true,residual:0,overUnder:0,detail:"Target allocation equals 100%"}}

function allocationPersistDraft(c){localStorage.setItem(allocationStorageKey(c),JSON.stringify(allocationDraft(c)));localStorage.setItem(allocationPlanStorageKey(c),state.allocationPlanStatus)}

function allocationSetEqual(){state.allocationDraftWeights=allocationEqualWeights(state.contract);state.allocationPlanStatus="Draft / Review";allocationPersistDraft(state.contract);render()}

function allocationSetRecommended(){state.allocationDraftWeights=allocationRecommendedWeights(state.contract);state.allocationPlanStatus="Suggested Targets Applied";allocationPersistDraft(state.contract);render()}

function allocationNormalize(){const c=state.contract,w=allocationDraft(c),total=allocationTargetTotal(w);if(total<=0){toast("Cannot normalize zero allocation","negative");return}state.allocationDraftWeights=Object.fromEntries(Object.entries(w).map(([id,v])=>[id,Number(v)/total]));state.allocationPlanStatus="Draft / Review";allocationPersistDraft(c);render()}

function allocationSaveTarget(){const total=allocationTargetTotal(allocationDraft(state.contract)),v=allocationPlanValidation(total);if(!v.ok){toast(v.detail,"negative");return}state.allocationPlanStatus=total<0.9999?"Saved Paper Target / Residual Cash":"Saved Paper Target";allocationPersistDraft(state.contract);toast("Paper target saved in browser storage","positive");render()}

function allocationGeneratePlan(){const total=allocationTargetTotal(allocationDraft(state.contract)),v=allocationPlanValidation(total);if(!v.ok){toast(v.detail,"negative");return}state.allocationPlanStatus=allocationMaterialRows(state.contract).length?"Draft / Review":"No Material Paper Rebalance Required";allocationPersistDraft(state.contract);toast(state.allocationPlanStatus,"positive");render()}

function allocationSetPlanStatus(status){state.allocationPlanStatus=status;allocationPersistDraft(state.contract);toast(`Plan status: ${status}`,"positive");render()}

function allocationSyncTargetUi(total){const v=allocationPlanValidation(total);document.querySelector("[data-allocation-total]")?.replaceChildren(document.createTextNode(UI.percent(total,2)));document.querySelector("[data-allocation-residual]")?.replaceChildren(document.createTextNode(UI.percent(v.residual,2)));document.querySelector("[data-allocation-over-under]")?.replaceChildren(document.createTextNode(UI.percent(v.overUnder,2)));document.querySelector("[data-allocation-validation]")?.replaceChildren(document.createTextNode(v.state));document.querySelectorAll('[data-allocation-action="save"],[data-allocation-action="generate"]').forEach(b=>{b.disabled=!v.ok})}

function bindAllocationControls(){document.querySelectorAll("[data-allocation-input]").forEach(input=>input.addEventListener("input",e=>{const id=e.target.dataset.allocationInput,value=Number(e.target.value);if(!state.allocationDraftWeights)allocationDraft(state.contract);state.allocationDraftWeights[id]=Number.isFinite(value)?Math.max(0,value)/100:0;state.allocationPlanStatus="Draft / Review";allocationSyncTargetUi(allocationTargetTotal(state.allocationDraftWeights))}));document.querySelectorAll("[data-allocation-action]").forEach(b=>b.addEventListener("click",()=>{const a=b.dataset.allocationAction;if(a==="equal")allocationSetEqual();if(a==="normalize")allocationNormalize();if(a==="save")allocationSaveTarget();if(a==="generate")allocationGeneratePlan();if(a==="accept")allocationSetPlanStatus("Accepted / Pending Paper Application");if(a==="modify")allocationSetPlanStatus("Draft / Review");if(a==="reject")allocationSetPlanStatus("Rejected")}))}

function allocationControlStrip(c,total,validation){return `<section class="allocation-control-strip"><div><span>Portfolio Mode</span><b>Shadow-Live Paper</b></div><div><span>Target Allocated %</span><b data-allocation-total class="tone-${validation.tone}">${UI.percent(total,2)}</b></div><div><span>Residual Cash %</span><b data-allocation-residual>${UI.percent(validation.residual,2)}</b></div><div><span>Over / Under Allocation %</span><b data-allocation-over-under class="tone-${validation.tone}">${UI.percent(validation.overUnder,2)}</b></div><div><span>Paper Target</span><b>User adjustable</b></div><div><span>Save Method</span><b>browser/session persisted</b></div><div><span>Brokerage Execution</span><b class="tone-warning">Disabled</b></div><div><span>Target Validation</span><b data-allocation-validation class="tone-${validation.tone}">${validation.state}</b></div></section>`}

function allocationDisplayPercent(v){return v==null?"Unavailable":UI.percent(v,2)}

function allocationDisplayMoney(v){return v==null?"Unavailable":UI.money(v)}

function allocationEditableRows(c){return allocationPlanRows(c).map(r=>{const action=allocationDecision(r),tone=allocationDecisionTone(action),tradeText=r.material?UI.money(r.trade):r.hasData?UI.money(0):"Unavailable";return `<tr><td>${r.s.display_id}</td><td><strong>${r.s.ui_name}</strong><small>${r.s.internal_id}</small></td><td>${UI.StatusBadge({label:"ACTIVE PAPER SLEEVE",tone:r.s.internal_id==="COMBINED_PORTFOLIO"?"info":"ok"})}</td><td>${allocationDisplayPercent(r.current)}<small>${allocationDisplayMoney(r.currentNotional)}</small></td><td><input class="allocation-input" type="number" min="0" step="0.01" value="${((r.target??0)*100).toFixed(2)}" data-allocation-input="${UI.escapeHtml(r.s.internal_id)}" aria-label="Target allocation for ${UI.escapeHtml(r.s.ui_name)}"></td><td class="tone-${UI.toneForNumber(r.drift)}">${allocationDisplayPercent(r.drift)}</td><td>${allocationDisplayMoney(r.targetNotional)}</td><td class="tone-${r.material?UI.toneForNumber(r.trade):"info"}">${tradeText}</td><td>${UI.money(r.cost)}</td><td><span class="allocation-action-badge tone-${tone}">${action}</span></td></tr>`}).join("")}

function allocationTradeRows(c){const rows=allocationMaterialRows(c).sort((a,b)=>Math.abs(b.trade)-Math.abs(a.trade));if(!rows.length)return `<tr><td colspan="8"><strong>No material paper rebalance required</strong><small>All sleeve drifts are below ${UI.money(ALLOCATION_DUST_NOTIONAL)} or ${UI.percent(ALLOCATION_DUST_DRIFT,2)}.</small></td></tr>`;return rows.map(({s,trade,cost,target,current})=>`<tr><td>${s.display_id}</td><td><strong>${s.ui_name}</strong><small>${trade>0?"Paper BUY sleeve notional":trade<0?"Paper SELL sleeve notional":"No sleeve trade"}</small></td><td class="tone-${UI.toneForNumber(trade)}">${trade>0?"BUY":trade<0?"SELL":"NO TRADE"}</td><td>${UI.money(Math.abs(trade))}</td><td>${allocationDisplayPercent(current)}</td><td>${allocationDisplayPercent(target)}</td><td>${UI.money(cost)}</td><td>No live order; no official ledger change</td></tr>`).join("")}

function allocationWarnings(c,total,validation){const pending=(c.strategies||[]).filter(s=>!allocationActiveSleeves(c).some(a=>a.internal_id===s.internal_id)),saved=allocationReadSaved(c),material=allocationMaterialRows(c).length;return `<div class="allocation-warning-list"><div><span>Inactive / pending rows</span><b>${pending.length} separated by registry status</b></div><div><span>Target validation</span><b class="tone-${validation.tone}">${validation.detail}</b></div><div><span>Residual cash handling</span><b>${validation.residual>0?`${UI.percent(validation.residual,2)} unallocated cash`:"No residual cash"}</b></div><div><span>Dust threshold</span><b>${UI.money(ALLOCATION_DUST_NOTIONAL)} / ${UI.percent(ALLOCATION_DUST_DRIFT,2)}</b></div><div><span>Material trade rows</span><b>${material?material:"None"}</b></div><div><span>Saved target loaded</span><b>${saved?"Yes":"No; equal-weight default"}</b></div><div><span>Real Funded Brokerage Capital</span><b>$0</b></div><div><span>Official ledger</span><b class="tone-positive">Unchanged</b></div></div>`}

function allocationActionsPanel(validation){return UI.Panel({title:"Paper action center",meta:"No button executes live trades",className:"allocation-action-center",body:`<div class="allocation-buttons"><button data-allocation-action="equal">Reset Equal Weight</button><button data-allocation-action="normalize">Normalize to 100%</button><button data-allocation-action="save" ${validation.ok?"":"disabled"}>Save Paper Target</button><button data-allocation-action="generate" ${validation.ok?"":"disabled"}>Generate Paper Rebalance Plan</button><button class="approve-tile" data-allocation-action="accept">Accept</button><button class="modify-tile" data-allocation-action="modify">Modify</button><button class="reject-tile" data-allocation-action="reject">Reject</button></div><div class="decision-box compact"><strong>${UI.escapeHtml(state.allocationPlanStatus)}</strong><span>${validation.detail}. Paper-only workflow; no official ledger mutation and no brokerage execution.</span><em>Execution authorized: NO</em></div>`})}

function workflowNode(title,status,detail,tone="info"){return `<article class="workflow-map-node tone-${tone}"><strong>${UI.escapeHtml(title)}</strong><b>${UI.escapeHtml(status)}</b><span>${UI.escapeHtml(detail)}</span></article>`}

function workflowLane(title,nodes){return `<section class="panel workflow-lane">${UI.SectionHeader({title,meta:"Secondary audit detail"})}<div class="workflow-map-row">${nodes.map((n,i)=>`${i?'<i class="workflow-map-arrow">-></i>':""}${workflowNode(...n)}`).join("")}</div></section>`}

function workflowDiagramCard(n,title,status,bullets,tone="info"){return `<article class="workflow-command-node tone-${tone}"><span>${String(n).padStart(2,"0")} - ${UI.escapeHtml(title)}</span><strong>${UI.escapeHtml(status)}</strong><ul>${bullets.map(x=>`<li>${UI.escapeHtml(String(x))}</li>`).join("")}</ul></article>`}

function workflowFrameworkLanes(c,active,pending,g,blockers){const combined=c.strategies.find(s=>s.internal_id==="COMBINED_PORTFOLIO")||{},ordinary=active.filter(s=>s.internal_id!=="COMBINED_PORTFOLIO"),paperTradeRows=c.trades.length,positionRows=c.holdings.length;return `${workflowLane("Strategy Development Workflow",[["Research Idea",`${c.strategies.length} registry rows`,"Historical research stays separate from operations","info"],["Signal Definition",c.strategy_daily.length?"Loaded":"Unavailable","Read from canonical strategy_daily / signal artifacts when present","info"],["Target Construction",c.operational_status?.latest_valid_target_position_date||"Unavailable","Missing target rows stay Pending / Unavailable","warning"],["Backtest Evidence",c.strategies.filter(s=>s.research_evidence||s.research_evidence_available).length,"Research metrics are displayed only when loaded","info"]])}${workflowLane("Shadow-Live Paper Testing Workflow",[["Strategy Registry",`${active.length} active; ${pending.length} pending`,"Rows derive from current registry status","positive"],["Paper Execution Record",paperTradeRows?`${paperTradeRows} rows`:"Unavailable","Paper-only trade records; no brokerage execution","warning"],["Position Ledger",positionRows?`${positionRows} rows`:"Unavailable","Paper holdings / positions only","info"],["Human Approval",pending.length?`${pending.length} pending`:"Required for changes","No automatic admission or live execution","pending"]])}${workflowLane("Strategy Admission Gate",[["Candidate Registry",pending.length?`${pending.length} pending`:"No pending active admission","Approved-pending / pre-operational rows are separated","pending"],["Evidence Gate",g.status||"Evidence-gated",blockers[0]||"Pending evidence","warning"],["Human Approval","Required","Admission remains review-gated","pending"],["Operating Set",`${active.length} active`,"Only active rows enter allocation","positive"]])}${workflowLane("Combined Strategy Operating Workflow",[["Ordinary Constituents",`${ordinary.length} active ordinary rows`,"Derived from current active registry","info"],["Combined Strategy Ledger",combined.data_status||"Unavailable","Derived from ordinary strategy net returns","positive"],["Combined Paper Fills","None","No separate Combined paper fills; no cost double count","warning"]])}${workflowLane("Risk Review Workflow",[["Risk Model Inputs",c.available_factor_outputs?"Loaded":"Unavailable","Institutional factor/VaR/ES inputs must be validated before rendering","warning"],["Market Proxy",c.risk_factor_market_proxy_table?.length||0,"Proxy fields stay labeled as proxy","info"],["Review Decision","Human review","Missing data remains Unavailable / Pending / Proxy / Limited history","pending"]])}${workflowLane("Local-First Release Workflow",[["Local Snapshot",c.snapshot_id||c.snapshot_version||"Loaded","Dashboard reads shared local snapshot state","positive"],["Browser Verification","Required","Release checks must pass before handoff","info"],["Deployment Handoff","Project Handoff References","Static project references are not market/accounting data","info"]])}`}

function workflowTestingPage(){const c=state.contract,active=allocationActiveSleeves(c),pending=currentPendingRows(c),intr=c.intraday_estimate||{},u=c.operational_universe||{},promo=promotionReadiness(c),covered=u.current_price_covered_ticker_count??intr.covered_tickers,total=u.held_ticker_count??intr.total_tickers,coverage=covered!=null&&total!=null?`${covered}/${total}`:"Unavailable",refresh=refreshStatusLabel(c),schedulerState=c.intraday_scheduler_enabled===false?"Configured / currently disabled":"Enabled",manual="/api/refresh-data",poll="/api/snapshot-summary",g=c.wq_admission_gate||{},blockers=(g.blockers&&g.blockers.length?g.blockers:["Pending evidence"]);const kpis=[["Portfolio Mode","Shadow-Live Paper","Paper operation boundary","positive"],["Real Funded Capital","$0","No brokerage funding","warning"],["Brokerage Execution","Disabled","Live Fill = No","warning"],["Active Sleeves",active.length,"current active top-level sleeves","positive"],["Pending Candidates",pending.length,"Excluded from active allocation","pending"],["Delayed Coverage",coverage,"yfinance proxy when loaded","info"],["Manual Refresh",manual,"POST endpoint","info"],["UI Polling",poll,"Lightweight snapshot polling","info"]];return `<main class="main-stage"><div class="page workflow-page workflow-map-page">${workflowTestingTitle()}${workflowCommandDiagram(c,{active,pending,coverage,schedulerState,manual,poll,refresh})}<details class="workflow-secondary-detail"><summary>Detailed workflow audit sections</summary><section class="metric-grid workflow-testing-metrics">${kpis.map(x=>UI.MetricCard({label:x[0],value:String(x[1]),detail:x[2],tone:x[3]})).join("")}</section><div class="workflow-map-layout"><section class="panel workflow-boundary-panel">${UI.SectionHeader({title:"Operating boundary",meta:"Clear separation of official, paper, delayed estimate, and live brokerage"})}<div class="workflow-boundary-grid">${workflowNode("Official Ledger",c.portfolio_daily.length?"Loaded":"Unavailable",`${c.portfolio_daily.length} portfolio_daily rows; not changed by refresh or allocation UI`,"positive")}${workflowNode("Paper Performance",(c.paper_performance_daily||[]).length?"Loaded / Runtime":"Limited history","Separate paper daily artifact when delayed refresh writes paper-only estimates","info")}${workflowNode("Delayed Estimate",intr.estimated_nav!=null?refresh:"Unavailable",`Provider ${intr.provider||"yfinance proxy"}; coverage ${coverage}`,"warning")}${workflowNode("Live Brokerage","Disabled","Real funded brokerage capital = $0; Live Fill = No","warning")}</div></section>${workflowLane("Refresh and dashboard flow",[["Committed Shadow Holdings",c.holdings.length?`${c.holdings.length} rows`:"Unavailable","Source positions for delayed estimate","positive"],["Delayed yfinance proxy now / boss API later",intr.provider||"Proxy / Pending",`Coverage ${coverage}; not official live market data`,"warning"],["Auto Delayed Refresh","30-minute scheduler refresh",`${schedulerState}; minimum 30-minute background cadence`,"info"],["Manual Refresh",manual,"User-triggered delayed refresh endpoint","info"],["Operational Snapshot",poll,`Snapshot ${c.snapshot_id||c.snapshot_version||"loaded"}`,"positive"],["Dashboard Tabs",`${WORKFLOW_TABS.length} tabs`,`Current page uses shared snapshot state`,"positive"]])}${workflowLane("Strategy admission flow",[["Research Registry",`${c.strategies.length} strategy rows`,"Historical research stays separate from operations","info"],["Evidence Gate",g.status||"Evidence-gated",blockers[0]||"Pending evidence","warning"],["Human Approval",pending.length?`${pending.length} pending`:"No pending active admission","No automatic admission","pending"],["Current Operating Set",`${active.length} active sleeves`,"Only active/current rows enter allocation","positive"]])}${workflowLane("Paper rebalance flow",[["Active Sleeves",`${active.length} loaded`,"Read from current registry / snapshot","positive"],["Editable Paper Targets","localStorage","Browser/session persisted paper target weights","info"],["Paper Rebalance Plan","5 bps cost","Notional drift and estimated paper transaction cost","warning"],["Accept / Modify / Reject","Review status only","No live trades; no official ledger modification","pending"]])}${workflowFrameworkLanes(c,active,pending,g,blockers)}<section class="panel workflow-review-panel">${UI.SectionHeader({title:"Release and safety controls",meta:"Boss-presentable semantics"})}<div class="workflow-warning-grid"><div><span>Official promotion readiness</span><b>${promo.readiness_state||"Unavailable"}</b></div><div><span>Scheduler refresh</span><b>30-minute scheduler refresh</b></div><div><span>Scheduler state</span><b>${schedulerState}</b></div><div><span>Manual refresh endpoint</span><b>${manual}</b></div><div><span>UI polling endpoint</span><b>${poll}</b></div><div><span>Pending / inactive rows</span><b>${pending.length} separated by current status</b></div><div><span>Live brokerage fill</span><b class="tone-warning">Disabled / Not present</b></div><div><span>Missing-data policy</span><b>Unavailable / Pending / Proxy / Limited history</b></div></div><div class="blocker-list">${blockers.slice(0,6).map(x=>`<div><span>${UI.escapeHtml(x)}</span><b>REVIEW</b></div>`).join("")}</div></section></div></details></div></main>`}

function allocationAppliedTarget(c){return c.paper_rebalance?.current_paper_target||null}

function allocationAppliedWeights(c){return allocationAppliedTarget(c)?.weights||{}}

function allocationLatestPlan(c){return state.paperRebalancePlan||c.paper_rebalance?.latest_plan||null}

function allocationLatestCost(c){return c.paper_rebalance?.latest_cost_record||null}

function allocationCurrentWeight(c,s){const applied=allocationAppliedWeights(c),v=applied?.[s.internal_id];if(v!=null&&Number.isFinite(Number(v)))return Number(v);const raw=s.current_weight??s.sleeve_weight;return Number.isFinite(Number(raw))?Number(raw):null}

function allocationMetricValue(s,key){const v=s?.[key];return Number.isFinite(Number(v))?Number(v):null}

function allocationZScores(rows,key){const values=rows.map(s=>allocationMetricValue(s,key)).filter(Number.isFinite),mean=values.length?values.reduce((n,v)=>n+v,0)/values.length:0,variance=values.length?values.reduce((n,v)=>n+(v-mean)**2,0)/values.length:0,sd=Math.sqrt(variance)||1;return Object.fromEntries(rows.map(s=>[s.internal_id,allocationMetricValue(s,key)==null?null:(allocationMetricValue(s,key)-mean)/sd]))}

function allocationResearchMetrics(s){return s.research_evidence?.research_metrics||{}}

function allocationRecommendationScore(c,s,z){const m=allocationResearchMetrics(s),obs=Number(s.observation_count||0),complete=["COMPLETE","DERIVED_COMPLETE"].includes(s.data_state||s.data_status),hasMetrics=[s.daily_return,s.cumulative_return,s.current_drawdown].every(v=>Number.isFinite(Number(v)));if(!complete||obs<3||!hasMetrics)return null;let score=(z.cumulative_return[s.internal_id]||0)*0.36+(z.daily_return[s.internal_id]||0)*0.22+(z.current_drawdown[s.internal_id]||0)*0.18;if(Number.isFinite(Number(m.net_sharpe)))score+=Number(m.net_sharpe)>0.5?.14:Number(m.net_sharpe)<0?-.14:0;if(Number.isFinite(Number(m.annualized_return)))score+=Number(m.annualized_return)>0?.08:-.08;if(Number.isFinite(Number(m.max_drawdown))&&Number(m.max_drawdown)<-.30)score-=.16;if(Number.isFinite(Number(m.cost_drag_ratio))&&Number(m.cost_drag_ratio)>.12)score-=.10;if(String(s.validation_status||"").includes("WARNING"))score-=.16;return score}

function allocationRecommendationAction(c,s,z){const score=allocationRecommendationScore(c,s,z),m=allocationResearchMetrics(s);if(score==null)return "REVIEW";if(Number(s.daily_return)<0||Number(s.cumulative_return)<0||Number(s.current_drawdown)<-.02)return "REDUCE";if(Number.isFinite(Number(m.cost_drag_ratio))&&Number(m.cost_drag_ratio)>.14)return "REDUCE";if(score>.18)return "INCREASE";if(score<-.18)return "REDUCE";return "HOLD"}

function allocationRecommendedWeights(c){const sleeves=allocationActiveSleeves(c),equal=allocationEqualWeights(c),z={daily_return:allocationZScores(sleeves,"daily_return"),cumulative_return:allocationZScores(sleeves,"cumulative_return"),current_drawdown:allocationZScores(sleeves,"current_drawdown")},raw=Object.fromEntries(sleeves.map(s=>{const score=allocationRecommendationScore(c,s,z),action=allocationRecommendationAction(c,s,z),tilt=action==="REVIEW"?0:Math.max(-0.14,Math.min(0.14,(score||0)*0.07));return [s.internal_id,Math.min(0.10,Math.max(0,Number(equal[s.internal_id]||0)*(1+tilt)))]})),total=Object.values(raw).reduce((n,v)=>n+v,0)||1;return Object.fromEntries(Object.entries(raw).map(([id,v])=>[id,v/total]))}

function allocationRecommendationReason(r){const s=r.s,m=allocationResearchMetrics(s);if(!r.hasData||r.recommendationAction==="REVIEW")return "Missing / limited evidence; review required";if(Number(s.daily_return)<0)return "Negative recent paper performance";if(Number(s.cumulative_return)<0)return "Weak cumulative paper performance";if(Number(s.current_drawdown)<-.02)return "Drawdown elevated";if(Number.isFinite(Number(m.cost_drag_ratio))&&Number(m.cost_drag_ratio)>.14)return "High cost drag / turnover concern";if(r.recommendationAction==="INCREASE")return Number.isFinite(Number(m.net_sharpe))?"Positive paper performance + supportive backtest Sharpe":"Positive paper performance + acceptable drawdown";if(r.recommendationAction==="REDUCE")return "Weaker return / drawdown profile";return "Mixed evidence; no material rebalance"}

function allocationDraft(c){if(!state.allocationDraftWeights){const applied=allocationAppliedWeights(c),saved=allocationReadSaved(c),equal=allocationEqualWeights(c),hasApplied=Object.keys(applied).length>0;state.allocationDraftWeights=saved||Object.fromEntries(allocationActiveSleeves(c).map(s=>[s.internal_id,Number(hasApplied?applied[s.internal_id]??equal[s.internal_id]:equal[s.internal_id])]));try{state.allocationPlanStatus=localStorage.getItem(allocationPlanStorageKey(c))||c.paper_rebalance?.latest_plan?.applied_status||"Draft / Review"}catch{state.allocationPlanStatus=c.paper_rebalance?.latest_plan?.applied_status||"Draft / Review"}}return state.allocationDraftWeights}

function allocationReason(r){if(!r.hasData)return "Data incomplete / review required";if(!r.material){if(Math.abs(r.drift||0)<ALLOCATION_DUST_DRIFT)return "Equal-weight maintained";return "Dust trade ignored"}if(r.drift>0)return "Increase toward target";if(r.drift<0)return "Reduce overweight sleeve";return "Equal-weight maintained"}

function allocationPlanRows(c){const weights=allocationDraft(c),suggested=allocationRecommendedWeights(c),capital=allocationShadowCapital(c),sleeves=allocationActiveSleeves(c),z={daily_return:allocationZScores(sleeves,"daily_return"),cumulative_return:allocationZScores(sleeves,"cumulative_return"),current_drawdown:allocationZScores(sleeves,"current_drawdown")};return sleeves.map(s=>{const current=allocationCurrentWeight(c,s),targetRaw=weights[s.internal_id],target=Number(targetRaw),suggestedTarget=Number(suggested[s.internal_id]),hasData=Number.isFinite(current)&&Number.isFinite(target),currentNotional=Number.isFinite(current)?current*capital:null,targetNotional=Number.isFinite(target)?target*capital:null,trade=hasData?targetNotional-currentNotional:null,drift=hasData?target-current:null,material=hasData&&Math.abs(trade)>=ALLOCATION_DUST_NOTIONAL&&Math.abs(drift)>=ALLOCATION_DUST_DRIFT,cost=material?Math.abs(trade)*0.0005:0,recommendationAction=allocationRecommendationAction(c,s,z),action=!hasData?"REVIEW":!material?"HOLD":drift>0?"INCREASE":"REDUCE";return {s,current:hasData?current:null,target:Number.isFinite(target)?target:null,suggestedTarget:Number.isFinite(suggestedTarget)?suggestedTarget:null,currentNotional,targetNotional,trade,drift,material,cost,hasData,action,recommendationAction,reason:null}}).map(r=>({...r,reason:allocationRecommendationReason(r)}))}

function allocationHasReview(c){return allocationPlanRows(c).some(r=>allocationDecision(r)==="REVIEW")}

function allocationPersistDraft(c){localStorage.setItem(allocationStorageKey(c),JSON.stringify(allocationDraft(c)));localStorage.setItem(allocationPlanStorageKey(c),state.allocationPlanStatus)}

function allocationSetEqual(){state.allocationDraftWeights=allocationEqualWeights(state.contract);state.allocationPlanStatus="Draft / Review";allocationPersistDraft(state.contract);render()}

function allocationNormalize(){const c=state.contract,w=allocationDraft(c),total=allocationTargetTotal(w);if(total<=0){toast("Cannot normalize zero allocation","negative");return}state.allocationDraftWeights=Object.fromEntries(Object.entries(w).map(([id,v])=>[id,Number(v)/total]));state.allocationPlanStatus="Draft / Review";allocationPersistDraft(c);render()}

function allocationSaveTarget(){const total=allocationTargetTotal(allocationDraft(state.contract)),v=allocationPlanValidation(total);if(!v.ok){toast(v.detail,"negative");return}state.allocationPlanStatus=total<0.9999?"Saved Draft Target / Residual Paper Cash":"Saved Draft Target";allocationPersistDraft(state.contract);toast("Draft paper target saved locally; generate plan to persist project artifact","positive");render()}

async function allocationRefreshFromResponse(result){if(result.snapshot){state.contract=result.snapshot;enrich(state.contract)}else{await loadSnapshot()}state.paperRebalancePlan=result.plan||result.paper_rebalance?.latest_plan||state.contract.paper_rebalance?.latest_plan||state.paperRebalancePlan;state.recommendationReviewDraft=result.recommendation_review_draft||result.paper_rebalance?.recommendation_review?.latest_draft||state.contract.paper_rebalance?.recommendation_review?.latest_draft||state.recommendationReviewDraft;state.monthlyRebalanceProposal=result.monthly_rebalance_proposal||result.paper_rebalance?.monthly_proposal?.latest_proposal||state.contract.paper_rebalance?.monthly_proposal?.latest_proposal||state.monthlyRebalanceProposal;state.approvedRebalancePlan=result.approved_rebalance_plan||result.paper_rebalance?.approved_rebalance?.latest_plan||state.contract.paper_rebalance?.approved_rebalance?.latest_plan||state.approvedRebalancePlan;state.allocationPlanStatus=state.approvedRebalancePlan?.status||state.recommendationReviewDraft?.review_status||state.monthlyRebalanceProposal?.status||state.paperRebalancePlan?.applied_status||state.paperRebalancePlan?.status||state.allocationPlanStatus;state.allocationDraftWeights=null}

async function allocationApi(path,body){const r=await fetch(path,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(body||{})}),result=await r.json();if(!r.ok)throw new Error(result.error||"Paper rebalance request failed");await allocationRefreshFromResponse(result);return result}

function allocationRecommendationRowsPayload(c){return allocationPlanRows(c).map(r=>recommendationRecordForStrategy(c,r))}

function allocationLatestRecommendationDraft(c){return state.recommendationReviewDraft||c.paper_rebalance?.recommendation_review?.latest_draft||null}
function allocationLatestApprovedPlan(c){return state.approvedRebalancePlan||c.paper_rebalance?.approved_rebalance?.latest_plan||null}
function allocationLatestMonthlyProposal(c){return state.monthlyRebalanceProposal||c.paper_rebalance?.monthly_proposal?.latest_proposal||null}
function allocationLatestAppliedEvent(c){return c.paper_rebalance?.approved_rebalance?.latest_applied_event||null}
function allocationBookedTransactionCost(c){const approved=allocationLatestApprovedPlan(c),event=allocationLatestAppliedEvent(c);return approved?.status==="APPLIED_PAPER"?(approved.total_transaction_cost_booked??event?.total_transaction_cost??0):0}
function allocationCombinedDynamicSummary(c){const event=allocationLatestAppliedEvent(c),summary=event?.combined_dynamic_summary||allocationAppliedTarget(c)?.combined_dynamic_summary||{};return {ordinary_strategy_count:summary.ordinary_strategy_count??ordinaryActiveRows(c).length,ordinary_weight_total:summary.ordinary_weight_total??ordinaryActiveRows(c).reduce((n,s)=>n+Number(allocationAppliedWeights(c)[s.strategy_uid||s.internal_id]??s.current_weight??0),0),computed_from:summary.computed_from||"dynamic ordinary active strategy rows"}}

async function allocationGeneratePlan(){const total=allocationTargetTotal(allocationDraft(state.contract)),v=allocationPlanValidation(total);if(!v.ok){toast(v.detail,"negative");return}try{state.allocationBusy=true;render();const result=await allocationApi("/api/paper-rebalance/recommendation-review-draft",{portfolio_nav:allocationShadowCapital(state.contract),source_recommendation_artifact:"operational_snapshot_runtime_recommendation_rows",recommendation_rows:allocationRecommendationRowsPayload(state.contract)});state.recommendationReviewDraft=result.recommendation_review_draft||result.paper_rebalance?.recommendation_review?.latest_draft;state.allocationPlanStatus="DRAFT_NOT_APPLIED";toast("Recommendation review draft created; no NAV/P&L impact","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}
async function allocationApproveRecommendationDraft(){const draft=allocationLatestRecommendationDraft(state.contract);if(!draft?.proposal_id){toast("Generate Recommendation Review Draft first","warning");return}if(!confirm("Approve this recommendation review draft as a rebalance plan artifact only? No NAV/P&L impact, no ledger mutation, and no live/brokerage orders."))return;try{state.allocationBusy=true;render();const result=await allocationApi("/api/paper-rebalance/approve-recommendation-draft",{draft_id:draft.proposal_id});state.approvedRebalancePlan=result.approved_rebalance_plan||result.paper_rebalance?.approved_rebalance?.latest_plan;state.allocationPlanStatus="APPROVED_WAITING_EFFECTIVE_DATE";toast("Approved Plan Created; Waiting Effective Date","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}
async function allocationApplyApprovedPlan(){const approved=allocationLatestApprovedPlan(state.contract);if(!approved?.plan_id){toast("Approve a rebalance plan artifact first","warning");return}if(!confirm("Apply approved paper rebalance now if backend session_state has reached the effective date? This books paper-only estimated cost and creates no live/brokerage orders."))return;try{state.allocationBusy=true;render();const result=await allocationApi("/api/paper-rebalance/apply-approved",{plan_id:approved.plan_id});state.approvedRebalancePlan=result.paper_apply_result?.plan||result.paper_rebalance?.approved_rebalance?.latest_plan;state.allocationPlanStatus=state.approvedRebalancePlan?.status||"APPROVED_WAITING_EFFECTIVE_DATE";const applyResult=result.paper_apply_result||{};toast(applyResult.already_applied?"Already applied; no cost re-booked":applyResult.applied?"Applied paper rebalance; no live/brokerage orders":applyResult.message||"Waiting effective date","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}
async function allocationGenerateMonthlyProposal(force=false){const rows=allocationRecommendationRowsPayload(state.contract);try{state.allocationBusy=true;render();const result=await allocationApi("/api/paper-rebalance/monthly-proposal",{portfolio_nav:allocationShadowCapital(state.contract),source_recommendation_artifact:"operational_snapshot_runtime_recommendation_rows",source_strategy_universe_snapshot:state.contract.snapshot_id||state.contract.as_of_date,recommendation_rows:rows,force:!!force});state.monthlyRebalanceProposal=result.monthly_rebalance_proposal||result.paper_rebalance?.monthly_proposal?.latest_proposal;state.allocationPlanStatus="MONTHLY_PROPOSAL_READY";toast("Monthly Proposal Ready; not approved and no NAV/P&L impact","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}
async function allocationReviewMonthlyProposal(){const proposal=allocationLatestMonthlyProposal(state.contract);if(!proposal?.proposal_id){toast("Generate Monthly Proposal first","warning");return}try{state.allocationBusy=true;render();const result=await allocationApi("/api/paper-rebalance/monthly-proposal/review-draft",{proposal_id:proposal.proposal_id});state.recommendationReviewDraft=result.recommendation_review_draft||result.paper_rebalance?.recommendation_review?.latest_draft;state.allocationPlanStatus="DRAFT_NOT_APPLIED";toast("Monthly proposal loaded as Recommendation Review Draft; no NAV/P&L impact","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}

async function allocationAcceptPlan(){const c=state.contract,plan=allocationLatestPlan(c),total=allocationTargetTotal(allocationDraft(c)),v=allocationPlanValidation(total);if(!v.ok||allocationHasReview(c)){toast(!v.ok?v.detail:"Review rows block accept/apply","negative");return}if(!plan?.plan_id){toast("Generate a project paper plan first","warning");return}try{state.allocationBusy=true;render();await allocationApi("/api/paper-rebalance/accept",{plan_id:plan.plan_id});toast("Plan accepted; pending next paper allocation application","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}

async function allocationApplyPlan(){const c=state.contract,plan=allocationLatestPlan(c),total=allocationTargetTotal(allocationDraft(c)),v=allocationPlanValidation(total);if(!v.ok||allocationHasReview(c)){toast(!v.ok?v.detail:"Review rows block accept/apply","negative");return}if(!plan?.plan_id){toast("Generate and accept a project paper plan first","warning");return}try{state.allocationBusy=true;render();await allocationApi("/api/paper-rebalance/apply",{plan_id:plan.plan_id});toast("Applied as next paper allocation baseline; no live fill and no official ledger mutation","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}

async function allocationRejectPlan(){const plan=allocationLatestPlan(state.contract);if(!plan?.plan_id){state.allocationPlanStatus="Rejected";allocationPersistDraft(state.contract);render();return}try{state.allocationBusy=true;render();await allocationApi("/api/paper-rebalance/reject",{plan_id:plan.plan_id});toast("Paper plan rejected","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}

function allocationSyncTargetUi(total){const v=allocationPlanValidation(total);document.querySelector("[data-allocation-total]")?.replaceChildren(document.createTextNode(UI.percent(total,2)));document.querySelector("[data-allocation-residual]")?.replaceChildren(document.createTextNode(UI.percent(v.residual,2)));document.querySelector("[data-allocation-over-under]")?.replaceChildren(document.createTextNode(UI.percent(v.overUnder,2)));document.querySelector("[data-allocation-validation]")?.replaceChildren(document.createTextNode(v.state));document.querySelectorAll('[data-allocation-action="save"],[data-allocation-action="generate"]').forEach(b=>{b.disabled=!v.ok});document.querySelectorAll('[data-allocation-action="accept"],[data-allocation-action="apply"]').forEach(b=>{b.disabled=!v.ok||allocationHasReview(state.contract)})}

function bindAllocationControls(){document.querySelectorAll("[data-allocation-input]").forEach(input=>input.addEventListener("input",e=>{const id=e.target.dataset.allocationInput,value=Number(e.target.value);if(!state.allocationDraftWeights)allocationDraft(state.contract);state.allocationDraftWeights[id]=Number.isFinite(value)?Math.max(0,value)/100:0;state.allocationPlanStatus="Draft / Review";allocationSyncTargetUi(allocationTargetTotal(state.allocationDraftWeights))}));document.querySelectorAll("[data-allocation-action]").forEach(b=>b.addEventListener("click",()=>{const a=b.dataset.allocationAction;if(a==="equal")allocationSetEqual();if(a==="recommend")allocationSetRecommended();if(a==="normalize")allocationNormalize();if(a==="save")allocationSaveTarget();if(a==="generate")allocationGeneratePlan();if(a==="monthlyProposal")allocationGenerateMonthlyProposal(false);if(a==="monthlyProposalForce")allocationGenerateMonthlyProposal(true);if(a==="reviewMonthlyProposal")allocationReviewMonthlyProposal();if(a==="approveDraft")allocationApproveRecommendationDraft();if(a==="applyApproved")allocationApplyApprovedPlan();if(a==="accept")allocationAcceptPlan();if(a==="apply")allocationApplyPlan();if(a==="modify"){state.allocationPlanStatus="Draft / Review";allocationPersistDraft(state.contract);render()}if(a==="reject")allocationRejectPlan()}))}

function allocationControlStrip(c,total,validation){const applied=allocationAppliedTarget(c),plan=allocationLatestPlan(c),draft=allocationLatestRecommendationDraft(c),approved=allocationLatestApprovedPlan(c),cost=allocationLatestCost(c),isApplied=approved?.status==="APPLIED_PAPER",booked=allocationBookedTransactionCost(c);return `<section class="allocation-control-strip allocation-control-strip-v2"><div><span>Mode</span><b>${isApplied?"Plan Applied / Paper Effective":"Recommendation Only"}</b></div><div><span>Review Status</span><b>${UI.escapeHtml(approved?.status||draft?.review_status||"DRAFT_NOT_APPLIED")}</b></div><div><span>Draft Target</span><b data-allocation-total class="tone-${validation.tone}">${UI.percent(total,2)}</b></div><div><span>${isApplied?"Applied Effective Date":"Effective Date"}</span><b>${UI.escapeHtml(approved?.applied_effective_date||approved?.effective_date||c.session_state?.next_trading_session||"Backend session pending")}</b></div><div><span>Proposal Artifact</span><b>${UI.escapeHtml(approved?.plan_id||draft?.proposal_id||"Pending draft")}</b></div><div><span>Estimated Transaction Cost</span><b>${UI.money(approved?.estimated_total_transaction_cost??draft?.estimated_transaction_cost_total??plan?.paper_transaction_cost_total??cost?.paper_transaction_cost_total??0)}</b></div><div><span>Booked Transaction Cost</span><b>${UI.money(booked)}</b></div><div><span>NAV/P&amp;L impact</span><b class="tone-warning">${isApplied?"No fake historical P&L rewrite":"No NAV/P&L Impact Yet"}</b></div><div><span>Live/Brokerage Orders</span><b class="tone-positive">None</b></div></section>`}

function allocationDecisionRows(c){const rows=allocationPlanRows(c);return `<div class="allocation-decision-grid" role="table"><div class="allocation-decision-header" role="row"><span>Strategy</span><span>Current %</span><span>Target %</span><span>Suggested %</span><span>Paper Trade $</span><span>Action</span><span>Reason / Rationale</span></div><div class="allocation-decision-body">${rows.map(r=>{const action=r.recommendationAction||allocationDecision(r),tone=allocationDecisionTone(action),tradeText=r.material?UI.money(r.trade):r.hasData?UI.money(0):"Unavailable";return `<div class="allocation-decision-row" role="row"><div><strong>${UI.escapeHtml(r.s.ui_name||r.s.display_name||r.s.internal_id)}</strong><small>${UI.escapeHtml(r.s.display_id||r.s.internal_id)}</small></div><span>${allocationDisplayPercent(r.current)}</span><label><input class="allocation-input" type="number" min="0" step="0.01" value="${((r.target??0)*100).toFixed(2)}" data-allocation-input="${UI.escapeHtml(r.s.internal_id)}" aria-label="Target allocation for ${UI.escapeHtml(r.s.ui_name||r.s.internal_id)}"><em>%</em></label><span class="allocation-suggested">${allocationDisplayPercent(r.suggestedTarget)}</span><span class="tone-${r.material?UI.toneForNumber(r.trade):"info"}">${tradeText}</span><span><i class="allocation-action-badge tone-${tone}">${action}</i></span><span class="allocation-reason">${UI.escapeHtml(r.reason)}</span></div>`}).join("")}</div></div>`}

function allocationTradeRows(c){const approved=allocationLatestApprovedPlan(c),event=allocationLatestAppliedEvent(c),draft=allocationLatestRecommendationDraft(c),draftRows=approved?.rows||draft?.line_items||[],rows=draftRows.length?draftRows:allocationPlanRows(c).map(r=>recommendationRecordForStrategy(c,r)),isApplied=approved?.status==="APPLIED_PAPER";if(!rows.length)return `<tr><td colspan="8"><strong>No recommendation review draft rows available.</strong><small>Generate Recommendation Review Draft to persist a DRAFT_NOT_APPLIED artifact.</small></td></tr>`;return rows.map(r=>{const uid=r.strategy_uid||"Missing strategy_uid",booked=event?.per_strategy_transaction_cost?.[uid]??0,tradeWeight=event?.per_strategy_trade_weight?.[uid];return `<tr><td>${UI.escapeHtml(uid)}</td><td><strong>${UI.escapeHtml(r.strategy_name||"Unavailable")}</strong><small>${UI.escapeHtml(r.recommendation_reason||"Recommendation review line")}</small></td><td class="tone-info">${UI.escapeHtml(isApplied?"PAPER_WEIGHTED":r.action_status||"REVIEW")}</td><td>${allocationDisplayMoney(Math.abs(Number(r.estimated_trade||0)))}</td><td>${allocationDisplayPercent(r.current_weight)}</td><td>${allocationDisplayPercent(r.approved_target_weight??r.proposed_weight)}</td><td>${UI.money(isApplied?booked:r.estimated_transaction_cost||0)}${isApplied&&tradeWeight!=null?`<small>Trade weight ${allocationDisplayPercent(tradeWeight)}</small>`:""}</td><td>${isApplied?"Plan Applied / Paper Effective; active-unallocated rows now paper-weighted where approved target > 0; no fake NAV/P&L rewrite":approved?"Approved Plan Created; Waiting Effective Date; $0 booked until effective date; no NAV/P&L impact yet":"Recommendation Only; Draft Not Applied; no NAV/P&L impact"}</td></tr>`}).join("")}

function allocationWarnings(c,total,validation){const pending=(c.strategies||[]).filter(s=>!allocationActiveSleeves(c).some(a=>a.internal_id===s.internal_id)),review=allocationHasReview(c),draft=allocationLatestRecommendationDraft(c);return `<div class="allocation-warning-list"><div><span>Validation</span><b class="tone-${validation.tone}">${validation.detail}</b></div><div><span>Draft creation allowed</span><b>${validation.ok?"Yes":"Blocked"}</b></div><div><span>Accept / Apply</span><b>Disabled in Phase 1B</b></div><div><span>Residual cash handling</span><b>${validation.residual>0?`${UI.percent(validation.residual,2)} retained as residual cash`:"No residual cash"}</b></div><div><span>Warning badges</span><b>PUBLIC_FALLBACK / NOT PIT / NOT SURVIVORSHIP-FREE / Missing ML do not hard block</b></div><div><span>Review rows</span><b>${review?"Present - review before later phases":"None detected"}</b></div><div><span>Pending / inactive excluded</span><b>${pending.length}</b></div><div><span>Recommendation draft</span><b>${draft?.proposal_id||"Pending generation"}</b></div><div><span>Official ledger unchanged</span><b>Yes</b></div><div><span>Live trading disabled</span><b>No live brokerage fill</b></div></div>`}

function allocationActionsPanel(validation){const draft=allocationLatestRecommendationDraft(state.contract),approved=allocationLatestApprovedPlan(state.contract),applied=approved?.status==="APPLIED_PAPER",disableCore=!validation.ok||state.allocationBusy,canApprove=!!draft?.proposal_id&&!approved?.plan_id&&!state.allocationBusy,canApply=!!approved?.plan_id&&!applied&&!state.allocationBusy,combined=allocationCombinedDynamicSummary(state.contract),booked=allocationBookedTransactionCost(state.contract);return UI.Panel({title:"Recommendation Review Draft",meta:"Phase 2C applied-state readiness",className:"allocation-action-center",body:`<div class="allocation-buttons"><button data-allocation-action="recommend">Apply Suggested Targets</button><button data-allocation-action="equal">Reset Equal Weight</button><button data-allocation-action="normalize">Normalize to 100%</button><button data-allocation-action="save" ${validation.ok?"":"disabled"}>Save Local Draft</button><button data-allocation-action="generate" ${!disableCore?"":"disabled"}>Generate Recommendation Review Draft</button><button data-allocation-action="monthlyProposal" ${!disableCore?"":"disabled"}>Generate Monthly Proposal</button><button data-allocation-action="monthlyProposalForce" ${!disableCore?"":"disabled"}>Force New Monthly Proposal</button><button class="approve-tile" data-allocation-action="approveDraft" ${canApprove?"":"disabled"}>Approve Rebalance Plan Artifact</button><button class="approve-tile" data-allocation-action="applyApproved" ${canApply?"":"disabled"}>Apply Approved Paper Rebalance</button><button class="reject-tile" data-allocation-action="reject">Reject Local View</button></div><div class="decision-box compact"><strong>${UI.escapeHtml(approved?.status||draft?.review_status||state.allocationPlanStatus||"DRAFT_NOT_APPLIED")}</strong><span>${applied?`Plan Applied / Paper Effective. Applied effective date ${UI.escapeHtml(approved.applied_effective_date||approved.effective_date||"N/A")}. Total booked transaction cost ${UI.money(booked)}.`:approved?`Approved Plan Created. Waiting Effective Date: ${UI.escapeHtml(approved.effective_date||"backend session pending")}. Estimated Transaction Cost ${UI.money(approved.estimated_total_transaction_cost||0)}. $0 booked until effective date.`:`${validation.detail}. Recommendation Only. Draft Not Applied.`}</span><em>No Live/Brokerage Orders | Historical P&amp;L not rewritten | Combined updated dynamically from ${combined.ordinary_strategy_count} ordinary rows</em></div>`})}

function allocationMonthlyProposalPanel(c){const proposal=allocationLatestMonthlyProposal(c),ready=proposal?.status==="MONTHLY_PROPOSAL_READY",rows=proposal?.rows||[],warnings=proposal?.warnings||[],meta=ready?`${proposal.proposal_id}; proposal-only monthly artifact`:"Dynamic recommendation rows; one proposal per month unless force=true";return UI.Panel({title:"Monthly Auto Proposal",meta,className:"allocation-monthly-proposal compact",body:`<div class="allocation-warning-list compact"><div><span>Status</span><b>${UI.escapeHtml(proposal?.status||"NOT_CREATED")}</b></div><div><span>Review</span><b>${UI.escapeHtml(proposal?.review_status||"NOT_APPROVED")}</b></div><div><span>Proposal Month</span><b>${UI.escapeHtml(proposal?.proposal_month||c.session_state?.calendar_date?.slice(0,7)||"Backend session pending")}</b></div><div><span>Rows</span><b>${rows.length}</b></div><div><span>Estimated Transaction Cost</span><b>${UI.money(proposal?.estimated_total_transaction_cost||0)}</b></div><div><span>Residual Cash</span><b>${allocationDisplayPercent(proposal?.residual_cash??0)}</b></div><div><span>Warnings / caps</span><b>${UI.escapeHtml(warnings.length?warnings.join(" / "):"None")}</b></div><div><span>NAV/P&amp;L</span><b>No NAV/P&amp;L Impact Yet</b></div><div><span>Orders</span><b>No Live/Brokerage Orders</b></div></div><div class="allocation-buttons"><button data-allocation-action="reviewMonthlyProposal" ${ready&&!state.allocationBusy?"":"disabled"}>Review Monthly Proposal</button></div><p class="factory-artifact-note">Monthly Proposal Ready is proposal-only. Review creates a DRAFT_NOT_APPLIED recommendation review draft; approval/apply remain separate.</p>`})}

function allocationMembershipSummary(c){const active=allocationActiveSleeves(c),pending=(c.strategies||[]).length-active.length;return UI.Panel({title:"Current Membership / Allocation Summary",meta:"Derived from registry and paper target artifact",body:`<div class="allocation-warning-list"><div><span>Active sleeve count</span><b>${active.length}</b></div><div><span>Pending / inactive excluded</span><b>${pending}</b></div><div><span>Current baseline source</span><b>${allocationAppliedTarget(c)?"Applied paper target":"Snapshot weights"}</b></div><div><span>Last applied paper rebalance</span><b>${allocationAppliedTarget(c)?.applied_at?.slice(0,10)||"Unavailable"}</b></div></div>`})}

function p0MissingPaperAllocationProposal(){return {ok:false,status:"MISSING_ARTIFACT",source:"paper_allocation_proposal_v1",artifact:null,artifact_path:null,message:"No paper allocation proposal artifact has been generated yet.",paper_shadow_only:true,financial_state_mutated:false}}
function p0PaperProposalPayload(c){return c?.paper_allocation_proposal||state.paperAllocationProposal||p0MissingPaperAllocationProposal()}
function p0ProposalArtifact(c){const p=p0PaperProposalPayload(c);return p?.artifact&&typeof p.artifact==="object"?p.artifact:null}
function p0ProposalRows(c){const a=p0ProposalArtifact(c);return Array.isArray(a?.rows)?a.rows:[]}
function p0ProposalUid(row){return String(row?.strategy_uid||row?.strategy_id||row?.internal_id||row?.id||"")}
function p0ProposalName(row){return row?.display_name||row?.strategy_name||p0ProposalUid(row)||"Strategy"}
function p0Number(value,fallback=0){const n=Number(value);return Number.isFinite(n)?n:fallback}
function p0CurrentWeight(row){return p0Number(row?.current_weight,0)}
function p0SuggestedWeight(row){return p0Number(row?.suggested_weight??row?.target_weight??row?.proposed_weight,0)}
function p0DraftTarget(row){const uid=p0ProposalUid(row),saved=state.allocationTargetDrafts?.[uid];return saved!=null?p0Number(saved,0):p0SuggestedWeight(row)}
function p0DraftRows(c){return p0ProposalRows(c).map(row=>{const target=p0DraftTarget(row),current=p0CurrentWeight(row);return {...row,target_weight:target,delta:target-current}})}
function p0DraftSummary(c){const rows=p0DraftRows(c),targetSum=rows.reduce((n,row)=>n+p0Number(row.target_weight,0),0),residual=1-targetSum;return {rows,targetSum,residual,sumsTo100:Math.abs(residual)<=0.000001}}
function p0ActionTone(action){const text=String(action||"").toUpperCase();if(text.includes("INCREASE"))return "positive";if(text.includes("REDUCE"))return "negative";if(text.includes("REVIEW")||text.includes("CANDIDATE"))return "warning";return "info"}
function p0ProposalTable(c){const payload=p0PaperProposalPayload(c),rows=p0DraftRows(c);if(!rows.length)return `<div class="work-table-wrap"><table class="work-table"><thead><tr>${["Strategy","Current %","Suggested %","Target %","Delta","Score","Action","Reason"].map(x=>`<th>${x}</th>`).join("")}</tr></thead><tbody><tr><td colspan="8">Proposal missing. Generate first with the P0 paper allocation proposal endpoint.</td></tr></tbody></table></div><footer class="monitor-table-footer"><span>Source: GET /api/automation-intelligence/paper-allocation-proposal/latest</span><b>${UI.escapeHtml(payload.message||payload.status||"Missing proposal")}</b></footer>`;return `<div class="work-table-wrap"><table class="work-table"><thead><tr>${["Strategy","Current %","Suggested %","Target %","Delta","Score","Action","Reason"].map(x=>`<th>${x}</th>`).join("")}</tr></thead><tbody>${rows.map(row=>{const uid=p0ProposalUid(row),current=p0CurrentWeight(row),suggested=p0SuggestedWeight(row),target=p0DraftTarget(row),delta=target-current,action=row.action||row.suggested_action||"REVIEW";return `<tr><td><strong>${UI.escapeHtml(p0ProposalName(row))}</strong><small>${UI.escapeHtml(uid)}</small></td><td>${UI.percent(current,2)}</td><td>${UI.percent(suggested,2)}</td><td><input class="allocation-target-input" type="number" min="0" step="0.01" value="${(target*100).toFixed(2)}" data-p0-target-uid="${UI.escapeHtml(uid)}"></td><td class="tone-${UI.toneForNumber(delta)}">${UI.percent(delta,2)}</td><td>${row.score==null?"N/A":UI.displayNumber(row.score,{maximumFractionDigits:2})}</td><td><span class="status-badge ${p0ActionTone(action)}">${UI.escapeHtml(String(action))}</span></td><td>${UI.escapeHtml(row.reason||row.short_reason||"Review required.")}</td></tr>`}).join("")}</tbody></table></div><footer class="monitor-table-footer"><span>Source: ${UI.escapeHtml(payload.artifact_path||"latest proposal artifact")}</span><b>Proposal only. Target edits are local draft state; no NAV/P&amp;L mutation, no approved plan, no auto-apply.</b></footer>`}
function p0ExistingApprovedPlanPanel(c){const approved=allocationLatestApprovedPlan(c);if(!approved?.plan_id)return UI.Panel({title:"Existing Approved Paper Plan",meta:"Legacy/current paper rebalance state",body:`<div class="allocation-warning-list"><div><span>Status</span><b>None / Not Approved</b></div><div><span>Effective Date</span><b>Not Scheduled</b></div><div><span>Boundary</span><b>Not the current P0 proposal</b></div></div>`});return UI.Panel({title:"Existing Approved Paper Plan",meta:"Legacy/current paper rebalance state, separate from P0 proposal",body:`<div class="allocation-warning-list"><div><span>Plan</span><b>${UI.escapeHtml(approved.plan_id)}</b></div><div><span>Status</span><b>${UI.escapeHtml(approved.status||"Approved Waiting Effective Date")}</b></div><div><span>Effective Date</span><b>${UI.escapeHtml(approved.effective_date||"Not Scheduled")}</b></div><div><span>Source</span><b>data/paper_rebalance/approved_rebalance_plans.json</b></div><div><span>P0 Boundary</span><b>Not the current P0 proposal</b></div></div>`})}
function p0ProposalOpsPanel(c){const payload=p0PaperProposalPayload(c),artifact=p0ProposalArtifact(c),summary=p0DraftSummary(c),hasRows=summary.rows.length>0,canReport=hasRows&&summary.sumsTo100&&!state.allocationBusy;return UI.Panel({title:"Proposal Operations",meta:"P0 paper allocation proposal only / no live trading",className:"allocation-action-center",body:`<div class="allocation-warning-list"><div><span>Proposal</span><b>${hasRows?"Available":"Missing / Generate first"}</b></div><div><span>Target Sum</span><b>${hasRows?UI.percent(summary.targetSum,2):"N/A"}</b></div><div><span>Residual</span><b>${hasRows?UI.percent(summary.residual,2):"N/A"}</b></div><div><span>Candidates Added</span><b>${artifact?.summary?.active_unallocated_candidate_count??"N/A"}</b></div><div><span>Estimated Turnover</span><b>${artifact?.summary?.estimated_turnover!=null?UI.percent(artifact.summary.estimated_turnover,2):"N/A"}</b></div><div><span>Estimated Cost</span><b>${artifact?.summary?.estimated_transaction_cost!=null?UI.money(artifact.summary.estimated_transaction_cost):"N/A"}</b></div><div><span>Last Proposal Date</span><b>${artifact?.as_of_date||"N/A"}</b></div><div><span>Next Biweekly Proposal</span><b>${artifact?.next_scheduled_proposal_date||"N/A"}</b></div><div><span>Mode</span><b>Paper Only / No Live Trading</b></div></div><div class="allocation-buttons"><button data-p0-allocation-action="generate" ${state.allocationBusy?"disabled":""}>Generate Proposal</button><button data-p0-allocation-action="suggested" ${hasRows&&!state.allocationBusy?"":"disabled"}>Reset to Suggested</button><button data-p0-allocation-action="current" ${hasRows&&!state.allocationBusy?"":"disabled"}>Reset to Current</button><button data-p0-allocation-action="normalize" ${hasRows&&!state.allocationBusy?"":"disabled"}>Normalize to 100%</button><button data-p0-allocation-action="save" ${hasRows&&!state.allocationBusy?"":"disabled"}>Save Draft</button><button data-p0-allocation-action="report" ${canReport?"":"disabled"}>Generate Allocation Report</button></div><p class="factory-artifact-note">${UI.escapeHtml(payload.message||"Report generation uses editable Target values. No approval/apply action is created by this page.")}</p>`})}
function p0PaperProposalPanel(c){return `<div class="allocation-layout allocation-layout-v2"><section class="panel allocation-matrix-panel">${UI.SectionHeader({title:"Paper Allocation Proposal",meta:"Current % | Suggested % | editable Target % | Delta | Score | Action | Reason"})}${p0ProposalTable(c)}</section><aside class="allocation-side">${p0ProposalOpsPanel(c)}${p0ExistingApprovedPlanPanel(c)}</aside></div>`}
function p0SetDraftTargets(c,mode){const rows=p0ProposalRows(c);if(mode==="suggested")state.allocationTargetDrafts=Object.fromEntries(rows.map(row=>[p0ProposalUid(row),p0SuggestedWeight(row)]));if(mode==="current")state.allocationTargetDrafts=Object.fromEntries(rows.map(row=>[p0ProposalUid(row),p0CurrentWeight(row)]));state.allocationDraftStatus=mode==="current"?"Reset to Current":"Reset to Suggested";render()}
function p0NormalizeTargets(c){const rows=p0ProposalRows(c),draft=Object.fromEntries(rows.map(row=>[p0ProposalUid(row),p0DraftTarget(row)])),total=Object.values(draft).reduce((n,v)=>n+p0Number(v,0),0);if(total<=0){toast("Cannot normalize zero target","negative");return}state.allocationTargetDrafts=Object.fromEntries(Object.entries(draft).map(([uid,value])=>[uid,p0Number(value,0)/total]));state.allocationDraftStatus="Normalized to 100%";render()}
function p0ReportRowsPayload(c){return p0DraftRows(c).map(row=>({strategy_uid:p0ProposalUid(row),display_name:p0ProposalName(row),current_weight:p0CurrentWeight(row),suggested_weight:p0SuggestedWeight(row),target_weight:p0DraftTarget(row),score:row.score,action:row.action||row.suggested_action,reason:row.reason||row.short_reason,evidence_status:row.evidence_status,ml_status:row.ml_status,source_artifacts:row.source_artifacts||[]}))}
async function p0GeneratePaperProposal(){try{state.allocationBusy=true;render();const r=await fetch("/api/automation-intelligence/paper-allocation-proposal/generate",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({paper_shadow_only:true})}),result=await r.json();if(!r.ok)throw new Error(result.error||result.message||"Paper allocation proposal generation failed");state.paperAllocationProposal=result;if(state.contract)state.contract.paper_allocation_proposal=result;state.allocationTargetDrafts={};toast("Paper allocation proposal generated","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}
async function p0GenerateAllocationReport(){const c=state.contract,summary=p0DraftSummary(c);if(!summary.rows.length){toast("Generate proposal first","warning");return}if(!summary.sumsTo100){toast("Target weights must sum to 100% before report generation","negative");return}try{state.allocationBusy=true;render();const result=await fetch("/api/automation-intelligence/paper-allocation-report/generate",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({source_proposal_artifact:p0PaperProposalPayload(c).artifact_path,rows:p0ReportRowsPayload(c),draft_summary:{target_weight_sum:summary.targetSum,residual_weight:summary.residual,source:"editable_target"}})}).then(async r=>{const payload=await r.json();if(!r.ok)throw new Error(payload.error||payload.message||"Allocation report generation failed");return payload});state.paperAllocationReport=result;toast("Allocation report generated from editable Target","positive")}catch(e){toast(e.message,"negative")}finally{state.allocationBusy=false;render()}}
function bindP0AllocationControls(){document.querySelectorAll("[data-p0-target-uid]").forEach(input=>input.addEventListener("input",e=>{const uid=e.target.dataset.p0TargetUid,value=Number(e.target.value);state.allocationTargetDrafts={...(state.allocationTargetDrafts||{}),[uid]:Number.isFinite(value)?Math.max(0,value)/100:0};state.allocationDraftStatus="Draft / Review"}));document.querySelectorAll("[data-p0-allocation-action]").forEach(button=>button.addEventListener("click",()=>{const action=button.dataset.p0AllocationAction;if(action==="generate")p0GeneratePaperProposal();if(action==="suggested")p0SetDraftTargets(state.contract,"suggested");if(action==="current")p0SetDraftTargets(state.contract,"current");if(action==="normalize")p0NormalizeTargets(state.contract);if(action==="save"){state.allocationDraftStatus="Saved Draft";toast("Editable Target draft saved in browser state","positive");render()}if(action==="report")p0GenerateAllocationReport()}))}
function allocationPage(){const c=state.contract,total=allocationTargetTotal(allocationDraft(c)),validation=allocationPlanValidation(total);return `<main class="main-stage"><div class="page workflow-page allocation-workstation-page">${pageTitle("Allocation & Rebalance","P0 paper allocation proposal/report; no approve/apply and no NAV/P&L mutation")}${p0PaperProposalPanel(c)}<details class="allocation-legacy-tool collapsed-legacy-tool"><summary>Legacy / Manual Draft Tool - Not Current P0 Proposal</summary><div class="allocation-layout allocation-layout-v2"><section class="panel allocation-matrix-panel">${UI.SectionHeader({title:"Legacy Manual Draft Matrix",meta:"Collapsed; local scorecard only, not backend current P0 proposal truth"})}${allocationDecisionRows(c)}<footer class="monitor-table-footer"><span>This legacy tool is hidden by default and must not be read as current backend P0 proposal truth.</span><b>No live orders. No review draft generation from page load.</b></footer></section><aside class="allocation-side">${allocationActionsPanel(validation)}${allocationMonthlyProposalPanel(c)}${UI.Panel({title:"Validation / Warnings",meta:"Legacy manual draft safety checks",body:allocationWarnings(c,total,validation)})}${allocationMembershipSummary(c)}</aside></div></details></div></main>`}

function workflowCommandDiagram(c,{active,pending,coverage,schedulerState,manual,poll,refresh}){const paperRows=(c.paper_performance_daily||[]).length,latestPaper=c.paper_performance_daily_metadata?.latest_date||latestPaperPerformanceDate(c)||"Limited history",holdings=c.holdings.length,delayedCoverage=coverage||"Unavailable",plan=c.paper_rebalance?.latest_plan,applied=c.paper_rebalance?.current_paper_target,dashTabs=Array.isArray(WORKFLOW_TABS)?WORKFLOW_TABS.length:"Unavailable";const cards=[

  [1,"Strategy Registry",`${active.length} active / ${pending.length} pending`,["Active sleeves from registry","Pending/inactive excluded","Future ACTIVE rows auto-join"],"positive"],

  [2,"Data & Proxy Layer",delayedCoverage,["Official ledger separate","Delayed estimate labeled proxy","Missing data stays Unavailable"],"warning"],

  [3,"Shadow Holdings",`${holdings} rows`,["Paper holdings artifact","Real funded capital: $0","No broker execution"],"info"],

  [4,"Refresh Engine",schedulerState,["Scheduler/config status from snapshot",`Manual ${manual}`,"Snapshot polling remains read-only"],"info"],

  [5,"Paper Performance",paperRows?`${paperRows} rows / ${latestPaper}`:"Limited history",["Paper performance separate","No fake official close","Delayed estimates separated"],"positive"],

  [6,"Risk / Allocation Controls",plan?.applied_status||"Draft / Review",["Paper target lifecycle","5 bps cost assumption","Apply only to paper baseline"],"warning"],

  [7,"Dashboard Command Center",`${dashTabs} tabs`,["Shared operational snapshot","Decision support only","No official ledger mutation"],"info"],

  [8,"PM Action Output",applied?"Applied paper target":"Human review required",["Accept / Modify / Reject","Apply as next paper allocation","No live fill"],"pending"]

 ];return `<section class="workflow-command-diagram"><header><div><strong>Shadow-Live Paper PM Command Workflow</strong><span>Dynamic paper strategy workflow for research admission, shadow holdings, delayed estimates, paper allocation, and dashboard monitoring.</span></div><em>${refresh}</em></header><div class="workflow-command-grid">${cards.map(x=>workflowDiagramCard(...x)).join("")}</div><div class="workflow-command-output"><strong>Output: Shadow-Live Paper Risk Workstation</strong><span>Official Ledger: separate</span><span>Paper Performance: separate</span><span>Delayed Estimate: separate</span><span>Brokerage Execution: disabled</span><span>Live Fill: no</span><span>Human Review: required</span></div></section>`}

function factoryPayload(){return state.strategyFactory||{ok:false,intake:{materials:[]},candidate_portfolio:[],allocation_drafts:[],applied_paper_strategies:[],backend_counts:{},safety_labels:["PROTOTYPE_ONLY","NOT_LIVE_TRADING","NOT_INSTITUTIONAL_VALIDATION","USER_CONFIRMATION_REQUIRED"]}}

function factoryMetric(v,type){if(v==null)return "N/A";return type==="percent"?UI.percent(v,2):type==="ratio"?UI.displayNumber(v,{maximumFractionDigits:2}):UI.displayNumber(v,{maximumFractionDigits:0})}

function factoryBadges(labels){return (labels||[]).map(x=>UI.StatusBadge({label:x,tone:x==="USER_CONFIRMATION_REQUIRED"?"pending":"warning",dot:true})).join("")}

function factoryWorkflowStrip(f){const counts=f.stage_counts||{},stages=f.workflow_stages||[];return `<section class="factory-workflow-strip">${stages.map(s=>`<div><span>${UI.escapeHtml(s.stage)}</span><b>${counts[s.count_key]??0}</b></div>`).join("")}</section>`}

function factoryListItems(xs){return (xs||[]).length?(xs||[]).map(x=>`<li>${UI.escapeHtml(String(x))}</li>`).join(""):"<li>Unavailable</li>"}

function factoryMaterialAnalysis(materials){const selected=(materials||[]).slice().reverse()[0];if(!selected)return `<section class="panel span-5">${UI.SectionHeader({title:"Material Review / Analysis",meta:"No selected material"})}<div class="na-block"><strong>No material uploaded</strong><span>Upload txt, md, csv, PDF, or xlsx. Unsupported extraction remains explicitly labeled.</span></div></section>`;const a=selected.analysis||{};return `<section class="panel span-5 factory-material-review">${UI.SectionHeader({title:"Material Review / Analysis",meta:UI.escapeHtml(selected.filename||"Selected material")})}<div class="factory-analysis-head"><div><span>Selected filename</span><b>${UI.escapeHtml(selected.filename)}</b></div><div><span>Extraction status</span><b>${UI.escapeHtml(selected.extraction_status)}</b></div><div><span>Extracted character count</span><b>${selected.extracted_character_count??0}</b></div><div><span>Source classification</span><b>${UI.escapeHtml(a.source_classification||"Unavailable")}</b></div><div><span>Testability</span><b>${UI.escapeHtml(a.testability||"Unavailable")}</b></div></div><p>${UI.escapeHtml(a.document_summary||"No analysis summary available.")}</p><div class="factory-analysis-grid"><div><strong>Key themes</strong><ul>${factoryListItems(a.key_themes)}</ul></div><div><strong>Strategy concepts</strong><ul>${factoryListItems(a.strategy_concepts)}</ul></div><div><strong>Signal ideas</strong><ul>${factoryListItems(a.signal_ideas)}</ul></div><div><strong>Risk filters</strong><ul>${factoryListItems(a.risk_filters)}</ul></div><div><strong>Data requirements</strong><ul>${factoryListItems(a.data_requirements)}</ul></div><div><strong>Implementation blockers</strong><ul>${factoryListItems(a.implementation_blockers)}</ul></div></div></section>`}

function factoryApplyReady(c,portfolio,drafts){return !!c&&portfolio.some(x=>x.strategy_id===c.strategy_id)&&drafts.some(x=>x.strategy_id===c.strategy_id)}

function factoryStageDone(c,stage){return (c?.completed_stages||[]).includes(stage)}

function factoryDetailRows(c){const m=c.backtest_metrics||{};return [["Strategy thesis",c.strategy_thesis],["Source papers/materials",(c.source_materials||[]).map(x=>`${x.filename}: ${x.contribution}`).join(" | ")||"No uploaded source material used"],["Source evidence",c.source_evidence?.honesty_note],["Signal formula",c.signal_formula],["Universe",c.universe],["Benchmark",c.benchmark],["Rebalance frequency",c.rebalance_frequency],["Holding period",c.holding_period],["Cost assumption",c.cost_assumption],["Date range",c.date_range],["Sample size",c.sample_size],["Gross metrics",`Return ${factoryMetric(m.gross_annual_return,"percent")} / Sharpe ${factoryMetric(m.gross_sharpe,"ratio")}`],["Net metrics",`Return ${factoryMetric(m.net_annual_return??m.annual_return,"percent")} / Sharpe ${factoryMetric(m.net_sharpe??m.sharpe,"ratio")} / Max DD ${factoryMetric(m.max_drawdown,"percent")}`],["Decision status",c.decision_status],["Next action",c.next_action]]}

function factoryChartGrid(c){const charts=c.chart_previews||[];return `<div class="factory-chart-grid">${charts.map(x=>`<figure><figcaption>${UI.escapeHtml(x.title)}</figcaption><img src="${x.path}" alt="${UI.escapeHtml(x.title)}"></figure>`).join("")}</div>`}

function factoryReportViewer(c){if(!c)return "";const r=c.report_sections||{},materialRows=Array.isArray(r["Uploaded Materials Reviewed"])?r["Uploaded Materials Reviewed"].map(x=>`<li><b>${UI.escapeHtml(x.filename||"Material")}</b> ${UI.escapeHtml(x.contribution||"No contribution recorded.")}</li>`).join(""):"<li>No uploaded materials reviewed.</li>",ideas=Array.isArray(r["Extracted Strategy Ideas"])?r["Extracted Strategy Ideas"].map(x=>`<li>${UI.escapeHtml(x)}</li>`).join(""):"<li>Unavailable</li>",raw=c.report_url?`<a class="tool-button" href="${c.report_url}" target="_blank" rel="noreferrer">Open Raw Markdown Artifact</a>`:`<span class="factory-artifact-note">Evidence report artifact required.</span>`;return `<section class="panel span-12 factory-report-viewer">${UI.SectionHeader({title:"Styled Strategy Factory Report",meta:"Boss-readable embedded report; markdown link retained after EVIDENCE_REPORT_CREATED"})}<article><h2>Executive Summary</h2><p>${UI.escapeHtml(r["Executive Summary"]||"Unavailable until EVIDENCE_REPORT_CREATED.")}</p><h3>Uploaded Materials Reviewed</h3><ul>${materialRows}</ul><h3>What Each Paper Contributed</h3><ul>${materialRows}</ul><h3>Extracted Strategy Ideas</h3><ul>${ideas}</ul><h3>Selected Prototype Strategy</h3><p>${UI.escapeHtml(r["Selected Prototype Strategy"]||c.strategy_id)}</p><h3>Why Selected First</h3><p>${UI.escapeHtml(r["Why Selected First"]||"Unavailable")}</p><h3>Backtest Methodology</h3><p>${UI.escapeHtml(r["Backtest Methodology"]||"Unavailable")}</p><h3>Performance Metrics</h3><div class="factory-report-metrics">${Object.entries(c.backtest_metrics||{}).map(([k,v])=>`<span><b>${UI.escapeHtml(k)}</b>${UI.escapeHtml(String(v))}</span>`).join("")||"<span><b>Backtest</b>BACKTEST_RUN: NOT_STARTED_OR_BLOCKED</span>"}</div><h3>Charts</h3>${factoryChartGrid(c)}<h3>ML Diagnostics</h3><p>${UI.escapeHtml(c.ml_result_summary||r["ML Diagnostics"]||"Unavailable until ML_DIAGNOSTICS_RUN.")}</p><h3>Feature Importance</h3><ul>${(c.ml_diagnostics?.feature_importance||[]).map(x=>`<li>${UI.escapeHtml(x.feature)}: ${UI.escapeHtml(String(x.importance))}</li>`).join("")||"<li>ML_DIAGNOSTICS_RUN: NOT_STARTED_OR_BLOCKED</li>"}</ul><h3>Where It Made Money</h3><p>${UI.escapeHtml(c.where_it_made_money||"Unavailable")}</p><h3>Where It Lost Money</h3><p>${UI.escapeHtml(c.where_it_lost_money||"Unavailable")}</p><h3>Limitations</h3><p>${UI.escapeHtml(r["Limitations"]||"Prototype-only; no institutional validation.")}</p><h3>Next Action</h3><p>${UI.escapeHtml(r["Next Action"]||c.next_action||"Review required.")}</p>${raw}</article></section>`}

function factoryCandidateCards(candidates,portfolio=[],drafts=[]){if(!candidates.length)return `<div class="na-block"><strong>No candidate generated</strong><span>Run Strategy Factory through extraction, analysis, and candidate idea stages before a candidate appears.</span></div>`;return candidates.map(c=>{const m=c.backtest_metrics||{},d=c.ml_diagnostics||{},wf=c.portfolio_workflow||{},hasBacktest=factoryStageDone(c,"BACKTEST_RUN"),hasMl=factoryStageDone(c,"ML_DIAGNOSTICS_RUN"),addEnabled=!!wf.add_enabled,allocEnabled=!!wf.allocation_enabled,applyEnabled=!!wf.apply_enabled,added=!!wf.in_candidate_portfolio,allocated=!!wf.allocation_draft_exists,applied=!!wf.applied_to_paper,addText=applied?"Applied to Paper Portfolio":added?"Added to Candidate Portfolio":addEnabled?"Add to Candidate Portfolio":"Requires Evidence Report",allocText=applied?"Allocation Used for Apply":allocated?"Allocation Draft Created":allocEnabled?"Generate Allocation Draft":"Requires Candidate Portfolio",applyText=applied?"Applied to Paper Portfolio":applyEnabled?"Apply to Paper Portfolio":"Requires Allocation Draft + Confirmation";return `<article class="factory-candidate-card"><header><div><strong>${UI.escapeHtml(c.name||c.strategy_id)}</strong><span>${UI.escapeHtml(c.strategy_id)} / ${UI.escapeHtml(c.source_derivation_status||"Source status unavailable")} / ${UI.escapeHtml(c.pipeline_stage||"PIPELINE")}</span></div>${factoryBadges(c.safety_labels)}</header><div class="factory-workflow-status"><span>Candidate workflow status</span><b>${UI.escapeHtml(wf.candidate_status||"PIPELINE_IN_PROGRESS")}</b></div><p>${UI.escapeHtml(c.strategy_thesis||"Research thesis unavailable.")}</p><div class="factory-metric-strip"><div><span>Sharpe</span><b>${hasBacktest?factoryMetric(m.sharpe,"ratio"):"Pending BACKTEST_RUN"}</b></div><div><span>Annual return</span><b>${hasBacktest?factoryMetric(m.annual_return,"percent"):"Pending BACKTEST_RUN"}</b></div><div><span>Max drawdown</span><b>${hasBacktest?factoryMetric(m.max_drawdown,"percent"):"Pending BACKTEST_RUN"}</b></div><div><span>Volatility</span><b>${hasBacktest?factoryMetric(m.volatility,"percent"):"Pending BACKTEST_RUN"}</b></div><div><span>Win rate</span><b>${hasBacktest?factoryMetric(m.win_rate,"percent"):"Pending BACKTEST_RUN"}</b></div><div><span>Turnover</span><b>${hasBacktest?factoryMetric(m.turnover,"percent"):"Pending BACKTEST_RUN"}</b></div></div><div class="factory-detail-grid">${factoryDetailRows(c).map(([k,v])=>`<div><span>${UI.escapeHtml(k)}</span><b>${UI.escapeHtml(String(v??"Unavailable"))}</b></div>`).join("")}</div><div class="factory-ml"><strong>${UI.escapeHtml(hasMl?(c.ml_model_used||"ML diagnostic unavailable"):"Pending ML_DIAGNOSTICS_RUN")}</strong><span>${UI.escapeHtml(hasMl?(c.ml_result_summary||"No ML result summary loaded."):"ML result unlocks only after ML_DIAGNOSTICS_RUN artifact exists.")}</span><em>Feature importance: ${hasMl?(d.feature_importance||[]).map(x=>UI.escapeHtml(x.feature)).join(", ")||"Unavailable":"Pending"}</em></div>${factoryChartGrid(c)}<div class="factory-actions"><a class="tool-button" href="#factoryReportViewer">View Report</a><button class="tool-button ${addEnabled?"":"factory-disabled"}" data-factory-action="add" data-strategy-id="${c.strategy_id}" ${addEnabled?"":"disabled"}>${addText}</button><button class="tool-button ${allocEnabled?"":"factory-disabled"}" data-factory-action="allocation" data-strategy-id="${c.strategy_id}" ${allocEnabled?"":"disabled"}>${allocText}</button><button class="tool-button ${applyEnabled?"approve-tile":"factory-disabled"}" data-factory-action="apply" data-strategy-id="${c.strategy_id}" ${applyEnabled?"":"disabled"}>${applyText}</button></div></article>`}).join("")}

function factoryStatusBanner(f){const msg=state.strategyFactoryStatusMessage||f.last_status_message;if(!msg)return "";return `<section class="factory-status-message"><strong>Strategy Factory status</strong><span>${UI.escapeHtml(msg)}</span></section>`}

function factoryDataStatusPanel(f){const d=f.data_status||{},p=d.provider_status||{},latest=d.latest_date||"Unavailable",symbols=d.symbols_available||p.available_symbols||[],missing=d.missing_required_data||p.missing_symbols||[],candidate=selectedFactoryCandidate(f)||{},decision=candidate.testability_decision||f.latest_run?.testability_decision||"Pending current run";return `<section class="factory-data-status-panel"><div><span>Provider mode</span><b>${UI.escapeHtml(d.provider_mode||p.provider_mode||"UNAVAILABLE")}</b></div><div><span>Symbols available</span><b>${UI.escapeHtml(String(symbols.length||0))}</b><em>${UI.escapeHtml(symbols.slice(0,8).join(", ")||"None")}</em></div><div><span>Latest date</span><b>${UI.escapeHtml(String(latest))}</b></div><div><span>Missing required data</span><b>${UI.escapeHtml(String(missing.length||0))}</b><em>${UI.escapeHtml(missing.slice(0,8).join(", ")||"None")}</em></div><div><span>Current run testability</span><b>${UI.escapeHtml(String(decision))}</b></div></section>`}

function factoryFullPipelinePanel(f){const c=selectedFactoryCandidate(f)||{},ml=c.ml_diagnostics||{},full=c.full_pipeline_status||"NOT_STARTED",backtest=c.backtest_status||factoryStageState("BACKTEST_RUN").status,mlStatus=ml.status||factoryStageState("ML_DIAGNOSTICS_RUN").status,evidence=c.evidence_report_path?"COMPLETED":factoryStageState("EVIDENCE_REPORT_CREATED").status,report=c.strategy_id?`<a class="tool-button" href="/api/strategy-factory/report/${UI.escapeHtml(c.strategy_id)}" target="_blank" rel="noreferrer">Open Report</a>`:`<span class="factory-artifact-note">Report unavailable until current_run exists.</span>`;return `<section class="factory-data-status-panel"><div><span>Full Pipeline status</span><b>${UI.escapeHtml(full)}</b><em>${UI.escapeHtml(c.full_pipeline_reason||"")}</em></div><div><span>Backtest status</span><b>${UI.escapeHtml(backtest)}</b></div><div><span>ML status</span><b>${UI.escapeHtml(mlStatus)}</b><em>${UI.escapeHtml(c.ml_model_used||ml.model||"")}</em></div><div><span>Evidence status</span><b>${UI.escapeHtml(evidence)}</b></div><div><span>Recommendation</span><b>${UI.escapeHtml(c.recommendation||"Unavailable")}</b></div><div><span>Report link</span>${report}</div><button type="button" class="tool-button" data-factory-full-run ${state.strategyFactoryBusy||!f.latest_run?"disabled":""}>Run Full Pipeline</button></section>`}

function factoryCandidatePortfolioPanel(portfolio,candidate){return `<div class="factory-list factory-artifact-list factory-candidate-portfolio-list">${portfolio.map(x=>{const selected=(state.selectedFactoryCandidateId||candidate?.strategy_id)===x.strategy_id;return `<article class="factory-portfolio-row ${selected?"selected":""}" data-factory-select="${UI.escapeHtml(x.strategy_id)}" tabindex="0" role="button" aria-label="View candidate ${UI.escapeHtml(x.strategy_id)}"><header><span>${UI.escapeHtml(x.strategy_id)}</span><b>${UI.escapeHtml(x.status)}</b></header><p>${UI.escapeHtml(x.strategy_thesis||"No thesis recorded.")}</p><em>${UI.escapeHtml(x.updated_at||x.created_at||"Timestamp unavailable")}</em><code>${UI.escapeHtml(x.artifact_path||"candidate_portfolio_draft.json")}</code><footer><button class="tool-button" data-factory-select="${UI.escapeHtml(x.strategy_id)}">View Candidate</button><a class="tool-button" href="#factoryReportViewer">View Report</a><a class="tool-button" href="#factoryCandidateCharts">View Charts</a><button class="tool-button" data-factory-action="allocation" data-strategy-id="${UI.escapeHtml(x.strategy_id)}">Generate Allocation Draft</button><button class="tool-button factory-remove-button" data-factory-action="remove" data-strategy-id="${UI.escapeHtml(x.strategy_id)}">Remove from Candidate Portfolio</button></footer></article>`}).join("")||"<p>No candidate portfolio drafts.</p>"}</div>`}

function factoryAllocationPanel(drafts){return `<div class="factory-list factory-artifact-list">${drafts.map(x=>{const cost=x.transaction_cost_estimate||{},risk=x.risk_impact||{},impact=x.portfolio_impact||{};return `<div><span>${UI.escapeHtml(x.strategy_id)}</span><b>${UI.percent(x.proposed_weight,2)} proposed</b><p>${UI.escapeHtml(x.recommendation||"Review required.")}</p><em>Current active ${x.current_active_count??risk.active_count_before??"N/A"} / after apply ${x.active_count_after_if_applied??risk.active_count_after_if_applied??"N/A"} / cost ${UI.money(cost.estimated_cost)}</em><em>Risk contribution ${UI.percent(risk.risk_contribution,2)} / correlation ${UI.escapeHtml(String(risk.correlation??"Pending"))}</em><em>Candidate does not change active count: ${impact.candidate_does_not_change_active_count?"true":"false"}</em><code>${UI.escapeHtml(x.artifact_path||"allocation_draft.json")}</code></div>`}).join("")||"<p>No allocation drafts generated.</p>"}</div>`}

function factoryPaperPanel(applied,combined){return `<div class="factory-list factory-artifact-list">${applied.map(x=>`<div><span>${UI.escapeHtml(x.strategy_id)}</span><b>${UI.escapeHtml(x.status)}</b><p>${UI.escapeHtml(x.candidate_name||"Applied local paper strategy")}</p><em>${UI.escapeHtml(x.applied_at||"Timestamp unavailable")} / active ${x.active_strategy_count_before??"N/A"} -> ${x.active_strategy_count_after??"N/A"} / ordinary ${x.ordinary_active_count_before??"N/A"} -> ${x.ordinary_active_count_after??"N/A"}</em><em>${UI.escapeHtml(x.combined_recompute_status||"Combined recompute pending")}</em></div>`).join("")||"<p>No Strategy Factory candidate applied to paper portfolio.</p>"}${combined?`<div><span>Combined recompute artifact</span><b>${combined.active_strategy_count_before} -> ${combined.active_strategy_count_after}</b><p>${UI.escapeHtml(combined.strategy_added||"No strategy added")}</p><em>${UI.escapeHtml(combined.triggered_at||"Timestamp unavailable")} / ${UI.escapeHtml(combined.recompute_status)}</em><code>output/strategy_factory/combined_recompute.json</code></div>`:""}</div>`}

function factoryVariantReviewPayload(f){return f.variant_review||{status:"UNAVAILABLE",variant_count:0,variant_cards:[],ranking_summary:[],best_variant:null,candidate_gating:{add_to_candidate_portfolio_enabled:false,override_required:true,reason:"Variant ranking artifacts unavailable."}}}

function factoryCandidatePickerPayload(f){return f.candidate_picker||{schema_version:"strategy_factory_candidate_picker_v1",candidates:[],candidate_count:0,filters:["All","Proceed Eligible","Pending Approval","Active","Blocked","U.S. Stock","Commodity","Unknown / Review Required"]}}

function factoryPickerKey(row){return `${row?.run_id||row?.source_run_id||""}::${row?.variant_id||""}`}

function selectedFactoryPickerCandidate(f){const rows=factoryCandidatePickerPayload(f).candidates||[],selectedKey=`${state.selectedFactoryRunId||""}::${state.selectedFactoryVariantId||""}`;return rows.find(row=>factoryPickerKey(row)===selectedKey)||rows.find(row=>row.variant_id===state.selectedFactoryVariantId)||rows[0]||null}

function factoryThemeFilterGroup(row){const theme=String(row?.theme||"").toLowerCase();if(theme.includes("us_stock"))return "U.S. Stock";if(theme.includes("commodity"))return "Commodity";if(theme.includes("unknown")||theme.includes("review"))return "Unknown / Review Required";return "Unknown / Review Required"}

function factoryCandidateMatchesFilter(row,filter){const status=String(row?.portfolio_state||row?.approval_status||"").toUpperCase(),proceed=String(row?.proceed_status||"").toUpperCase();if(filter==="All")return true;if(filter==="Ready to Proceed"||filter==="Proceed Eligible")return proceed==="PROCEED_ELIGIBLE";if(filter==="Pending Approval")return status==="PENDING_USER_APPROVAL";if(filter==="Active")return ["ACTIVE_UNALLOCATED","ACTIVE_PENDING_REBALANCE"].includes(status);if(filter==="Blocked")return proceed==="PROCEED_BLOCKED";return factoryThemeFilterGroup(row)===filter}

function factoryFilteredPickerCandidates(f){const filter=state.selectedFactoryPickerFilter||"All";return (factoryCandidatePickerPayload(f).candidates||[]).filter(row=>factoryCandidateMatchesFilter(row,filter))}

function selectedFactoryVariant(f){const picked=selectedFactoryPickerCandidate(f);if(picked)return picked;const review=factoryVariantReviewPayload(f),cards=review.variant_cards||[];return cards.find(x=>x.variant_id===state.selectedFactoryVariantId)||cards[0]||null}

function factoryVariantMetricValue(v,type){if(v==null)return "N/A";return type==="percent"?UI.percent(v,2):type==="ratio"?UI.displayNumber(v,{maximumFractionDigits:3}):UI.displayNumber(v,{maximumFractionDigits:0})}

function factoryVariantRankingPanel(f){const review=factoryVariantReviewPayload(f),best=review.best_variant||{},gating=review.candidate_gating||{},report=review.ranking_report_url?`<a class="tool-button" href="${UI.escapeHtml(review.ranking_report_url)}" target="_blank" rel="noreferrer">Open Ranking Report</a>`:`<span class="factory-artifact-note">Ranking report unavailable</span>`,candidateEnabled=!!gating.add_to_candidate_portfolio_enabled;return `<section class="factory-data-status-panel factory-variant-ranking-panel"><div><span>Variant count</span><b>${UI.escapeHtml(String(review.variant_count||0))}</b><em>${UI.escapeHtml(review.status||"UNAVAILABLE")}</em></div><div><span>Best variant</span><b>${UI.escapeHtml(best.variant_name||best.variant_id||"Unavailable")}</b><em>${UI.escapeHtml(best.variant_id||"")}</em></div><div><span>Evidence score</span><b>${factoryVariantMetricValue(best.evidence_score,"ratio")}</b><em>Composite evidence, not Sharpe-only</em></div><div><span>Recommendation</span><b>${UI.escapeHtml(best.final_recommendation||"Unavailable")}</b><em>${UI.escapeHtml(best.reason||"")}</em></div><div><span>candidate_allowed</span><b>${UI.escapeHtml(String(!!best.candidate_allowed))}</b><em>${UI.escapeHtml(gating.reason||"")}</em></div><div><span>Ranking report</span>${report}</div><button type="button" class="tool-button factory-disabled" disabled title="${UI.escapeHtml(gating.reason||"Explicit override required")}">Add to Candidate Portfolio disabled</button><em class="factory-variant-warning">${UI.escapeHtml(candidateEnabled?"Explicit governance override required before any admission.":"All current variants are blocked from casual Candidate admission.")}</em></section>`}

function factoryVariantRows(cards){return (cards||[]).map(v=>{const m=v.metrics||{},ml=v.ml_diagnostics||{},r=v.robustness||{},d=v.decision||{},selected=(state.selectedFactoryVariantId||"")===v.variant_id;return `<tr class="${selected?"selected":""}" data-factory-variant-id="${UI.escapeHtml(v.variant_id)}"><td>${UI.escapeHtml(String(v.rank??"N/A"))}</td><td><strong>${UI.escapeHtml(v.variant_name||v.variant_id)}</strong><small>${UI.escapeHtml(v.variant_id)}</small></td><td>${factoryVariantMetricValue(m.sharpe,"ratio")}</td><td>${factoryVariantMetricValue(m.annual_return,"percent")}</td><td>${factoryVariantMetricValue(m.max_drawdown,"percent")}</td><td>${UI.escapeHtml(ml.summary||ml.status||"Unavailable")}</td><td>${UI.escapeHtml(r.overall||r.status||"Unavailable")}</td><td>${UI.escapeHtml(d.recommendation||"Unavailable")}</td><td><button class="tool-button" type="button" data-factory-variant-id="${UI.escapeHtml(v.variant_id)}">View Evidence</button></td></tr>`}).join("")||'<tr><td colspan="9">No variant ranking artifacts available.</td></tr>'}

function factoryVariantTable(f){const cards=factoryVariantReviewPayload(f).variant_cards||[];return `<div class="work-table-wrap factory-variant-table-wrap"><table class="work-table factory-variant-table"><thead><tr><th>Rank</th><th>Variant</th><th>Sharpe</th><th>Annual return</th><th>Max drawdown</th><th>ML summary</th><th>Robustness</th><th>Recommendation</th><th>Evidence</th></tr></thead><tbody>${factoryVariantRows(cards)}</tbody></table></div>`}

function factoryVariantDetail(f){const v=selectedFactoryVariant(f);if(!v)return `<div class="na-block"><strong>No selected variant</strong><span>Run Gate 3B and Gate 4 artifacts before reviewing variants.</span></div>`;const m=v.metrics||{},ml=v.ml_diagnostics||{},r=v.robustness||{},d=v.decision||{},ranking=v.ranking||{},evidence=v.evidence_report_url?`<a class="tool-button" href="${UI.escapeHtml(v.evidence_report_url)}" target="_blank" rel="noreferrer">Open Evidence Report</a>`:`<span class="factory-artifact-note">Evidence report unavailable</span>`;return `<article class="factory-variant-detail"><header><div><strong>${UI.escapeHtml(v.variant_name||v.variant_id)}</strong><span>${UI.escapeHtml(v.variant_id)} / Rank ${UI.escapeHtml(String(v.rank??"N/A"))} / ${UI.escapeHtml(d.recommendation||"Unavailable")}</span></div><button class="tool-button factory-disabled" disabled title="${UI.escapeHtml(d.reason||"Candidate not allowed")}">Candidate admission disabled</button></header><div class="factory-detail-grid readable"><div><span>Thesis</span><b>${UI.escapeHtml(v.thesis||"Unavailable")}</b></div><div><span>Signal formula</span><b>${UI.escapeHtml(v.signal_formula||"Unavailable")}</b></div><div><span>Universe/proxy</span><b>${UI.escapeHtml((v.universe_or_proxy||[]).join(", ")||"Unavailable")}</b></div><div><span>Benchmark</span><b>${UI.escapeHtml(v.benchmark||"Unavailable")}</b></div><div><span>Features</span><b>${UI.escapeHtml((v.features||[]).join(", ")||"Unavailable")}</b></div><div><span>Evidence score</span><b>${factoryVariantMetricValue(ranking.evidence_score,"ratio")}</b></div><div><span>Sharpe</span><b>${factoryVariantMetricValue(m.sharpe,"ratio")}</b></div><div><span>Annual return</span><b>${factoryVariantMetricValue(m.annual_return,"percent")}</b></div><div><span>Max drawdown</span><b>${factoryVariantMetricValue(m.max_drawdown,"percent")}</b></div><div><span>ML diagnostics</span><b>${UI.escapeHtml(ml.summary||"Unavailable")}</b></div><div><span>Robustness summary</span><b>${UI.escapeHtml([r.overall,r.cost_sensitivity,r.lookback_sensitivity,r.benchmark_status].filter(Boolean).join(" / ")||"Unavailable")}</b></div><div><span>Decision reason</span><b>${UI.escapeHtml(d.reason||ranking.reason||"Unavailable")}</b></div><div><span>candidate_allowed</span><b>${UI.escapeHtml(String(!!d.candidate_allowed))}</b></div><div><span>Evidence report</span>${evidence}</div></div></article>`}

function factoryVariantReviewPanel(f){const review=factoryVariantReviewPayload(f);return `${factoryVariantRankingPanel(f)}${factoryVariantTable(f)}${factoryVariantDetail(f)}${review.ranking_report_path?`<p class="factory-artifact-note">Ranking artifact: ${UI.escapeHtml(review.ranking_report_path)}</p>`:""}`}

function factoryObjectRows(obj){return Object.entries(obj||{}).map(([k,v])=>`<div><span>${UI.escapeHtml(k)}</span><b>${UI.escapeHtml(Array.isArray(v)?v.map(x=>typeof x==="object"?JSON.stringify(x):String(x)).join(" | "):typeof v==="object"?JSON.stringify(v):String(v??"Unavailable"))}</b></div>`).join("")||"<div><span>Status</span><b>Unavailable</b></div>"}

function factoryCandidateDetailPanel(candidate,portfolio=[],drafts=[],applied=[]){if(!candidate||!portfolio.some(x=>x.strategy_id===candidate.strategy_id))return `<section id="factoryCandidateDetail" class="panel span-12 factory-candidate-detail"><div class="na-block"><strong>Candidate Detail</strong><span>Select a candidate from Candidate Portfolio List after Add to Candidate Portfolio.</span></div></section>`;const wf=candidate.portfolio_workflow||{},portfolioDraft=portfolio.find(x=>x.strategy_id===candidate.strategy_id)||{},allocation=drafts.find(x=>x.strategy_id===candidate.strategy_id)||{},paper=applied.find(x=>x.strategy_id===candidate.strategy_id)||{},evidence=candidate.source_evidence||{},materials=candidate.source_materials||[],metrics=candidate.backtest_metrics||{},ml=candidate.ml_diagnostics||{},report=candidate.report_sections||{};return `<section id="factoryCandidateDetail" class="panel span-12 factory-candidate-detail">${UI.SectionHeader({title:"Candidate Detail",meta:"In-dashboard review panel"})}<article><header><div><strong>${UI.escapeHtml(candidate.name||candidate.strategy_id)}</strong><span>${UI.escapeHtml(candidate.strategy_id)} / ${UI.escapeHtml(wf.candidate_status||candidate.decision_status||"Status unavailable")} / ${UI.escapeHtml(candidate.pipeline_stage||"Pipeline unavailable")}</span></div>${factoryBadges(candidate.safety_labels)}</header><div class="factory-detail-grid"><div><span>Strategy name</span><b>${UI.escapeHtml(candidate.name||"Unavailable")}</b></div><div><span>Status</span><b>${UI.escapeHtml(wf.candidate_status||candidate.decision_status||"Unavailable")}</b></div><div><span>Current pipeline stage</span><b>${UI.escapeHtml(candidate.pipeline_stage||"Unavailable")}</b></div><div><span>Universe</span><b>${UI.escapeHtml(candidate.universe||"Unavailable")}</b></div><div><span>Benchmark</span><b>${UI.escapeHtml(candidate.benchmark||"Unavailable")}</b></div><div><span>Rebalance frequency</span><b>${UI.escapeHtml(candidate.rebalance_frequency||"Unavailable")}</b></div><div><span>Holding period</span><b>${UI.escapeHtml(candidate.holding_period||"Unavailable")}</b></div><div><span>Transaction cost assumption</span><b>${UI.escapeHtml(candidate.cost_assumption||"Unavailable")}</b></div><div><span>Allocation draft status</span><b>${allocation.status?UI.escapeHtml(allocation.status):"No allocation draft"}</b></div><div><span>Paper apply status</span><b>${paper.status?UI.escapeHtml(paper.status):"Not applied"}</b></div><div><span>Candidate portfolio draft artifact path</span><b>${UI.escapeHtml(portfolioDraft.artifact_path||candidate.candidate_portfolio_draft_path||"Unavailable")}</b></div><div><span>Allocation draft artifact path</span><b>${UI.escapeHtml(allocation.artifact_path||"No allocation draft")}</b></div></div><section><h3>Thesis</h3><p>${UI.escapeHtml(candidate.strategy_thesis||"Unavailable")}</p><h3>Signal Formula</h3><p>${UI.escapeHtml(candidate.signal_formula||"Unavailable")}</p></section><section><h3>Source Materials</h3><ul>${materials.map(x=>`<li><b>${UI.escapeHtml(x.filename||"Material")}</b> ${UI.escapeHtml(x.extraction_status||"Status unavailable")} / ${UI.escapeHtml(x.contribution||"No contribution recorded.")}</li>`).join("")||"<li>No source materials recorded.</li>"}</ul><h3>Source Evidence</h3><div class="factory-detail-grid">${factoryObjectRows(evidence)}</div></section><section><h3>Research Card</h3><div class="factory-detail-grid">${factoryObjectRows(candidate.research_card)}</div><h3>Test Spec</h3><div class="factory-detail-grid">${factoryObjectRows(candidate.test_spec)}</div></section><section><h3>Backtest Metrics</h3><div class="factory-report-metrics">${Object.entries(metrics).map(([k,v])=>`<span><b>${UI.escapeHtml(k)}</b>${UI.escapeHtml(String(v))}</span>`).join("")||"<span><b>Backtest</b>Pending BACKTEST_RUN</span>"}</div><h3 id="factoryCandidateCharts">Embedded Charts</h3>${factoryChartGrid(candidate)}</section><section><h3>ML Diagnostics</h3><p>${UI.escapeHtml(candidate.ml_result_summary||"Pending ML_DIAGNOSTICS_RUN")}</p><div class="factory-detail-grid">${factoryObjectRows({model:ml.model,auc:ml.auc,precision:ml.precision,recall:ml.recall,limitations:ml.limitations})}</div><h3>Feature Importance</h3><ul>${(ml.feature_importance||[]).map(x=>`<li>${UI.escapeHtml(x.feature)}: ${UI.escapeHtml(String(x.importance))}</li>`).join("")||"<li>Pending ML_DIAGNOSTICS_RUN</li>"}</ul></section><section><h3>Evidence Report Summary</h3><p>${UI.escapeHtml(report["Executive Summary"]||"Pending EVIDENCE_REPORT_CREATED")}</p><p>${UI.escapeHtml(report["Limitations"]||"Prototype-only; no institutional validation.")}</p></section></article></section>`}

function strategyFactoryPage(){const f=factoryPayload(),candidate=f.latest_candidate,candidates=candidate?[candidate]:[],materials=f.intake?.materials||[],counts=f.backend_counts||{},portfolio=f.candidate_portfolio||[],drafts=f.allocation_drafts||[],applied=f.applied_paper_strategies||[];return `<main class="main-stage"><div class="page workflow-page strategy-factory-page">${pageTitle("Strategy Factory","AI strategy discovery plugin: prototype research to user-confirmed paper portfolio draft flow")}${secondaryStageNote("Strategy Factory safety boundary",[["PROTOTYPE_ONLY","Generated candidates are research prototypes, not live or institutionally validated strategies."],["PAPER_ONLY","Add and allocation draft actions create local draft artifacts only."],["USER_CONFIRMATION","Apply to Paper Portfolio requires explicit confirmation and records a backend artifact; brokerage execution remains disabled."]])}${factoryWorkflowStrip(f)}${factoryStatusBanner(f)}<section class="metric-grid strategy-factory-kpis">${UI.MetricCard({label:"Candidates",value:String(f.candidate_count||candidates.length),detail:"latest local factory run",tone:"info"})}${UI.MetricCard({label:"Candidate portfolio",value:String(portfolio.length),detail:"draft artifacts",tone:"pending"})}${UI.MetricCard({label:"Allocation drafts",value:String(drafts.length),detail:"review required",tone:"pending"})}${UI.MetricCard({label:"Applied paper",value:String(applied.length),detail:"no live trading",tone:"warning"})}${UI.MetricCard({label:"Active count",value:String(counts.current_active_strategy_count??"N/A"),detail:"backend state, not hardcoded",tone:"positive"})}${UI.MetricCard({label:"Combined recompute",value:counts.combined_strategy_recomputed?"Represented":"Pending",detail:"artifact only",tone:counts.combined_strategy_recomputed?"positive":"warning"})}</section><div class="workflow-grid"><section class="panel span-4 factory-upload-panel">${UI.SectionHeader({title:"Upload research materials",meta:"PDF, txt, md, csv, xlsx accepted; unsupported extraction is labeled"})}<form id="strategyFactoryUploadForm" class="factory-upload-form"><input id="strategyFactoryFiles" type="file" multiple accept=".pdf,.txt,.md,.csv,.xlsx"><button class="tool-button" type="submit" ${state.strategyFactoryBusy?"disabled":""}>Upload</button><button class="tool-button" type="button" id="strategyFactoryRun" ${state.strategyFactoryBusy?"disabled":""}>Run Strategy Factory</button></form><div class="factory-safety">${factoryBadges(f.safety_labels)}</div></section><section class="panel span-8">${UI.SectionHeader({title:"Intake queue / recent materials",meta:`${materials.length} material(s)`})}${table(["Filename","Type","Uploaded","Extraction","Chars","Stored"],materials.slice().reverse().map(x=>`<tr><td>${UI.escapeHtml(x.filename)}</td><td>${UI.escapeHtml(x.file_type)}</td><td>${UI.escapeHtml(x.uploaded_at)}</td><td>${UI.escapeHtml(x.extraction_status)}</td><td>${x.extracted_character_count??0}</td><td>${UI.escapeHtml((x.stored_path||"").split(/[\\\\/]/).slice(-1)[0])}</td></tr>`).join("")||'<tr><td colspan="6">No intake materials uploaded.</td></tr>',"factory-intake-table")}</section>${factoryMaterialAnalysis(materials)}<section class="panel span-7">${UI.SectionHeader({title:"Latest AI Strategy Candidates",meta:"Prototype candidate detail panel"})}<div class="factory-candidate-list">${factoryCandidateCards(candidates,portfolio,drafts)}</div></section><section class="panel span-4">${UI.SectionHeader({title:"Candidate Portfolio list",meta:"Draft flow"})}${factoryCandidatePortfolioPanel(portfolio,candidate)}${UI.SectionHeader({title:"Monitor-ready summary",meta:"Paper only"})}<div class="factory-list">${candidate?Object.entries(candidate.monitor_ready_summary||{}).map(([k,v])=>`<div><span>${UI.escapeHtml(k)}</span><b>${UI.escapeHtml(String(v))}</b></div>`).join(""):"<p>No monitor summary generated.</p>"}</div></section><section class="panel span-4">${UI.SectionHeader({title:"Allocation draft / risk impact",meta:"No automatic application"})}${factoryAllocationPanel(drafts)}</section><section class="panel span-4">${UI.SectionHeader({title:"Paper application state",meta:"Combined recompute artifact"})}${factoryPaperPanel(applied,f.combined_recompute)}</section>${factoryCandidateDetailPanel(candidate,portfolio,drafts,applied)}<div id="factoryReportViewer" class="span-12">${factoryReportViewer(candidate)}</div></div></div></main>`}

async function refreshStrategyFactory(){try{const r=await fetch(`/api/strategy-factory?ts=${Date.now()}`,{cache:"no-store",headers:{"Cache-Control":"no-store"}});state.strategyFactory=await r.json()}catch(e){state.strategyFactory={ok:false,error:e.message,intake:{materials:[]},candidate_portfolio:[],allocation_drafts:[],applied_paper_strategies:[],backend_counts:{},safety_labels:["PROTOTYPE_ONLY","NOT_LIVE_TRADING","NOT_INSTITUTIONAL_VALIDATION","USER_CONFIRMATION_REQUIRED"]}}}

async function refreshStrategyFactoryState(){await refreshStrategyFactory();if(state.contract)enrich(state.contract)}

async function strategyFactoryApi(path,options={}){const r=await fetch(path,{cache:"no-store",...options}),text=await r.text();let result={};try{result=text?JSON.parse(text):{}}catch(e){result={ok:r.ok,report:text}}if(!r.ok)throw new Error(result.error||result.message||`Strategy Factory request failed (${r.status})`);state.strategyFactory=result.factory||result;if(result.message)state.strategyFactoryStatusMessage=result.message;return result}

function legacyBindStrategyFactoryControls(){}

function factorySection(title,meta,body,extra=""){return `<section class="panel factory-section ${extra}">${UI.SectionHeader({title,meta})}${body}</section>`}

function factoryStageState(stage){return (factoryPayload().stage_statuses||[]).find(x=>x.stage===stage)||{stage,status:"NOT_STARTED",reason:"Stage has not started.",required_artifact:`${stage.toLowerCase()}.json`,last_updated:null,action:"Run Strategy Factory stage."}}

function factoryStageLabel(stage){const s=factoryStageState(stage);return `${s.status}: ${s.reason}`}

function factoryStageStatusPanel(f){const rows=f.stage_statuses||[],currentRun=!!f.latest_run;return `<div class="factory-stage-status-panel">${rows.map(s=>{const runnerStage=["BACKTEST_RUN","ROBUSTNESS_RUN","ML_DIAGNOSTICS_RUN","EVIDENCE_REPORT_CREATED"].includes(s.stage)&&currentRun,disabled=s.status==="COMPLETED"&&!runnerStage,label=runnerStage?"Run Current Backtest / ML / Evidence":s.action||"Run Strategy Factory stage.";return `<article><header><strong>${UI.escapeHtml(s.stage)}</strong><b class="factory-state-${UI.escapeHtml(String(s.status).toLowerCase())}">${UI.escapeHtml(s.status)}</b></header><p>${UI.escapeHtml(s.reason)}</p><dl><dt>Required artifact</dt><dd>${UI.escapeHtml(s.required_artifact||"Unavailable")}</dd><dt>Last updated</dt><dd>${UI.escapeHtml(s.last_updated||"timestamp unavailable")}</dd></dl><button class="tool-button ${disabled?"factory-disabled":""}" data-factory-stage-run="${UI.escapeHtml(s.stage)}" ${disabled?"disabled":""}>${UI.escapeHtml(label)}</button></article>`}).join("")}</div>`}

function factoryViewportSnapshot(){const containers=[".main-stage",".factory-material-window"].map(selector=>{const el=document.querySelector(selector);return el?{selector,top:el.scrollTop||0,left:el.scrollLeft||0}:null}).filter(Boolean);return {x:window.scrollX||0,y:window.scrollY||0,docTop:document.scrollingElement?.scrollTop||0,docLeft:document.scrollingElement?.scrollLeft||0,hash:window.location.hash||"",containers}}

function factoryRestoreViewport(s){if(!s)return;if(window.location.hash!==s.hash)history.replaceState(null,"",`${window.location.pathname}${window.location.search}${s.hash}`);const restore=()=>{document.scrollingElement?.scrollTo(s.docLeft||0,s.docTop||0);window.scrollTo(s.x||0,s.y||0);(s.containers||[]).forEach(row=>{const el=document.querySelector(row.selector);if(el){el.scrollTop=row.top||0;el.scrollLeft=row.left||0}})};restore();requestAnimationFrame(restore);setTimeout(restore,0)}

function factoryRenderStable(){const s=factoryViewportSnapshot();render();factoryRestoreViewport(s)}

function factorySetCandidate(id,tab="Overview"){state.selectedFactoryCandidateId=id||state.strategyFactory?.latest_candidate?.strategy_id||"";state.selectedFactoryDetailTab=tab;state.strategyFactoryStatusMessage=`Viewing ${state.selectedFactoryDetailTab} for ${state.selectedFactoryCandidateId}.`}

function bindStrategyFactoryControls(){document.getElementById("strategyFactoryUploadForm")?.addEventListener("submit",async e=>{e.preventDefault();e.stopPropagation();const files=document.getElementById("strategyFactoryFiles")?.files;if(!files?.length){toast("Choose at least one research material","warning");return}const body=new FormData();Array.from(files).forEach(file=>body.append("files",file));try{state.strategyFactoryBusy=true;factoryRenderStable();const result=await strategyFactoryApi("/api/strategy-factory/upload",{method:"POST",body});state.factoryMaterialLibraryExpanded=true;state.strategyFactoryStatusMessage=`Uploaded ${result.saved?.length||files.length} material(s) to Material Library / Inbox.`;toast("Research material uploaded","positive")}catch(err){toast(err.message,"negative")}finally{state.strategyFactoryBusy=false;await refreshStrategyFactory();factoryRenderStable()}});document.getElementById("strategyFactoryRun")?.addEventListener("click",async e=>{e.preventDefault();e.stopPropagation();const selected=[...(state.selectedFactoryMaterialIds||[])];if(!selected.length){state.strategyFactoryStatusMessage="Select materials for current batch first.";toast("Select materials for current batch first.","warning");factoryRenderStable();return}try{state.strategyFactoryBusy=true;state.strategyFactoryStatusMessage="Running selected batch job...";factoryRenderStable();const result=await strategyFactoryApi("/api/strategy-factory/run-selected-batch",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({selected_material_ids:selected})});state.selectedFactoryCandidateId=result.job?.outputs?.candidate_id||state.selectedFactoryCandidateId;state.selectedFactoryDetailTab="Overview";state.factoryMaterialLibraryExpanded=false;state.strategyFactoryStatusMessage=`Completed selected batch job ${result.job_id||result.job?.job_id||"selected batch"}. selected_material_count=${result.selected_material_count??selected.length}.`;toast("Completed selected batch job","positive")}catch(err){toast(err.message,"negative")}finally{state.strategyFactoryBusy=false;await refreshStrategyFactory();factoryRenderStable()}});document.querySelectorAll("[data-factory-material-id]").forEach(el=>{el.addEventListener("click",e=>e.stopPropagation());el.addEventListener("change",e=>{e.stopPropagation();state.factoryMaterialLibraryExpanded=true;const id=e.target.dataset.factoryMaterialId,current=new Set(state.selectedFactoryMaterialIds||[]);if(e.target.checked)current.add(id);else current.delete(id);state.selectedFactoryMaterialIds=[...current];factoryRenderStable()})});document.querySelectorAll("[data-factory-material-control]").forEach(b=>b.addEventListener("click",e=>{e.preventDefault();e.stopPropagation();state.factoryMaterialLibraryExpanded=true;const action=b.dataset.factoryMaterialControl,visible=(factoryPayload().intake?.materials||[]).map(x=>String(x.material_id||"")).filter(Boolean);if(action==="select-visible")state.selectedFactoryMaterialIds=[...new Set([...(state.selectedFactoryMaterialIds||[]),...visible])];if(action==="clear")state.selectedFactoryMaterialIds=[];if(action==="remove"){const remove=new Set(visible);state.selectedFactoryMaterialIds=(state.selectedFactoryMaterialIds||[]).filter(id=>!remove.has(id))}if(action==="toggle-window")state.factoryMaterialWindowExpanded=!state.factoryMaterialWindowExpanded;factoryRenderStable()}));document.querySelectorAll("[data-factory-select]").forEach(el=>el.addEventListener("click",e=>{if(e.target.closest("[data-factory-action],[data-factory-view],[data-factory-detail-tab],[data-factory-material-control],input,button,a"))return;e.preventDefault();e.stopPropagation();factorySetCandidate(el.dataset.factorySelect,"Overview");factoryRenderStable()}));document.querySelectorAll("[data-factory-select]").forEach(el=>el.addEventListener("keydown",e=>{if(e.key!=="Enter"&&e.key!==" ")return;e.preventDefault();e.stopPropagation();factorySetCandidate(el.dataset.factorySelect,"Overview");factoryRenderStable()}));document.querySelectorAll("[data-factory-action]").forEach(b=>b.addEventListener("click",async e=>{e.preventDefault();e.stopPropagation();const id=b.dataset.strategyId,action=b.dataset.factoryAction,path=action==="add"?`/api/strategy-factory/candidates/${id}/add-to-candidate-portfolio`:action==="allocation"?`/api/strategy-factory/candidates/${id}/generate-allocation-draft`:action==="remove"?`/api/strategy-factory/candidates/${id}/remove-from-candidate-portfolio`:`/api/strategy-factory/candidates/${id}/apply-to-paper-portfolio`,body=action==="apply"?{confirmed:confirm("Apply this prototype to Paper Portfolio only? This does not enable live trading.")}:{};if(action==="apply"&&!body.confirmed){state.strategyFactoryStatusMessage="Paper apply cancelled. Candidate remains outside active paper portfolio.";factoryRenderStable();return}if(action==="remove"&&!confirm("Remove this candidate from the Candidate Portfolio draft? Paper-applied candidates cannot be removed here."))return;try{state.strategyFactoryBusy=true;factoryRenderStable();const result=await strategyFactoryApi(path,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(body)});if(action==="add")factorySetCandidate(id,"Overview");if(action==="remove")state.selectedFactoryCandidateId="";state.strategyFactoryStatusMessage=result.message||(action==="add"?"Candidate Portfolio draft created. Paper Portfolio unchanged.":action==="allocation"?"Allocation draft and risk impact created. Apply still requires confirmation.":action==="remove"?"Candidate removed from Candidate Portfolio draft.":"Paper Portfolio state updated and combined recompute artifact generated.");toast(action==="apply"?"Applied to Paper Portfolio artifact":action==="remove"?"Candidate Portfolio draft removed":"Strategy Factory draft updated","positive")}catch(err){toast(err.message,"negative")}finally{state.strategyFactoryBusy=false;await refreshStrategyFactory();factoryRenderStable()}}))}

function factoryWorkflowStrip(f){const counts=f.stage_counts||{},stages=f.workflow_stages||[];return `<section class="factory-workflow-strip factory-section">${stages.map(s=>{const detail=s.detail_key?counts[s.detail_key]??0:null,detailText=s.detail_key?`${UI.escapeHtml(s.detail_key.replaceAll("_"," "))}: ${detail}`:"";return `<div><span>${UI.escapeHtml(s.stage)}</span><b>${counts[s.count_key]??0}</b>${detailText?`<em>${detailText}</em>`:""}</div>`}).join("")}</section>`}

function factoryChartGrid(c){const charts=c?.chart_previews||[];if(!charts.length)return `<div class="factory-chart-empty">Charts unavailable until BACKTEST_RUN artifact exists.</div>`;return `<div class="factory-chart-grid readable">${charts.map(x=>`<figure><figcaption>${UI.escapeHtml(x.title)}</figcaption><img src="${x.path}" alt="${UI.escapeHtml(x.title)}"></figure>`).join("")}</div>`}

function factoryMaterialAnalysis(materials){const selected=(materials||[]).slice().reverse()[0];if(!selected)return factorySection("Material Review / Analysis","No selected material",`<div class="na-block"><strong>No material uploaded</strong><span>Upload txt, md, csv, PDF, or xlsx. Unsupported extraction remains explicitly labeled.</span></div>`,"factory-material-review");const a=selected.analysis||{},blocked=selected.extraction_status!=="Extracted"||Number(selected.extracted_character_count||0)===0;return factorySection("Material Review / Analysis",UI.escapeHtml(selected.filename||"Selected material"),`<div class="factory-material-layout"><aside><div><span>Selected filename</span><b>${UI.escapeHtml(selected.filename)}</b></div><div><span>Extraction status</span><b>${UI.escapeHtml(selected.extraction_status)}</b></div><div><span>Extracted characters</span><b>${selected.extracted_character_count??0}</b></div><div><span>Stored artifact</span><b>${UI.escapeHtml(selected.stored_path||"Unavailable")}</b></div></aside><article><h3>${blocked?"Analysis blocked or limited":"Extracted summary"}</h3><p>${UI.escapeHtml(a.document_summary||"No analysis summary available.")}</p><h3>Next action</h3><p>${UI.escapeHtml(blocked?"Use text/markdown/csv material or add a supported extractor before treating uploads as evidence. Prototype seed remains not paper-derived.":a.testability||"Review extracted context before candidate generation.")}</p><div class="factory-analysis-grid readable"><div><strong>Key themes</strong><ul>${factoryListItems(a.key_themes)}</ul></div><div><strong>Strategy concepts</strong><ul>${factoryListItems(a.strategy_concepts)}</ul></div><div><strong>Blockers</strong><ul>${factoryListItems(a.implementation_blockers)}</ul></div></div></article></div>`,"factory-material-review") }

function factoryIsPrototypeCandidate(c){return String(c?.strategy_id||"") === "AI_SECTOR_MOMENTUM_RISK_FILTER_V0" || String(c?.source_derivation_status||"").includes("PROTOTYPE_SEED_NOT_DERIVED_FROM_UPLOADS")}

function factoryIsCurrentRunCandidate(c){return String(c?.source_derivation_status||"").includes("SELECTED_BATCH_ARTIFACT_LINEAGE") || String(c?.strategy_id||"").startsWith("RUN_SCOPED_CANDIDATE_")}

function factoryCurrentRunCandidates(candidates){return (candidates||[]).filter(factoryIsCurrentRunCandidate)}

function factoryRealAlphaCandidates(candidates){return (candidates||[]).filter(c=>!factoryIsPrototypeCandidate(c))}

function factoryHistoricalAlphaCandidates(candidates){return (candidates||[]).filter(c=>!factoryIsPrototypeCandidate(c)&&!factoryIsCurrentRunCandidate(c))}

function factoryPrototypeCandidates(candidates){return (candidates||[]).filter(factoryIsPrototypeCandidate)}

function factoryExtractedIdeasPanel(candidate){const ideas=candidate?.report_sections?.["Extracted Strategy Ideas"]||[],materials=factoryIsPrototypeCandidate(candidate)?[]:(candidate?.source_materials||[]),label=factoryIsPrototypeCandidate(candidate)?"Prototype seed fallback":"Selected real alpha candidate";return factorySection("Extracted Strategy Ideas","Selected candidate source label is shown honestly",`<div class="factory-ideas-grid"><article><h3>${label}</h3><p><b>${UI.escapeHtml(candidate?.strategy_id||"No candidate yet")}</b></p><p>${UI.escapeHtml(candidate?.source_derivation_status||"Source status unavailable")}</p></article><article><h3>Extracted ideas from materials</h3><ul>${Array.isArray(ideas)&&ideas.length?ideas.map(x=>`<li>${UI.escapeHtml(x)}</li>`).join(""):"<li>No uploaded-material-derived ideas available for the selected candidate.</li>"}</ul></article><article><h3>Candidate source material contribution</h3><ul>${materials.map(x=>`<li><b>${UI.escapeHtml(x.filename||"Material")}</b>: ${UI.escapeHtml(x.contribution||"Candidate-specific context artifact")}</li>`).join("")||"<li>No candidate-specific source materials recorded.</li>"}</ul></article></div>`)}

function factoryCandidateCards(candidates,portfolio=[],drafts=[]){if(!candidates.length)return `<div class="na-block"><strong>No candidate generated</strong><span>Run Strategy Factory through extraction, analysis, and candidate idea stages before a candidate appears.</span></div>`;return candidates.map(c=>{const m=c.backtest_metrics||{},wf=c.portfolio_workflow||{},hasBacktest=factoryStageDone(c,"BACKTEST_RUN"),hasMl=factoryStageDone(c,"ML_DIAGNOSTICS_RUN"),addEnabled=!!wf.add_enabled,allocEnabled=!!wf.allocation_enabled,applyEnabled=!!wf.apply_enabled,added=!!wf.in_candidate_portfolio,allocated=!!wf.allocation_draft_exists,applied=!!wf.applied_to_paper,addText=applied?"Applied to Paper Portfolio":added?"Added to Candidate Portfolio":addEnabled?"Add to Candidate Portfolio":"Requires Evidence Report",allocText=applied?"Allocation Used for Apply":allocated?"Allocation Draft Created":allocEnabled?"Generate Allocation Draft":"Requires Candidate Portfolio",applyText=applied?"Applied to Paper Portfolio":applyEnabled?"Apply to Paper Portfolio":"Requires Allocation Draft + Confirmation";return `<article class="factory-candidate-card readable"><header><div><strong>${UI.escapeHtml(c.name||c.strategy_id)}</strong><span>${UI.escapeHtml(c.strategy_id)} / ${UI.escapeHtml(c.source_derivation_status||"Source status unavailable")}</span></div>${factoryBadges(c.safety_labels)}</header><div class="factory-candidate-body"><div><h3>Thesis</h3><p>${UI.escapeHtml(c.strategy_thesis||"Research thesis unavailable.")}</p><h3>Pipeline</h3><p>${UI.escapeHtml(c.pipeline_stage||"PIPELINE")} / ${UI.escapeHtml(wf.candidate_status||"PIPELINE_IN_PROGRESS")}</p></div><div class="factory-metric-strip readable"><div><span>Sharpe</span><b>${hasBacktest?factoryMetric(m.sharpe,"ratio"):"Pending Backtest"}</b></div><div><span>Annual return</span><b>${hasBacktest?factoryMetric(m.annual_return,"percent"):"Pending Backtest"}</b></div><div><span>Max drawdown</span><b>${hasBacktest?factoryMetric(m.max_drawdown,"percent"):"Pending Backtest"}</b></div><div><span>ML</span><b>${hasMl?"Diagnostics ready":"Pending ML"}</b></div></div></div><div class="factory-actions"><a class="tool-button" href="#factoryCandidateDetail">View Candidate</a><a class="tool-button" href="#factoryReportViewer">View Report</a><button class="tool-button ${addEnabled?"":"factory-disabled"}" data-factory-action="add" data-strategy-id="${c.strategy_id}" ${addEnabled?"":"disabled"}>${addText}</button><button class="tool-button ${allocEnabled?"":"factory-disabled"}" data-factory-action="allocation" data-strategy-id="${c.strategy_id}" ${allocEnabled?"":"disabled"}>${allocText}</button><button class="tool-button ${applyEnabled?"approve-tile":"factory-disabled"}" data-factory-action="apply" data-strategy-id="${c.strategy_id}" ${applyEnabled?"":"disabled"}>${applyText}</button></div></article>`}).join("")}

function factoryCandidatePortfolioPanel(portfolio,candidate){return `<div class="factory-candidate-portfolio-list">${portfolio.map(x=>{const selected=(state.selectedFactoryCandidateId||candidate?.strategy_id)===x.strategy_id,hasBacktest=!!candidate?.backtest_metrics;return `<article class="factory-portfolio-row readable ${selected?"selected":""}" data-factory-select="${UI.escapeHtml(x.strategy_id)}" tabindex="0" role="button" aria-label="View candidate ${UI.escapeHtml(x.strategy_id)}"><header><div><strong>${UI.escapeHtml(x.candidate_name||x.strategy_id)}</strong><span>${UI.escapeHtml(x.strategy_id)} / ${UI.escapeHtml(x.status)}</span></div><b>${UI.escapeHtml(candidate?.pipeline_stage||"Pipeline")}</b></header><p>${UI.escapeHtml(x.strategy_thesis||"No thesis recorded.")}</p><div class="factory-portfolio-metrics"><span>${hasBacktest?`Sharpe ${factoryMetric(candidate.backtest_metrics.sharpe,"ratio")}`:"Pending Backtest"}</span><span>${hasBacktest?`Return ${factoryMetric(candidate.backtest_metrics.annual_return,"percent")}`:"Metrics pending"}</span><span>${UI.escapeHtml(x.updated_at||x.created_at||"Timestamp unavailable")}</span></div><code>${UI.escapeHtml(x.artifact_path||"candidate_portfolio_draft.json")}</code><footer><button class="tool-button" data-factory-select="${UI.escapeHtml(x.strategy_id)}">View Candidate</button><a class="tool-button" href="#factoryReportViewer">View Report</a><a class="tool-button" href="#factoryCandidateCharts">View Charts</a><button class="tool-button" data-factory-action="allocation" data-strategy-id="${UI.escapeHtml(x.strategy_id)}">Generate Allocation Draft</button><button class="tool-button factory-remove-button" data-factory-action="remove" data-strategy-id="${UI.escapeHtml(x.strategy_id)}">Remove from Candidate Portfolio</button></footer></article>`}).join("")||"<p>No candidate portfolio drafts.</p>"}</div>`}

function factoryReadableBlock(title,body){return `<section class="factory-readable-block"><h3>${UI.escapeHtml(title)}</h3>${body}</section>`}

function factoryObjectRows(obj){return Object.entries(obj||{}).map(([k,v])=>`<div><span>${UI.escapeHtml(k)}</span><b>${UI.escapeHtml(Array.isArray(v)?v.map(x=>typeof x==="object"?JSON.stringify(x):String(x)).join(" | "):typeof v==="object"?JSON.stringify(v):String(v??"Unavailable"))}</b></div>`).join("")||"<div><span>Status</span><b>Unavailable</b></div>"}

function factoryCandidateDetailPanel(candidate,portfolio=[],drafts=[],applied=[]){if(!candidate||!portfolio.some(x=>x.strategy_id===candidate.strategy_id))return factorySection("Candidate Detail / Report Viewer","Full-width review opens after Add to Candidate Portfolio",`<div class="na-block"><strong>Candidate Detail</strong><span>Select a candidate from Candidate Portfolio List after Add to Candidate Portfolio.</span></div>`,"factory-candidate-detail");const wf=candidate.portfolio_workflow||{},portfolioDraft=portfolio.find(x=>x.strategy_id===candidate.strategy_id)||{},allocation=drafts.find(x=>x.strategy_id===candidate.strategy_id)||{},paper=applied.find(x=>x.strategy_id===candidate.strategy_id)||{},evidence=candidate.source_evidence||{},materials=candidate.source_materials||[],metrics=candidate.backtest_metrics||{},ml=candidate.ml_diagnostics||{},report=candidate.report_sections||{};return `<section id="factoryCandidateDetail" class="panel factory-section factory-candidate-detail readable">${UI.SectionHeader({title:"Candidate Detail",meta:"Full-width in-dashboard review panel"})}<article><header><div><strong>${UI.escapeHtml(candidate.name||candidate.strategy_id)}</strong><span>Status ${UI.escapeHtml(wf.candidate_status||candidate.decision_status||"Unavailable")} / Stage ${UI.escapeHtml(candidate.pipeline_stage||"Unavailable")} / Source ${UI.escapeHtml(candidate.source_derivation_status||"Unavailable")}</span></div>${factoryBadges(candidate.safety_labels)}</header>${factoryReadableBlock("Research Card",`<div class="factory-detail-grid readable">${factoryObjectRows(candidate.research_card)}</div>`)}${factoryReadableBlock("Test Spec",`<div class="factory-detail-grid readable">${factoryObjectRows(candidate.test_spec)}</div>`)}${factoryReadableBlock("Source Evidence",`<ul>${materials.map(x=>`<li><b>${UI.escapeHtml(x.filename||"Material")}</b> ${UI.escapeHtml(x.extraction_status||"Status unavailable")} / ${UI.escapeHtml(x.contribution||"No contribution recorded.")}</li>`).join("")||"<li>No source materials recorded.</li>"}</ul><div class="factory-detail-grid readable">${factoryObjectRows(evidence)}</div>`)}${factoryReadableBlock("Backtest Results",`<p>${Object.keys(metrics).length?"Prototype metrics are available after BACKTEST_RUN.":"Sharpe / return / drawdown unavailable until BACKTEST_RUN artifact exists."}</p><div class="factory-report-metrics readable">${Object.entries(metrics).map(([k,v])=>`<span><b>${UI.escapeHtml(k)}</b>${UI.escapeHtml(String(v))}</span>`).join("")||"<span><b>Backtest</b>Pending BACKTEST_RUN</span>"}</div>`)}${factoryReadableBlock("Embedded Charts",`<div id="factoryCandidateCharts">${factoryChartGrid(candidate)}</div>`)}${factoryReadableBlock("ML Diagnostics",`<p>${UI.escapeHtml(candidate.ml_result_summary||"Pending ML_DIAGNOSTICS_RUN")}</p><div class="factory-detail-grid readable">${factoryObjectRows({model:ml.model,auc:ml.auc,precision:ml.precision,recall:ml.recall,limitations:ml.limitations})}</div><h4>Feature Importance</h4><ul>${(ml.feature_importance||[]).map(x=>`<li>${UI.escapeHtml(x.feature)}: ${UI.escapeHtml(String(x.importance))}</li>`).join("")||"<li>Pending ML_DIAGNOSTICS_RUN</li>"}</ul>`)}${factoryReadableBlock("Portfolio Workflow State",`<div class="factory-detail-grid readable"><div><span>Candidate portfolio draft</span><b>${UI.escapeHtml(portfolioDraft.artifact_path||candidate.candidate_portfolio_draft_path||"Unavailable")}</b></div><div><span>Allocation draft status</span><b>${allocation.status?UI.escapeHtml(allocation.status):"No allocation draft"}</b></div><div><span>Paper apply status</span><b>${paper.status?UI.escapeHtml(paper.status):"Not applied"}</b></div><div><span>Workflow status</span><b>${UI.escapeHtml(wf.candidate_status||"Unavailable")}</b></div></div>`)}${factoryReadableBlock("Evidence Report Summary",`<p>${UI.escapeHtml(report["Executive Summary"]||"Pending EVIDENCE_REPORT_CREATED")}</p><p>${UI.escapeHtml(report["Limitations"]||"Prototype-only; no institutional validation.")}</p>`)}</article></section>`}

function factoryReportViewer(c){if(!c)return "";const r=c.report_sections||{},materialRows=Array.isArray(r["Uploaded Materials Reviewed"])?r["Uploaded Materials Reviewed"].map(x=>`<li><b>${UI.escapeHtml(x.filename||"Material")}</b> ${UI.escapeHtml(x.contribution||"No contribution recorded.")}</li>`).join(""):"<li>No uploaded materials reviewed.</li>",ideas=Array.isArray(r["Extracted Strategy Ideas"])?r["Extracted Strategy Ideas"].map(x=>`<li>${UI.escapeHtml(x)}</li>`).join(""):"<li>Unavailable</li>",raw=c.report_url?`<a class="tool-button" href="${c.report_url}" target="_blank" rel="noreferrer">Open Raw Markdown Artifact</a>`:`<span class="factory-artifact-note">Evidence report artifact pending.</span>`;return `<section id="factoryReportViewer" class="panel factory-section factory-report-viewer readable">${UI.SectionHeader({title:"Styled Strategy Factory Report",meta:"Full-width embedded report"})}<article><h2>Executive Summary</h2><p>${UI.escapeHtml(r["Executive Summary"]||"Unavailable until EVIDENCE_REPORT_CREATED.")}</p><h3>Uploaded Materials Reviewed</h3><ul>${materialRows}</ul><h3>What Each Paper Contributed</h3><ul>${materialRows}</ul><h3>Extracted Strategy Ideas</h3><ul>${ideas}</ul><h3>Selected Prototype Strategy</h3><p>${UI.escapeHtml(r["Selected Prototype Strategy"]||c.strategy_id)}</p><h3>Backtest Methodology</h3><p>${UI.escapeHtml(r["Backtest Methodology"]||"Unavailable")}</p><h3>Performance Metrics</h3><div class="factory-report-metrics readable">${Object.entries(c.backtest_metrics||{}).map(([k,v])=>`<span><b>${UI.escapeHtml(k)}</b>${UI.escapeHtml(String(v))}</span>`).join("")||"<span><b>Backtest</b>Pending BACKTEST_RUN</span>"}</div><h3>Charts</h3>${factoryChartGrid(c)}<h3>ML Diagnostics</h3><p>${UI.escapeHtml(c.ml_result_summary||r["ML Diagnostics"]||"Unavailable until ML_DIAGNOSTICS_RUN.")}</p><h3>Limitations</h3><p>${UI.escapeHtml(r["Limitations"]||"Prototype-only; no institutional validation.")}</p><h3>Next Action</h3><p>${UI.escapeHtml(r["Next Action"]||c.next_action||"Review required.")}</p>${raw}</article></section>`}

function strategyFactoryPage(){const f=factoryPayload(),candidate=f.latest_candidate,candidates=candidate?[candidate]:[],materials=f.intake?.materials||[],counts=f.backend_counts||{},portfolio=f.candidate_portfolio||[],drafts=f.allocation_drafts||[],applied=f.applied_paper_strategies||[];return `<main class="main-stage"><div class="page workflow-page strategy-factory-page readable-layout">${pageTitle("Strategy Factory","AI strategy discovery plugin: prototype research to user-confirmed paper portfolio draft flow")}${secondaryStageNote("Strategy Factory safety boundary",[["PROTOTYPE_ONLY","Generated candidates are research prototypes, not live or institutionally validated strategies."],["PAPER_ONLY","Add and allocation draft actions create local draft artifacts only."],["USER_CONFIRMATION","Apply to Paper Portfolio requires explicit confirmation and records a backend artifact; brokerage execution remains disabled."]])}${factorySection("Pipeline Status Strip","Uploaded / extracted / failed / analyzed / prototype / tested / evidence / portfolio semantics",factoryWorkflowStrip(f)+factoryStatusBanner(f))}${factorySection("Upload + Intake Queue",`${materials.length} material(s)`,`${UI.MetricCard({label:"Active count",value:String(counts.current_active_strategy_count??"N/A"),detail:"backend state, not hardcoded",tone:"positive"})}<form id="strategyFactoryUploadForm" class="factory-upload-form"><input id="strategyFactoryFiles" type="file" multiple accept=".pdf,.txt,.md,.csv,.xlsx"><button class="tool-button" type="submit" ${state.strategyFactoryBusy?"disabled":""}>Upload</button><button class="tool-button" type="button" id="strategyFactoryRun" ${state.strategyFactoryBusy?"disabled":""}>Run Strategy Factory</button></form>${table(["Filename","Type","Uploaded","Extraction","Chars","Stored"],materials.slice().reverse().map(x=>`<tr><td>${UI.escapeHtml(x.filename)}</td><td>${UI.escapeHtml(x.file_type)}</td><td>${UI.escapeHtml(x.uploaded_at)}</td><td>${UI.escapeHtml(x.extraction_status)}</td><td>${x.extracted_character_count??0}</td><td>${UI.escapeHtml((x.stored_path||"").split(/[\\\\/]/).slice(-1)[0])}</td></tr>`).join("")||'<tr><td colspan="6">No intake materials uploaded.</td></tr>',"factory-intake-table")}`)}${factoryMaterialAnalysis(materials)}${factoryExtractedIdeasPanel(candidate)}${factorySection("Tested Strategy Candidate","Metrics and charts unlock only after the corresponding artifacts exist",`<div class="factory-candidate-list">${factoryCandidateCards(candidates,portfolio,drafts)}</div>`)}${factorySection("Candidate Portfolio / Allocation / Paper Apply","Candidate draft does not change active strategy count; confirmed paper apply does",`<div class="factory-three-column"><div>${UI.SectionHeader({title:"Candidate Portfolio list",meta:"Clickable operational rows"})}${factoryCandidatePortfolioPanel(portfolio,candidate)}</div><div>${UI.SectionHeader({title:"Allocation draft / risk impact",meta:"No automatic application"})}${factoryAllocationPanel(drafts)}</div><div>${UI.SectionHeader({title:"Paper application state",meta:"Combined recompute artifact"})}${factoryPaperPanel(applied,f.combined_recompute)}</div></div>`)}${factoryCandidateDetailPanel(candidate,portfolio,drafts,applied)}${factoryReportViewer(candidate)}</div></main>`}

function factoryStatusText(stage){const s=factoryStageState(stage);return `${stage}: ${s.status}. ${s.reason}`}

function factoryMetricOrStage(stage,metric,formatter){const s=factoryStageState(stage);return s.status==="COMPLETED"&&metric!=null?formatter(metric):`${s.status}: ${s.reason}`}

function factoryCandidateCards(candidates,portfolio=[],drafts=[]){if(!candidates.length)return `<div class="na-block"><strong>No candidate generated</strong><span>Run Strategy Factory stages before a candidate appears.</span></div>`;return candidates.map(c=>{const m=c.backtest_metrics||{},wf=c.portfolio_workflow||{},hasMl=factoryStageState("ML_DIAGNOSTICS_RUN").status==="COMPLETED",addEnabled=!!wf.add_enabled,allocEnabled=!!wf.allocation_enabled,applyEnabled=!!wf.apply_enabled,added=!!wf.in_candidate_portfolio,allocated=!!wf.allocation_draft_exists,applied=!!wf.applied_to_paper,addText=applied?"Applied to Paper Portfolio":added?"Added to Candidate Portfolio":addEnabled?"Add to Candidate Portfolio":"Requires Evidence Report",allocText=applied?"Allocation Used for Apply":allocated?"Allocation Draft Created":allocEnabled?"Generate Allocation Draft":"Requires Candidate Portfolio",applyText=applied?"Applied to Paper Portfolio":applyEnabled?"Apply to Paper Portfolio":"Requires Allocation Draft + Confirmation";return `<article class="factory-candidate-card readable"><header><div><strong>${UI.escapeHtml(c.name||c.strategy_id)}</strong><span>${UI.escapeHtml(c.strategy_id)} / ${UI.escapeHtml(c.source_derivation_status||"Source status unavailable")}</span></div>${factoryBadges(c.safety_labels)}</header><div class="factory-candidate-body"><div><h3>Thesis</h3><p>${UI.escapeHtml(c.strategy_thesis||"Research thesis unavailable.")}</p><h3>Pipeline</h3><p>${UI.escapeHtml(c.pipeline_stage||"PIPELINE")} / ${UI.escapeHtml(wf.candidate_status||"PIPELINE_IN_PROGRESS")}</p></div><div class="factory-metric-strip readable"><div><span>Sharpe</span><b>${UI.escapeHtml(factoryMetricOrStage("BACKTEST_RUN",m.sharpe,v=>factoryMetric(v,"ratio")))}</b></div><div><span>Annual return</span><b>${UI.escapeHtml(factoryMetricOrStage("BACKTEST_RUN",m.annual_return,v=>factoryMetric(v,"percent")))}</b></div><div><span>Max drawdown</span><b>${UI.escapeHtml(factoryMetricOrStage("BACKTEST_RUN",m.max_drawdown,v=>factoryMetric(v,"percent")))}</b></div><div><span>ML</span><b>${UI.escapeHtml(hasMl?"COMPLETED: diagnostics artifact exists":factoryStatusText("ML_DIAGNOSTICS_RUN"))}</b></div></div></div><div class="factory-actions"><a class="tool-button" href="#factoryCandidateDetail">View Candidate</a><a class="tool-button" href="#factoryReportViewer">View Report</a><button class="tool-button ${addEnabled?"":"factory-disabled"}" data-factory-action="add" data-strategy-id="${c.strategy_id}" ${addEnabled?"":"disabled"}>${addText}</button><button class="tool-button ${allocEnabled?"":"factory-disabled"}" data-factory-action="allocation" data-strategy-id="${c.strategy_id}" ${allocEnabled?"":"disabled"}>${allocText}</button><button class="tool-button ${applyEnabled?"approve-tile":"factory-disabled"}" data-factory-action="apply" data-strategy-id="${c.strategy_id}" ${applyEnabled?"":"disabled"}>${applyText}</button></div></article>`}).join("")}

function factoryChartGrid(c){const charts=c?.chart_previews||[],s=factoryStageState("BACKTEST_RUN");if(!charts.length)return `<div class="factory-chart-empty">Charts unavailable. BACKTEST_RUN: ${UI.escapeHtml(s.status)}. Reason: ${UI.escapeHtml(s.reason)} Required artifact: ${UI.escapeHtml(s.required_artifact||"backtest_results.json")}.</div>`;return `<div class="factory-chart-grid readable">${charts.map(x=>`<figure><figcaption>${UI.escapeHtml(x.title)}</figcaption><img src="${x.path}" alt="${UI.escapeHtml(x.title)}"></figure>`).join("")}</div>`}

function factoryCandidateDetailPanel(candidate,portfolio=[],drafts=[],applied=[]){if(!candidate||!portfolio.some(x=>x.strategy_id===candidate.strategy_id))return factorySection("Candidate Detail / Report Viewer","Full-width review opens after Add to Candidate Portfolio",`<div class="na-block"><strong>Candidate Detail</strong><span>Select a candidate from Candidate Portfolio List after Add to Candidate Portfolio.</span></div>`,"factory-candidate-detail");const wf=candidate.portfolio_workflow||{},portfolioDraft=portfolio.find(x=>x.strategy_id===candidate.strategy_id)||{},allocation=drafts.find(x=>x.strategy_id===candidate.strategy_id)||{},paper=applied.find(x=>x.strategy_id===candidate.strategy_id)||{},evidence=candidate.source_evidence||{},materials=candidate.source_materials||[],metrics=candidate.backtest_metrics||{},ml=candidate.ml_diagnostics||{},report=candidate.report_sections||{};return `<section id="factoryCandidateDetail" class="panel factory-section factory-candidate-detail readable">${UI.SectionHeader({title:"Candidate Detail",meta:"Full-width in-dashboard review panel"})}<article><header><div><strong>${UI.escapeHtml(candidate.name||candidate.strategy_id)}</strong><span>Status ${UI.escapeHtml(wf.candidate_status||candidate.decision_status||"Unavailable")} / Stage ${UI.escapeHtml(candidate.pipeline_stage||"Unavailable")} / Source ${UI.escapeHtml(candidate.source_derivation_status||"Unavailable")}</span></div>${factoryBadges(candidate.safety_labels)}</header>${factoryReadableBlock("Research Card",`<div class="factory-detail-grid readable">${factoryObjectRows(candidate.research_card)}</div>`)}${factoryReadableBlock("Test Spec",`<div class="factory-detail-grid readable">${factoryObjectRows(candidate.test_spec)}</div>`)}${factoryReadableBlock("Source Evidence",`<ul>${materials.map(x=>`<li><b>${UI.escapeHtml(x.filename||"Material")}</b> ${UI.escapeHtml(x.extraction_status||"Status unavailable")} / ${UI.escapeHtml(x.contribution||"No contribution recorded.")}</li>`).join("")||"<li>No source materials recorded.</li>"}</ul><div class="factory-detail-grid readable">${factoryObjectRows(evidence)}</div>`)}${factoryReadableBlock("Backtest Results",`<p>${UI.escapeHtml(factoryStatusText("BACKTEST_RUN"))}</p><div class="factory-report-metrics readable">${Object.entries(metrics).map(([k,v])=>`<span><b>${UI.escapeHtml(k)}</b>${UI.escapeHtml(String(v))}</span>`).join("")||`<span><b>Required artifact</b>${UI.escapeHtml(factoryStageState("BACKTEST_RUN").required_artifact||"backtest_results.json")}</span>`}</div>`)}${factoryReadableBlock("Embedded Charts",`<div id="factoryCandidateCharts">${factoryChartGrid(candidate)}</div>`)}${factoryReadableBlock("ML Diagnostics",`<p>${UI.escapeHtml(candidate.ml_result_summary||factoryStatusText("ML_DIAGNOSTICS_RUN"))}</p><div class="factory-detail-grid readable">${factoryObjectRows({status:factoryStageState("ML_DIAGNOSTICS_RUN").status,reason:factoryStageState("ML_DIAGNOSTICS_RUN").reason,required_artifact:factoryStageState("ML_DIAGNOSTICS_RUN").required_artifact,model:ml.model,auc:ml.auc,precision:ml.precision,recall:ml.recall,limitations:ml.limitations})}</div><h4>Feature Importance</h4><ul>${(ml.feature_importance||[]).map(x=>`<li>${UI.escapeHtml(x.feature)}: ${UI.escapeHtml(String(x.importance))}</li>`).join("")||`<li>${UI.escapeHtml(factoryStatusText("ML_DIAGNOSTICS_RUN"))}</li>`}</ul>`)}${factoryReadableBlock("Portfolio Workflow State",`<div class="factory-detail-grid readable"><div><span>Candidate portfolio draft</span><b>${UI.escapeHtml(portfolioDraft.artifact_path||candidate.candidate_portfolio_draft_path||"Unavailable")}</b></div><div><span>Allocation draft status</span><b>${allocation.status?UI.escapeHtml(allocation.status):"No allocation draft"}</b></div><div><span>Paper apply status</span><b>${paper.status?UI.escapeHtml(paper.status):"Not applied"}</b></div><div><span>Workflow status</span><b>${UI.escapeHtml(wf.candidate_status||"Unavailable")}</b></div></div>`)}${factoryReadableBlock("Evidence Report Summary",`<p>${UI.escapeHtml(report["Executive Summary"]||factoryStatusText("EVIDENCE_REPORT_CREATED"))}</p><p>${UI.escapeHtml(report["Limitations"]||"Prototype-only; no institutional validation.")}</p>`)}</article></section>`}

function factoryReportViewer(c){if(!c)return "";const r=c.report_sections||{},materialRows=Array.isArray(r["Uploaded Materials Reviewed"])?r["Uploaded Materials Reviewed"].map(x=>`<li><b>${UI.escapeHtml(x.filename||"Material")}</b> ${UI.escapeHtml(x.contribution||"No contribution recorded.")}</li>`).join(""):"<li>No uploaded materials reviewed.</li>",ideas=Array.isArray(r["Extracted Strategy Ideas"])?r["Extracted Strategy Ideas"].map(x=>`<li>${UI.escapeHtml(x)}</li>`).join(""):"<li>Unavailable</li>",raw=c.report_url?`<a class="tool-button" href="${c.report_url}" target="_blank" rel="noreferrer">Open Raw Markdown Artifact</a>`:`<span class="factory-artifact-note">Evidence report artifact required: ${UI.escapeHtml(factoryStageState("EVIDENCE_REPORT_CREATED").required_artifact||"evidence_report.md")}</span>`;return `<section id="factoryReportViewer" class="panel factory-section factory-report-viewer readable">${UI.SectionHeader({title:"Styled Strategy Factory Report",meta:"Full-width embedded report"})}<article><h2>Executive Summary</h2><p>${UI.escapeHtml(r["Executive Summary"]||factoryStatusText("EVIDENCE_REPORT_CREATED"))}</p><h3>Uploaded Materials Reviewed</h3><ul>${materialRows}</ul><h3>What Each Paper Contributed</h3><ul>${materialRows}</ul><h3>Extracted Strategy Ideas</h3><ul>${ideas}</ul><h3>Selected Prototype Strategy</h3><p>${UI.escapeHtml(r["Selected Prototype Strategy"]||c.strategy_id)}</p><h3>Backtest Methodology</h3><p>${UI.escapeHtml(r["Backtest Methodology"]||factoryStatusText("BACKTEST_RUN"))}</p><h3>Performance Metrics</h3><div class="factory-report-metrics readable">${Object.entries(c.backtest_metrics||{}).map(([k,v])=>`<span><b>${UI.escapeHtml(k)}</b>${UI.escapeHtml(String(v))}</span>`).join("")||`<span><b>BACKTEST_RUN</b>${UI.escapeHtml(factoryStageState("BACKTEST_RUN").status)}: ${UI.escapeHtml(factoryStageState("BACKTEST_RUN").reason)}</span>`}</div><h3>Charts</h3>${factoryChartGrid(c)}<h3>ML Diagnostics</h3><p>${UI.escapeHtml(c.ml_result_summary||r["ML Diagnostics"]||factoryStatusText("ML_DIAGNOSTICS_RUN"))}</p><h3>Limitations</h3><p>${UI.escapeHtml(r["Limitations"]||"Prototype-only; no institutional validation.")}</p><h3>Next Action</h3><p>${UI.escapeHtml(r["Next Action"]||c.next_action||factoryStageState("EVIDENCE_REPORT_CREATED").action)}</p>${raw}</article></section>`}

function strategyFactoryPage(){const f=factoryPayload(),candidate=f.latest_candidate,candidates=candidate?[candidate]:[],materials=f.intake?.materials||[],counts=f.backend_counts||{},portfolio=f.candidate_portfolio||[],drafts=f.allocation_drafts||[],applied=f.applied_paper_strategies||[];return `<main class="main-stage"><div class="page workflow-page strategy-factory-page readable-layout">${pageTitle("Strategy Factory","AI strategy discovery plugin: prototype research to user-confirmed paper portfolio draft flow")}${secondaryStageNote("Strategy Factory safety boundary",[["PROTOTYPE_ONLY","Generated candidates are research prototypes, not live or institutionally validated strategies."],["PAPER_ONLY","Add and allocation draft actions create local draft artifacts only."],["USER_CONFIRMATION","Apply to Paper Portfolio requires explicit confirmation and records a backend artifact; brokerage execution remains disabled."]])}${factorySection("Pipeline Status Strip","Explicit statuses: NOT_STARTED / QUEUED / RUNNING / COMPLETED / FAILED / BLOCKED",factoryWorkflowStrip(f)+factoryStatusBanner(f)+factoryStageStatusPanel(f))}${factorySection("Upload + Intake Queue",`${materials.length} material(s)`,`${UI.MetricCard({label:"Active count",value:String(counts.current_active_strategy_count??"N/A"),detail:"backend state, not hardcoded",tone:"positive"})}<form id="strategyFactoryUploadForm" class="factory-upload-form"><input id="strategyFactoryFiles" type="file" multiple accept=".pdf,.txt,.md,.csv,.xlsx"><button class="tool-button" type="submit" ${state.strategyFactoryBusy?"disabled":""}>Upload</button><button class="tool-button" type="button" id="strategyFactoryRun" ${state.strategyFactoryBusy?"disabled":""}>Run Strategy Factory</button></form>${table(["Filename","Type","Uploaded","Extraction","Chars","Stored"],materials.slice().reverse().map(x=>`<tr><td>${UI.escapeHtml(x.filename)}</td><td>${UI.escapeHtml(x.file_type)}</td><td>${UI.escapeHtml(x.uploaded_at)}</td><td>${UI.escapeHtml(x.extraction_status)}</td><td>${x.extracted_character_count??0}</td><td>${UI.escapeHtml((x.stored_path||"").split(/[\\\\/]/).slice(-1)[0])}</td></tr>`).join("")||'<tr><td colspan="6">No intake materials uploaded.</td></tr>',"factory-intake-table")}`)}${factoryMaterialAnalysis(materials)}${factoryExtractedIdeasPanel(candidate)}${factorySection("Tested Strategy Candidate","Metrics and charts use explicit stage statuses until artifacts exist",`<div class="factory-candidate-list">${factoryCandidateCards(candidates,portfolio,drafts)}</div>`)}${factorySection("Candidate Portfolio / Allocation / Paper Apply","Candidate draft does not change active strategy count; confirmed paper apply does",`<div class="factory-three-column"><div>${UI.SectionHeader({title:"Candidate Portfolio list",meta:"Clickable operational rows"})}${factoryCandidatePortfolioPanel(portfolio,candidate)}</div><div>${UI.SectionHeader({title:"Allocation draft / risk impact",meta:"No automatic application"})}${factoryAllocationPanel(drafts)}</div><div>${UI.SectionHeader({title:"Paper application state",meta:"Combined recompute artifact"})}${factoryPaperPanel(applied,f.combined_recompute)}</div></div>`)}${factoryCandidateDetailPanel(candidate,portfolio,drafts,applied)}${factoryReportViewer(candidate)}</div></main>`}

if(!window.__strategyFactoryStageDelegated){window.__strategyFactoryStageDelegated=true;document.addEventListener("click",async e=>{const b=e.target.closest?.("[data-factory-stage-run]");if(!b||state.selectedPage!=="Strategy Factory")return;e.preventDefault();e.stopPropagation();const stage=b.dataset.factoryStageRun,selected=[...(state.selectedFactoryMaterialIds||[])];if(["BACKTEST_RUN","ROBUSTNESS_RUN","ML_DIAGNOSTICS_RUN","EVIDENCE_REPORT_CREATED"].includes(stage)){try{state.strategyFactoryBusy=true;state.strategyFactoryStatusMessage="Running local current-run backtest / ML / evidence...";factoryRenderStable();const result=await strategyFactoryApi("/api/strategy-factory/backtest-current-run",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({run_id:state.strategyFactory?.latest_run?.run_id})});state.strategyFactoryStatusMessage=result.status==="BLOCKED"?`Backtest blocked: ${result.reason}`:"Backtest/ML/evidence artifacts generated for current run.";toast(result.status==="BLOCKED"?"Backtest blocked":"Backtest artifacts generated",result.status==="BLOCKED"?"warning":"positive")}catch(err){toast(err.message,"negative")}finally{state.strategyFactoryBusy=false;await refreshStrategyFactory();factoryRenderStable()}return}if(!selected.length){state.strategyFactoryStatusMessage="Select materials for current batch first.";toast("Select materials for current batch first.","warning");factoryRenderStable();return}try{state.strategyFactoryBusy=true;state.strategyFactoryStatusMessage="Running selected batch job...";factoryRenderStable();const result=await strategyFactoryApi("/api/strategy-factory/run-selected-batch",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({selected_material_ids:selected})});state.selectedFactoryCandidateId=result.job?.outputs?.candidate_id||state.selectedFactoryCandidateId;state.strategyFactoryStatusMessage=`Completed selected batch job ${result.job_id||result.job?.job_id||"selected batch"}.`;toast("Completed selected batch job","positive")}catch(err){toast(err.message,"negative")}finally{state.strategyFactoryBusy=false;await refreshStrategyFactory();factoryRenderStable()}})}

if(!window.__strategyFactoryFullRunDelegated){window.__strategyFactoryFullRunDelegated=true;document.addEventListener("click",async e=>{const b=e.target.closest?.("[data-factory-full-run]");if(!b||state.selectedPage!=="Strategy Factory")return;e.preventDefault();e.stopPropagation();try{state.strategyFactoryBusy=true;state.strategyFactoryStatusMessage="Running full current-run pipeline...";factoryRenderStable();const result=await strategyFactoryApi("/api/strategy-factory/jobs/run-full-current-run",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({run_id:state.strategyFactory?.latest_run?.run_id})});state.strategyFactoryStatusMessage=result.status==="COMPLETED"?`Full Pipeline completed. Recommendation: ${result.recommendation||"Unavailable"}`:`Full Pipeline ${result.status}: ${result.reason||"review job_status.json"}`;toast(result.status==="COMPLETED"?"Full Pipeline completed":"Full Pipeline needs review",result.status==="COMPLETED"?"positive":"warning")}catch(err){toast(err.message,"negative")}finally{state.strategyFactoryBusy=false;await refreshStrategyFactory();factoryRenderStable()}})}

function factoryDetailButton(label,tab,id){return `<button type="button" class="tool-button" data-factory-view="${UI.escapeHtml(tab)}" data-strategy-id="${UI.escapeHtml(id||"")}">${UI.escapeHtml(label)}</button>`}

function factoryMetricValue(v,type){return v==null||String(v).includes("artifact exists")?"Metric unavailable in artifact.":factoryMetric(v,type)}

function factoryCandidateCards(candidates,portfolio=[],drafts=[]){if(!candidates.length)return `<div class="na-block"><strong>No candidate generated</strong><span>Real alpha candidates appear here when artifacts exist; prototype seed is fallback only.</span></div>`;return candidates.map(c=>{const m=c.backtest_metrics||{},wf=c.portfolio_workflow||{},addEnabled=!!wf.add_enabled,allocEnabled=!!wf.allocation_enabled,applyEnabled=!!wf.apply_enabled,added=!!wf.in_candidate_portfolio,allocated=!!wf.allocation_draft_exists,applied=!!wf.applied_to_paper,addText=applied?"Applied to Paper Portfolio":added?"Added to Candidate Portfolio":addEnabled?"Add to Candidate Portfolio":"Requires Evidence Report",allocText=applied?"Allocation Used for Apply":allocated?"Allocation Draft Created":allocEnabled?"Generate Allocation Draft":"Requires Candidate Portfolio",applyText=applied?"Applied to Paper Portfolio":applyEnabled?"Apply to Paper Portfolio":"Requires Allocation Draft + Confirmation";return `<article class="factory-candidate-card readable ${state.selectedFactoryCandidateId===c.strategy_id?"selected":""}" data-factory-select="${UI.escapeHtml(c.strategy_id)}" tabindex="0" role="button" aria-label="View candidate ${UI.escapeHtml(c.strategy_id)}"><header><div><strong>${UI.escapeHtml(c.name||c.strategy_id)}</strong><span>${UI.escapeHtml(c.strategy_id)} / ${UI.escapeHtml(c.source_derivation_status||"Source status unavailable")}</span></div>${factoryBadges(c.safety_labels)}</header><div class="factory-candidate-body"><div><h3>Thesis</h3><p>${UI.escapeHtml(c.strategy_thesis||"Research thesis unavailable.")}</p><h3>Pipeline</h3><p>${UI.escapeHtml(c.pipeline_stage||"PIPELINE")} / ${UI.escapeHtml(wf.candidate_status||c.decision_status||"RESEARCH_ONLY")}</p></div><div class="factory-metric-strip readable"><div><span>Sharpe</span><b>${UI.escapeHtml(factoryMetricValue(m.sharpe,"ratio"))}</b></div><div><span>Annual return</span><b>${UI.escapeHtml(factoryMetricValue(m.annual_return,"percent"))}</b></div><div><span>Max drawdown</span><b>${UI.escapeHtml(factoryMetricValue(m.max_drawdown,"percent"))}</b></div><div><span>Turnover</span><b>${UI.escapeHtml(factoryMetricValue(m.turnover,"percent"))}</b></div></div></div><div class="factory-actions">${factoryDetailButton("View Candidate","Overview",c.strategy_id)}${factoryDetailButton("Backtest","Backtest",c.strategy_id)}${factoryDetailButton("View Report","Report",c.strategy_id)}${factoryDetailButton("View Charts","Charts",c.strategy_id)}<button type="button" class="tool-button ${addEnabled?"":"factory-disabled"}" data-factory-action="add" data-strategy-id="${c.strategy_id}" ${addEnabled?"":"disabled"}>${addText}</button><button type="button" class="tool-button ${allocEnabled?"":"factory-disabled"}" data-factory-action="allocation" data-strategy-id="${c.strategy_id}" ${allocEnabled?"":"disabled"}>${allocText}</button><button type="button" class="tool-button ${applyEnabled?"approve-tile":"factory-disabled"}" data-factory-action="apply" data-strategy-id="${c.strategy_id}" ${applyEnabled?"":"disabled"}>${applyText}</button></div></article>`}).join("")}

function factoryCandidateOutputPanel(candidates,portfolio,drafts){const current=factoryCurrentRunCandidates(candidates),historical=factoryHistoricalAlphaCandidates(candidates),prototype=factoryPrototypeCandidates(candidates);return `<div class="factory-candidate-groups"><section><h3>Current Run Candidates / Ideas</h3><p>${current.length?`${current.length} selected-batch output(s) loaded from the current run.`:"No current selected-batch run output yet. Select materials and click Run Selected Batch."}</p><div class="factory-candidate-list current-run-output">${factoryCandidateCards(current,portfolio,drafts)}</div></section><section><h3>Historical Alpha Candidates</h3><p>${historical.length?`${historical.length} alpha_research candidate artifact(s) loaded.`:"No historical alpha candidates found."}</p><div class="factory-candidate-list">${factoryCandidateCards(historical,portfolio,drafts)}</div></section>${prototype.length?`<section><h3>Prototype Seed Fallback</h3><p>PROTOTYPE_SEED_NOT_DERIVED_FROM_UPLOADS</p><div class="factory-candidate-list prototype-fallback">${factoryCandidateCards(prototype,portfolio,drafts)}</div></section>`:""}</div>`}

function factoryCandidatePortfolioPanel(portfolio,candidate){return `<div class="factory-candidate-portfolio-list">${portfolio.map(x=>{const selected=(state.selectedFactoryCandidateId||candidate?.strategy_id)===x.strategy_id,hasBacktest=!!candidate?.backtest_metrics;return `<article class="factory-portfolio-row readable ${selected?"selected":""}" data-factory-select="${UI.escapeHtml(x.strategy_id)}" tabindex="0" role="button" aria-label="View candidate ${UI.escapeHtml(x.strategy_id)}"><header><div><strong>${UI.escapeHtml(x.candidate_name||x.strategy_id)}</strong><span>${UI.escapeHtml(x.strategy_id)} / ${UI.escapeHtml(x.status)}</span></div><b>${UI.escapeHtml(candidate?.pipeline_stage||"Pipeline")}</b></header><p>${UI.escapeHtml(x.strategy_thesis||"No thesis recorded.")}</p><div class="factory-portfolio-metrics"><span>${hasBacktest?`Sharpe ${factoryMetric(candidate.backtest_metrics.sharpe,"ratio")}`:factoryStageState("BACKTEST_RUN").status}</span><span>${hasBacktest?`Return ${factoryMetric(candidate.backtest_metrics.annual_return,"percent")}`:"Metrics locked"}</span><span>${UI.escapeHtml(x.updated_at||x.created_at||"Timestamp unavailable")}</span></div><code>${UI.escapeHtml(x.artifact_path||"candidate_portfolio_draft.json")}</code><footer>${factoryDetailButton("View Candidate","Overview",x.strategy_id)}${factoryDetailButton("View Report","Report",x.strategy_id)}${factoryDetailButton("View Charts","Charts",x.strategy_id)}<button type="button" class="tool-button" data-factory-action="allocation" data-strategy-id="${UI.escapeHtml(x.strategy_id)}">Generate Allocation Draft</button><button type="button" class="tool-button factory-remove-button" data-factory-action="remove" data-strategy-id="${UI.escapeHtml(x.strategy_id)}">Remove from Candidate Portfolio</button></footer></article>`}).join("")||"<p>No candidate portfolio drafts.</p>"}</div>`}

function factoryDetailTabs(){const tabs=["Overview","Research Card","Test Spec","Source Evidence","Backtest","Charts","ML","Report","Portfolio Flow"];return `<nav class="factory-detail-tabs">${tabs.map(t=>`<button class="${state.selectedFactoryDetailTab===t?"active":""}" data-factory-detail-tab="${UI.escapeHtml(t)}">${UI.escapeHtml(t)}</button>`).join("")}</nav>`}

function factoryStageLock(stage,artifact){const s=factoryStageState(stage);return `<div class="factory-locked-state"><strong>${UI.escapeHtml(stage)}: ${UI.escapeHtml(s.status)}</strong><p>${UI.escapeHtml(s.reason)}</p><dl><dt>Required artifact</dt><dd>${UI.escapeHtml(artifact||s.required_artifact||"Unavailable")}</dd><dt>Next action</dt><dd>${UI.escapeHtml(s.action||"Run Strategy Factory stage.")}</dd><dt>Last updated</dt><dd>${UI.escapeHtml(s.last_updated||"timestamp unavailable")}</dd></dl></div>`}

function factoryReportTab(candidate){const s=factoryStageState("EVIDENCE_REPORT_CREATED"),r=candidate.report_sections||{};if(s.status!=="COMPLETED")return `<div class="factory-locked-state compact"><strong>Evidence report not generated yet</strong><p>Required previous stages: extraction, material analysis, research card, test spec, backtest, and ML diagnostics if selected.</p><dl><dt>Current status</dt><dd>${UI.escapeHtml(s.status)}</dd><dt>Reason</dt><dd>${UI.escapeHtml(s.reason)}</dd><dt>Required artifact</dt><dd>${UI.escapeHtml(s.required_artifact||"evidence_report.md")}</dd></dl></div>`;return `<article class="factory-inline-report"><h2>${UI.escapeHtml(candidate.name||candidate.strategy_id)}</h2><h3>Executive Summary</h3><p>${UI.escapeHtml(r["Executive Summary"]||"Unavailable")}</p><h3>Uploaded Materials Reviewed</h3><ul>${Array.isArray(r["Uploaded Materials Reviewed"])?r["Uploaded Materials Reviewed"].map(x=>`<li><b>${UI.escapeHtml(x.filename||"Material")}</b> ${UI.escapeHtml(x.contribution||"No contribution recorded.")}</li>`).join(""):"<li>No uploaded materials reviewed.</li>"}</ul><h3>Backtest Methodology</h3><p>${UI.escapeHtml(r["Backtest Methodology"]||"Unavailable")}</p><h3>Limitations</h3><p>${UI.escapeHtml(r["Limitations"]||"Prototype-only; no institutional validation.")}</p></article>`}

function factoryChartMeta(chart){return `<dl class="factory-chart-meta"><dt>Source artifact</dt><dd>${UI.escapeHtml(chart.source_artifact_path||"Unavailable")}</dd><dt>Data range</dt><dd>${UI.escapeHtml(chart.data_range||"Unavailable")}</dd><dt>Benchmark</dt><dd>${UI.escapeHtml(chart.benchmark||"Unavailable")}</dd><dt>Cost assumption</dt><dd>${UI.escapeHtml(chart.cost_assumption||"Unavailable")}</dd></dl>`}

function factoryChartValue(v,type="ratio"){const n=Number(v);if(v==null||v==="Metric unavailable in artifact."||!Number.isFinite(n))return "Metric unavailable in artifact.";return type==="percent"?UI.percent(n,2):UI.displayNumber(n,{maximumFractionDigits:3})}

function factoryLineSvg(chart,title){const series=(chart?.series||[]).filter(s=>(s.values||[]).length>1);if(!series.length)return `<div class="factory-locked-state compact"><strong>${UI.escapeHtml(title)}</strong><p>Chart unavailable: missing real backtest series.</p></div>`;const all=series.flatMap(s=>s.values||[]),vals=all.map(p=>Number(p.value)).filter(Number.isFinite),min=Math.min(...vals),max=Math.max(...vals),span=max-min||1,w=760,h=220,pad=36,colors=["#19aef5","#f2ae22","#e95d52"];const pathFor=(values)=>values.map((p,i)=>{const x=pad+(i/Math.max(1,values.length-1))*(w-pad*2),y=h-pad-((Number(p.value)-min)/span)*(h-pad*2);return `${i?"L":"M"}${x.toFixed(1)} ${y.toFixed(1)}`}).join(" ");const first=all[0]?.date||"",last=all.at(-1)?.date||"";return `<figure class="factory-real-chart"><figcaption><strong>${UI.escapeHtml(title)}</strong><span>${UI.escapeHtml(first)} to ${UI.escapeHtml(last)}</span></figcaption><svg viewBox="0 0 ${w} ${h}" role="img" aria-label="${UI.escapeHtml(title)}"><line x1="${pad}" y1="${h-pad}" x2="${w-pad}" y2="${h-pad}" stroke="#d8dee9"/><line x1="${pad}" y1="${pad}" x2="${pad}" y2="${h-pad}" stroke="#d8dee9"/>${series.map((s,i)=>`<path d="${pathFor(s.values||[])}" fill="none" stroke="${colors[i%colors.length]}" stroke-width="2"/>`).join("")}<text x="${pad}" y="${h-10}" fill="#607080" font-size="11">${UI.escapeHtml(first)}</text><text x="${w-pad-80}" y="${h-10}" fill="#607080" font-size="11">${UI.escapeHtml(last)}</text><text x="${pad}" y="18" fill="#607080" font-size="11">${factoryChartValue(max)}</text><text x="${pad}" y="${h-pad-4}" fill="#607080" font-size="11">${factoryChartValue(min)}</text></svg><div class="factory-chart-legend">${series.map((s,i)=>`<span><i style="background:${colors[i%colors.length]}"></i>${UI.escapeHtml(s.label||`Series ${i+1}`)}</span>`).join("")}</div></figure>`}

function factoryHistogramSvg(chart){const bins=chart?.bins||[];if(!bins.length)return `<div class="factory-locked-state compact"><strong>Return Distribution</strong><p>Chart unavailable: missing real backtest series.</p></div>`;const max=Math.max(...bins.map(b=>Number(b.count)||0),1),w=760,h=220,pad=36,barW=(w-pad*2)/bins.length;return `<figure class="factory-real-chart"><figcaption><strong>Return Distribution</strong><span>Daily net return histogram</span></figcaption><svg viewBox="0 0 ${w} ${h}" role="img" aria-label="Return distribution histogram"><line x1="${pad}" y1="${h-pad}" x2="${w-pad}" y2="${h-pad}" stroke="#d8dee9"/>${bins.map((b,i)=>{const bh=((Number(b.count)||0)/max)*(h-pad*2),x=pad+i*barW+2,y=h-pad-bh;return `<rect x="${x.toFixed(1)}" y="${y.toFixed(1)}" width="${Math.max(2,barW-4).toFixed(1)}" height="${bh.toFixed(1)}" fill="#67d3ff"><title>${UI.escapeHtml(b.label)}: ${UI.escapeHtml(String(b.count))}</title></rect>`}).join("")}<text x="${pad}" y="${h-10}" fill="#607080" font-size="11">${UI.escapeHtml(bins[0]?.label||"")}</text><text x="${w-pad-150}" y="${h-10}" fill="#607080" font-size="11">${UI.escapeHtml(bins.at(-1)?.label||"")}</text></svg></figure>`}

function factoryRowsTable(headers,rows){return `<table class="mini-table factory-chart-table"><thead><tr>${headers.map(h=>`<th>${UI.escapeHtml(h)}</th>`).join("")}</tr></thead><tbody>${rows}</tbody></table>`}

function factoryChartGrid(candidate){const chart=candidate?.chart_data||{};if(chart.status==="AVAILABLE")return `<div class="factory-chart-grid readable real-artifact-charts">${factoryChartMeta(chart)}${factoryLineSvg(chart.equity_curve,"Equity Curve vs Benchmark")}${factoryLineSvg(chart.drawdown,"Drawdown")}${factoryLineSvg(chart.rolling_sharpe,`Rolling Sharpe (${chart.rolling_sharpe?.window||63}D)`) }<section class="factory-real-chart table-chart"><h4>Monthly Returns</h4>${factoryRowsTable(["Month","Strategy","Benchmark"],(chart.monthly_returns?.rows||[]).slice(-24).map(r=>`<tr><td>${UI.escapeHtml(r.month)}</td><td>${factoryChartValue(r.strategy_return,"percent")}</td><td>${factoryChartValue(r.benchmark_return,"percent")}</td></tr>`).join("")||'<tr><td colspan="3">Chart unavailable: missing real backtest series.</td></tr>')}</section>${factoryHistogramSvg(chart.return_distribution)}<section class="factory-real-chart table-chart"><h4>Turnover / Transaction Cost</h4>${factoryRowsTable(["Month","Avg turnover","Cost drag"],(chart.turnover_cost?.rows||[]).slice(-24).map(r=>`<tr><td>${UI.escapeHtml(r.month)}</td><td>${factoryChartValue(r.average_turnover,"percent")}</td><td>${factoryChartValue(r.cost_drag,"percent")}</td></tr>`).join("")||'<tr><td colspan="3">Chart unavailable: missing real turnover/cost series.</td></tr>')}</section></div>`;const metrics=chart.summary_metrics||candidate?.backtest_metrics||{},summaryOnly=chart.status==="SUMMARY_ONLY"||Object.keys(metrics).length>0,message=summaryOnly?"Charts unavailable: summary metrics exist but candidate-specific time series is missing.":"Chart unavailable: missing real backtest series.";return `<div class="factory-locked-state compact"><strong>${message}</strong><p>${UI.escapeHtml(chart.message||"The dashboard does not render placeholder charts.")}</p>${factoryChartMeta(chart)}${factoryRowsTable(["Metric","Value"],Object.entries(metrics).map(([k,v])=>`<tr><td>${UI.escapeHtml(k)}</td><td>${UI.escapeHtml(String(v??"Metric unavailable in artifact."))}</td></tr>`).join("")||'<tr><td colspan="2">Metric unavailable in artifact.</td></tr>')}</div>`}

function factoryCleanArtifactRows(chain){const labels={research_card:"Research card",test_spec:"Test spec",run_plan:"Run plan",backtest:"Backtest",robustness:"Robustness",ml_diagnostics:"ML diagnostics",evidence:"Evidence report",decision:"Decision memo",idea:"Idea artifact",batch_manifest:"Batch manifest",run_manifest:"Run manifest"};return Object.entries(chain||{}).map(([k,v])=>`<tr><td>${UI.escapeHtml(labels[k]||k)}</td><td>${v?"Available":"Unavailable"}</td></tr>`).join("")||'<tr><td colspan="2">No candidate-specific artifacts linked.</td></tr>'}

function factorySelectedBatchMaterials(){const selected=new Set(state.selectedFactoryMaterialIds||[]),materials=factoryPayload().intake?.materials||[];return materials.filter(row=>selected.has(String(row.material_id||"")))}

function factoryGlobalContextRows(materials){return factorySortedMaterials(materials).slice(0,5).map(x=>`<li><b>${UI.escapeHtml(x.filename||x.material_id||"Material")}</b> ${UI.escapeHtml(x.extraction_status||"Status unavailable")} / ${UI.escapeHtml(x.uploaded_at||x.batch_id||"timestamp unavailable")}</li>`).join("")||"<li>No global materials available.</li>"}

function factorySourceEvidencePanel(candidate){const evidence=candidate.source_evidence||{},chain=evidence.artifact_chain||{},materials=candidate.source_materials||[],selected=factorySelectedBatchMaterials(),globalMaterials=factoryPayload().intake?.materials||[],counts=factoryPayload().stage_counts||{},prototype=String(candidate.source_derivation_status||"").includes("PROTOTYPE_SEED_NOT_DERIVED_FROM_UPLOADS"),candidateRows=prototype?'<tr><td>Candidate-derived evidence</td><td>None</td></tr><tr><td>Reason</td><td>PROTOTYPE_SEED_NOT_DERIVED_FROM_UPLOADS</td></tr>':factoryCleanArtifactRows(chain),selectedRows=selected.length?selected.map(x=>`<li><b>${UI.escapeHtml(x.filename||x.material_id||"Material")}</b> ${UI.escapeHtml(x.extraction_status||"Status unavailable")} / ${UI.escapeHtml(x.material_id||"")}</li>`).join(""):"<li>No selected batch materials. This candidate was not produced by the current selected batch.</li>",candidateMaterialRows=!prototype&&materials.length?materials.map(x=>`<li><b>${UI.escapeHtml(x.filename||x.material_id||"Material")}</b> ${UI.escapeHtml(x.extraction_status||"Status unavailable")} ${x.contribution?`/ ${UI.escapeHtml(x.contribution)}`:""}</li>`).join(""):"",raw=JSON.stringify({candidate_id:candidate.strategy_id,batch_id:evidence.batch_id||evidence.source_batch_id||evidence.source_batch_ids,run_id:evidence.run_id,selected_material_ids:evidence.selected_material_ids||evidence.source_material_ids,artifact_chain:chain},null,2);return `<div class="factory-evidence-groups"><section><h4>Candidate-derived evidence</h4>${factoryRowsTable(["Artifact","Status"],candidateRows)}${candidateMaterialRows?`<ul>${candidateMaterialRows}</ul>`:""}</section><section><h4>Selected batch materials</h4><dl class="factory-chart-meta"><dt>batch_id</dt><dd>${UI.escapeHtml(String(evidence.batch_id||evidence.source_batch_ids?.[0]||"Unavailable"))}</dd><dt>run_id</dt><dd>${UI.escapeHtml(String(evidence.run_id||"Unavailable"))}</dd><dt>selected_material_ids</dt><dd>${UI.escapeHtml(String((evidence.selected_material_ids||evidence.source_material_ids||[]).join?.(", ")||"Unavailable"))}</dd></dl><ul>${selectedRows}</ul></section><section><h4>Global alpha_research context</h4><dl class="factory-chart-meta"><dt>Total materials available</dt><dd>${UI.escapeHtml(String(counts.uploaded_materials??globalMaterials.length??0))}</dd><dt>Extracted</dt><dd>${UI.escapeHtml(String(counts.extracted_materials??0))}</dd><dt>Analyzed</dt><dd>${UI.escapeHtml(String(counts.analyzed_records??0))}</dd></dl><p>Global artifacts provide context only. They are not displayed as direct support unless linked to the selected candidate.</p><ul>${factoryGlobalContextRows(globalMaterials)}</ul><details><summary>View all global context</summary><ul>${globalMaterials.map(x=>`<li><b>${UI.escapeHtml(x.filename||x.material_id||"Material")}</b> ${UI.escapeHtml(x.extraction_status||"Status unavailable")} / ${UI.escapeHtml(x.material_id||"")}</li>`).join("")||"<li>No global materials available.</li>"}</ul></details></section><details class="factory-debug-paths"><summary>Show raw artifact paths</summary><pre>${UI.escapeHtml(raw)}</pre></details></div>`}

function factoryCandidateDetailContent(candidate,portfolioDraft,allocation,paper){const tab=state.selectedFactoryDetailTab||"Overview",metrics=candidate.backtest_metrics||{},ml=candidate.ml_diagnostics||{},wf=candidate.portfolio_workflow||{},run=candidate.current_run||{};if(tab==="Research Card")return factoryReadableBlock("Research Card",`<div class="factory-detail-grid readable">${factoryObjectRows(candidate.research_card)}</div>`);if(tab==="Test Spec")return factoryReadableBlock("Test Spec",`<div class="factory-detail-grid readable">${factoryObjectRows(candidate.test_spec)}</div>`);if(tab==="Source Evidence")return factoryReadableBlock("Source Evidence",factorySourceEvidencePanel(candidate));if(tab==="Backtest")return factoryReadableBlock("Backtest Results",`<p>${UI.escapeHtml(factoryStatusText("BACKTEST_RUN"))}</p><div class="factory-report-metrics readable">${Object.entries(metrics).map(([k,v])=>`<span><b>${UI.escapeHtml(k)}</b>${UI.escapeHtml(String(v))}</span>`).join("")||`<span><b>Required artifact</b>${UI.escapeHtml(factoryStageState("BACKTEST_RUN").required_artifact||"backtest_results.json")}</span>`}</div>`);if(tab==="Charts"){const chart=candidate.chart_data||{},s=factoryStageState("BACKTEST_RUN");if(chart.status==="AVAILABLE"||chart.status==="SUMMARY_ONLY")return factoryReadableBlock("Charts",`<div id="factoryCandidateCharts">${factoryChartGrid(candidate)}</div>`);const completed=s.status==="COMPLETED",message=completed?"Charts unavailable: summary metrics exist but candidate-specific time series is missing.":`Charts unavailable: BACKTEST_RUN ${s.status.toLowerCase().replaceAll("_"," ")}.`;return factoryReadableBlock("Charts",`<div class="factory-locked-state compact"><strong>${UI.escapeHtml(message)}</strong><p>${UI.escapeHtml(s.reason)}</p><dl><dt>Required artifact</dt><dd>daily_strategy_returns.csv or backtest_run.json</dd><dt>Next action</dt><dd>${UI.escapeHtml(s.action||"Run Prototype Backtest.")}</dd></dl></div>`)}if(tab==="ML")return factoryReadableBlock("ML Diagnostics",`<p>${UI.escapeHtml(candidate.ml_result_summary||factoryStatusText("ML_DIAGNOSTICS_RUN"))}</p><div class="factory-detail-grid readable">${factoryObjectRows({status:factoryStageState("ML_DIAGNOSTICS_RUN").status,reason:factoryStageState("ML_DIAGNOSTICS_RUN").reason,required_artifact:factoryStageState("ML_DIAGNOSTICS_RUN").required_artifact,model:ml.model,auc:ml.auc,precision:ml.precision,recall:ml.recall,limitations:ml.limitations})}</div><h4>Feature Importance</h4><ul>${(ml.feature_importance||[]).map(x=>`<li>${UI.escapeHtml(x.feature)}: ${UI.escapeHtml(String(x.importance))}</li>`).join("")||`<li>${UI.escapeHtml(factoryStatusText("ML_DIAGNOSTICS_RUN"))}</li>`}</ul>`);if(tab==="Report")return factoryReportTab(candidate);if(tab==="Portfolio Flow")return factoryReadableBlock("Portfolio Workflow State",`<div class="factory-detail-grid readable"><div><span>Candidate portfolio draft</span><b>${UI.escapeHtml(portfolioDraft.artifact_path||candidate.candidate_portfolio_draft_path||"Unavailable")}</b></div><div><span>Allocation draft status</span><b>${allocation.status?UI.escapeHtml(allocation.status):"No allocation draft"}</b></div><div><span>Paper apply status</span><b>${paper.status?UI.escapeHtml(paper.status):"Not applied"}</b></div><div><span>Workflow status</span><b>${UI.escapeHtml(wf.candidate_status||"Unavailable")}</b></div></div>`);return factoryReadableBlock("Overview",`<div class="factory-detail-grid readable"><div><span>Strategy</span><b>${UI.escapeHtml(candidate.name||candidate.strategy_id)}</b></div><div><span>Status</span><b>${UI.escapeHtml(wf.candidate_status||candidate.decision_status||"Unavailable")}</b></div><div><span>Pipeline stage</span><b>${UI.escapeHtml(candidate.pipeline_stage||"Unavailable")}</b></div><div><span>Source label</span><b>${UI.escapeHtml(candidate.source_derivation_status||"Unavailable")}</b></div><div><span>Current run id</span><b>${UI.escapeHtml(run.current_run_id||"Unavailable")}</b></div><div><span>Current batch id</span><b>${UI.escapeHtml(run.current_batch_id||"Unavailable")}</b></div><div><span>Selected materials used</span><b>${UI.escapeHtml((run.selected_material_names||[]).join(", ")||"Unavailable")}</b></div><div><span>Run manifest</span><b>${UI.escapeHtml(run.run_manifest_path||"Unavailable")}</b></div><div><span>Backtest</span><b>${UI.escapeHtml(factoryStageLabel("BACKTEST_RUN"))}</b></div><div><span>Evidence report</span><b>${UI.escapeHtml(factoryStageLabel("EVIDENCE_REPORT_CREATED"))}</b></div></div><h3>Thesis</h3><p>${UI.escapeHtml(candidate.strategy_thesis||"Unavailable")}</p><h3>Next available action</h3><p>${UI.escapeHtml(candidate.next_action||factoryStageState("BACKTEST_RUN").action)}</p>`)}

function factoryCandidateDetailPanel(candidate,portfolio=[],drafts=[],applied=[]){if(!candidate)return `<section id="factoryCandidateWorkspace" class="panel factory-section factory-candidate-workspace compact"><div class="na-block"><strong>Candidate workspace</strong><span>Select a real alpha candidate or run a selected material batch.</span></div></section>`;const portfolioDraft=portfolio.find(x=>x.strategy_id===candidate.strategy_id)||{},allocation=drafts.find(x=>x.strategy_id===candidate.strategy_id)||{},paper=applied.find(x=>x.strategy_id===candidate.strategy_id)||{},wf=candidate.portfolio_workflow||{};return `<section id="factoryCandidateWorkspace" class="panel factory-section factory-candidate-workspace readable">${UI.SectionHeader({title:"Selected Candidate Workspace",meta:"Candidate-specific lineage and artifacts"})}<article><header><div><strong>${UI.escapeHtml(candidate.name||candidate.strategy_id)}</strong><span>${UI.escapeHtml(candidate.strategy_id)} / ${UI.escapeHtml(wf.candidate_status||candidate.decision_status||"Unavailable")} / ${UI.escapeHtml(candidate.pipeline_stage||"Unavailable")} / ${UI.escapeHtml(candidate.source_derivation_status||"Unavailable")}</span></div>${factoryBadges(candidate.safety_labels)}</header>${factoryDetailTabs()}<div class="factory-tab-body">${factoryCandidateDetailContent(candidate,portfolioDraft,allocation,paper)}</div></article></section>`}

function factoryMaterialSelectionToolbar(materials){const ids=materials.map(x=>String(x.material_id||"")).filter(Boolean),selected=new Set(state.selectedFactoryMaterialIds||[]),visibleSelected=ids.filter(id=>selected.has(id)).length,mode=state.factoryMaterialWindowExpanded?"Compact":"Expanded";return `<div class="factory-selection-toolbar"><strong>Current Batch</strong><span>${visibleSelected} selected</span><button type="button" class="tool-button" data-factory-material-control="select-visible">Select all visible</button><button type="button" class="tool-button" data-factory-material-control="clear">Clear selection</button><button type="button" class="tool-button" data-factory-material-control="remove">Remove from current batch</button><button type="button" class="tool-button" data-factory-material-control="toggle-window">${mode}</button></div>`}

function factoryMaterialSortValue(row,key){if(key==="filename")return String(row.filename||"").toLowerCase();if(key==="type")return String(row.file_type||"").toLowerCase();if(key==="batch")return String(row.batch_id||"").toLowerCase();if(key==="uploaded")return Date.parse(row.uploaded_at||row.created_at||"")||0;if(key==="extraction")return String(row.extraction_status||"").toLowerCase();if(key==="chars")return Number(row.extracted_character_count||0);return String(row.filename||"").toLowerCase()}

function factorySortedMaterials(materials){const key=state.factoryMaterialSortKey||"uploaded",dir=state.factoryMaterialSortDir||-1;return [...materials].sort((a,b)=>{const av=factoryMaterialSortValue(a,key),bv=factoryMaterialSortValue(b,key),primary=av>bv?1:av<bv?-1:0;if(primary!==0)return primary*dir;const af=String(a.filename||"").toLowerCase(),bf=String(b.filename||"").toLowerCase();return af>bf?1:af<bf?-1:0})}

function factoryMaterialSortLabel(){const labels={filename:"Filename",type:"Type",batch:"Batch",uploaded:"Uploaded time",extraction:"Extraction",chars:"Chars"},key=state.factoryMaterialSortKey||"uploaded",arrow=(state.factoryMaterialSortDir||-1)===1?"&uarr;":"&darr;";return `Sorted by: ${labels[key]||"Uploaded time"} ${arrow}`}

function factoryMaterialSortHeader(label,key){const active=(state.factoryMaterialSortKey||"uploaded")===key,arrow=active?((state.factoryMaterialSortDir||-1)===1?" &uarr;":" &darr;"):"";return `<button type="button" class="factory-sort-button ${active?"active":""}" data-factory-material-sort="${key}">${UI.escapeHtml(label)}${arrow}</button>`}

function factoryMaterialRows(materials){const selected=new Set(state.selectedFactoryMaterialIds||[]);return factorySortedMaterials(materials).map(x=>`<tr><td><input type="checkbox" data-factory-material-id="${UI.escapeHtml(String(x.material_id||""))}" ${selected.has(String(x.material_id))?"checked":""}></td><td>${UI.escapeHtml(x.filename)}</td><td>${UI.escapeHtml(x.file_type)}</td><td>${UI.escapeHtml(x.batch_id||"")}</td><td>${UI.escapeHtml(x.uploaded_at||"")}</td><td>${UI.escapeHtml(x.extraction_status)}</td><td>${x.extracted_character_count??0}</td><td>${UI.escapeHtml((x.stored_path||"").split(/[\\\\/]/).slice(-1)[0])}</td></tr>`).join("")||'<tr><td colspan="8">No intake materials uploaded.</td></tr>'}

function factoryMaterialTable(materials){const headers=["Select",factoryMaterialSortHeader("Filename","filename"),factoryMaterialSortHeader("Type","type"),factoryMaterialSortHeader("Batch","batch"),factoryMaterialSortHeader("Uploaded","uploaded"),factoryMaterialSortHeader("Extraction","extraction"),factoryMaterialSortHeader("Chars","chars"),"Stored"];return `<div class="work-table-wrap"><table class="work-table factory-intake-table"><thead><tr>${headers.map(x=>`<th>${x}</th>`).join("")}</tr></thead><tbody>${factoryMaterialRows(materials)}</tbody></table></div>`}

function factoryMaterialLibraryBody(materials,counts){return `<div class="factory-material-library ${state.factoryMaterialWindowExpanded?"expanded":"compact"}"><div class="factory-material-controls">${UI.MetricCard({label:"Active count",value:String(counts.current_active_strategy_count??"N/A"),detail:"backend state, not hardcoded",tone:"positive"})}<form id="strategyFactoryUploadForm" class="factory-upload-form"><input id="strategyFactoryFiles" type="file" multiple accept=".pdf,.txt,.md,.csv,.xlsx"><button class="tool-button" type="submit" ${state.strategyFactoryBusy?"disabled":""}>Upload</button><button class="tool-button" type="button" id="strategyFactoryRun" ${state.strategyFactoryBusy?"disabled":""}>Run Selected Batch</button></form>${factoryMaterialSelectionToolbar(materials)}<div class="factory-sort-label">${factoryMaterialSortLabel()}</div></div><div class="factory-material-window">${factoryMaterialTable(materials)}</div></div>`}

function selectedFactoryCandidate(f){const candidates=f.candidates||[];return candidates.find(x=>x.strategy_id===state.selectedFactoryCandidateId)||candidates[0]||f.latest_candidate||null}

function strategyFactoryPage(){const f=factoryPayload(),materials=f.intake?.materials||[],candidate=selectedFactoryCandidate(f),candidates=f.candidates?.length?f.candidates:(candidate?[candidate]:[]),counts=f.backend_counts||{},portfolio=f.candidate_portfolio||[],drafts=f.allocation_drafts||[],applied=f.applied_paper_strategies||[];return `<main class="main-stage"><div class="page workflow-page strategy-factory-page readable-layout">${pageTitle("Strategy Factory","AI strategy discovery plugin: selected material batch to candidate artifact lineage")}${secondaryStageNote("Strategy Factory safety boundary",[["PROTOTYPE_ONLY","Research candidates are not live or institutionally validated strategies."],["BATCH_SCOPE","Run Selected Batch uses only checked materials; historical uploads stay in the library."],["USER_CONFIRMATION","Paper apply still requires explicit confirmation; brokerage execution remains disabled."]])}${factorySection("Pipeline Status Strip","Explicit statuses: NOT_STARTED / QUEUED / RUNNING / COMPLETED / FAILED / BLOCKED",factoryWorkflowStrip(f)+factoryStatusBanner(f)+factoryStageStatusPanel(f))}${factorySection("Data Status","Provider availability for current-run testability",factoryDataStatusPanel(f))}${factorySection("Full Pipeline","Current-run backtest, ML diagnostics, and evidence report",factoryFullPipelinePanel(f))}${factorySection("Variant Ranking","Ranked copper variants from existing Gate 3B/Gate 4 artifacts",factoryVariantReviewPanel(f))}${factorySection("Material Library / Inbox + Current Batch",`${materials.length} material(s)`,factoryMaterialLibraryBody(materials,counts))}${factoryMaterialAnalysis(materials)}${factoryExtractedIdeasPanel(candidate)}${factorySection("Candidate Outputs","Real alpha candidates first; prototype seed fallback only",`${factoryCandidateOutputPanel(candidates,portfolio,drafts)}${factoryCandidateDetailPanel(candidate,portfolio,drafts,applied)}`)}${factorySection("Candidate Portfolio / Allocation / Paper Apply","Candidate draft does not change active strategy count; confirmed paper apply does",`<div class="factory-three-column"><div>${UI.SectionHeader({title:"Candidate Portfolio list",meta:"Clickable operational rows"})}${factoryCandidatePortfolioPanel(portfolio,candidate)}</div><div>${UI.SectionHeader({title:"Allocation draft / risk impact",meta:"No automatic application"})}${factoryAllocationPanel(drafts)}</div><div>${UI.SectionHeader({title:"Paper application state",meta:"Combined recompute artifact"})}${factoryPaperPanel(applied,f.combined_recompute)}</div></div>`)}</div></main>`}

if(!window.__strategyFactoryViewDelegated){window.__strategyFactoryViewDelegated=true;document.addEventListener("click",e=>{const view=e.target.closest?.("[data-factory-view]"),tab=e.target.closest?.("[data-factory-detail-tab]");if(view&&state.selectedPage==="Strategy Factory"){e.preventDefault();e.stopPropagation();factorySetCandidate(view.dataset.strategyId||state.strategyFactory?.latest_candidate?.strategy_id||"",view.dataset.factoryView||"Overview");factoryRenderStable()}if(tab&&state.selectedPage==="Strategy Factory"){e.preventDefault();e.stopPropagation();state.selectedFactoryDetailTab=tab.dataset.factoryDetailTab;factoryRenderStable()}})}

if(!window.__strategyFactoryMaterialSortDelegated){window.__strategyFactoryMaterialSortDelegated=true;document.addEventListener("click",e=>{const b=e.target.closest?.("[data-factory-material-sort]");if(!b||state.selectedPage!=="Strategy Factory")return;e.preventDefault();e.stopPropagation();state.factoryMaterialLibraryExpanded=true;const key=b.dataset.factoryMaterialSort;if(state.factoryMaterialSortKey===key)state.factoryMaterialSortDir=(state.factoryMaterialSortDir||-1)*-1;else{state.factoryMaterialSortKey=key;state.factoryMaterialSortDir=key==="uploaded"||key==="chars"?-1:1}factoryRenderStable()})}

if(!window.__strategyFactoryVariantDelegated){window.__strategyFactoryVariantDelegated=true;document.addEventListener("click",e=>{if(e.target.closest?.("[data-factory-report-url]"))return;const row=e.target.closest?.("[data-factory-variant-id]");if(!row||state.selectedPage!=="Strategy Factory")return;e.preventDefault();e.stopPropagation();state.selectedFactoryVariantId=row.dataset.factoryVariantId||"";factoryRenderStable()})}

async function factoryOpenInlineReport(button){const snap=factoryViewportSnapshot(),url=button.dataset.factoryReportUrl,title=button.dataset.factoryReportTitle||"Strategy Factory Report",variantId=button.dataset.factoryReportVariant||"",path=button.dataset.factoryReportPath||url;if(!url){state.selectedFactoryWorkspaceTab="Evidence";state.selectedFactoryReport={status:"ERROR",title,error:"Report URL unavailable.",path,variantName:"Unavailable"};factoryRenderStable();factoryRestoreViewport(snap);return}const f=factoryPayload(),variant=(factoryVariantReviewPayload(f).variant_cards||[]).find(x=>x.variant_id===variantId)||selectedFactoryVariant(f)||{};state.selectedFactoryVariantId=variantId||state.selectedFactoryVariantId;state.selectedFactoryWorkspaceTab="Evidence";state.selectedFactoryReport={status:"LOADING",title,path,variantName:variant.variant_name||variant.variant_id||"Variant report"};factoryRenderStable();factoryRestoreViewport(snap);try{const r=await fetch(`${url}${url.includes("?")?"&":"?"}ts=${Date.now()}`,{cache:"no-store",headers:{"Cache-Control":"no-store"}}),text=await r.text();if(!r.ok)throw new Error(text||`Report request failed (${r.status})`);state.selectedFactoryReport={status:"COMPLETED",title,path,content:text,variantName:variant.variant_name||variant.variant_id||"Variant report"}}catch(err){state.selectedFactoryReport={status:"ERROR",title,path,error:err.message||"Unable to load report.",variantName:variant.variant_name||variant.variant_id||"Variant report"}}finally{factoryRenderStable();factoryRestoreViewport(snap)}}

if(!window.__strategyFactoryReportDelegated){window.__strategyFactoryReportDelegated=true;document.addEventListener("click",e=>{const b=e.target.closest?.("[data-factory-report-url]");if(!b||state.selectedPage!=="Strategy Factory")return;e.preventDefault();e.stopPropagation();factoryOpenInlineReport(b)})}

function factoryCurrentRunSummaryPanel(f,candidate,portfolio,drafts,applied){const run=f.latest_run||candidate?.current_run||{},artifacts=run.generated_artifacts||{},review=factoryVariantReviewPayload(f),best=review.best_variant||{},selectedNames=run.selected_material_names||candidate?.current_run?.selected_material_names||[],folder=artifacts.output_folder||artifacts.run_folder||run.output_folder||run.run_folder||run.run_manifest_path||"Unavailable",recommendation=best.final_recommendation||best.recommendation||candidate?.recommendation||candidate?.decision_status||"Unavailable",allowed=best.candidate_allowed===true,next=allowed?"Review evidence and require explicit admission approval before portfolio workflow.":"Review evidence; Candidate Portfolio admission is disabled until stronger non-proxy validation exists.";return `<section class="panel factory-section factory-current-run-summary">${UI.SectionHeader({title:"Current Run Summary",meta:"Operator workflow focus"})}<div class="factory-detail-grid readable"><div><span>current_run_id</span><b>${UI.escapeHtml(run.current_run_id||run.run_id||review.run_id||"Unavailable")}</b></div><div><span>Selected materials</span><b>${UI.escapeHtml(selectedNames.join(", ")||"Unavailable")}</b></div><div><span>Latest output folder</span><b>${UI.escapeHtml(folder)}</b></div><div><span>Full Pipeline status</span><b>${UI.escapeHtml(factoryStageLabel("EVIDENCE_REPORT_CREATED"))}</b></div><div><span>Best variant</span><b>${UI.escapeHtml(best.variant_name||best.variant_id||"Unavailable")}</b></div><div><span>Recommendation</span><b>${UI.escapeHtml(recommendation)}</b></div><div><span>candidate_allowed</span><b>${UI.escapeHtml(String(allowed))}</b></div><div><span>Next action</span><b>${UI.escapeHtml(next)}</b></div></div><div class="factory-operator-actions"><button class="tool-button" type="button" data-factory-full-run ${state.strategyFactoryBusy?"disabled":""}>Run Full Pipeline</button><button class="tool-button factory-disabled" type="button" disabled title="${UI.escapeHtml(review.candidate_gating?.reason||"candidate_allowed=false")}">Add to Candidate Portfolio disabled</button><span class="factory-artifact-note">Candidate portfolio ${portfolio.length}; allocation drafts ${drafts.length}; paper apply ${applied.length}.</span></div></section>`}

function factoryFullPipelineStatusCompact(f){return factorySection("Full Pipeline Status","Current-run stages and job state",`${factoryFullPipelinePanel(f)}<details class="factory-debug-collapsed"><summary>Stage status details</summary>${factoryWorkflowStrip(f)}${factoryStatusBanner(f)}${factoryStageStatusPanel(f)}</details>`)}

function factoryLatestEvidencePanel(f,candidate){const review=factoryVariantReviewPayload(f),selected=selectedFactoryVariant(f),run=f.latest_run||candidate?.current_run||{},artifacts=run.generated_artifacts||{},links=[];if(review.ranking_report_url)links.push(`<a class="tool-button" href="${UI.escapeHtml(review.ranking_report_url)}" target="_blank" rel="noreferrer">Open Variant Ranking Report</a>`);if(selected?.evidence_report_url)links.push(`<a class="tool-button" href="${UI.escapeHtml(selected.evidence_report_url)}" target="_blank" rel="noreferrer">Open Selected Variant Evidence</a>`);if(candidate?.report_url)links.push(`<a class="tool-button" href="${UI.escapeHtml(candidate.report_url)}" target="_blank" rel="noreferrer">Open Current Run Evidence</a>`);return factorySection("Latest Evidence / Report Links","Reports are links to existing artifacts, not regenerated output",`<div class="factory-actions">${links.join("")||'<span class="factory-artifact-note">No evidence links available yet.</span>'}</div><div class="factory-detail-grid readable"><div><span>Ranking report path</span><b>${UI.escapeHtml(review.ranking_report_path||"Unavailable")}</b></div><div><span>Current evidence artifact</span><b>${UI.escapeHtml(artifacts.evidence_report||candidate?.report_path||"Unavailable")}</b></div><div><span>Selected variant evidence</span><b>${UI.escapeHtml(selected?.evidence_report_path||"Unavailable")}</b></div></div>`)}

function factoryCurrentRunIdeasPanel(candidate){const run=candidate?.current_run||factoryPayload().latest_run||{},ideas=run.generated_artifacts?.candidate_ideas||candidate?.report_sections?.["Extracted Strategy Ideas"]||[],names=run.selected_material_names||[];return factorySection("Current Run Ideas","Only selected-batch ideas are shown by default",`<div class="factory-ideas-grid"><article><h3>Selected material source</h3><p>${UI.escapeHtml(names.join(", ")||"Unavailable")}</p></article><article><h3>Generated current-run ideas</h3><ul>${Array.isArray(ideas)&&ideas.length?ideas.map(x=>`<li>${UI.escapeHtml(String(x))}</li>`).join(""):"<li>No current-run ideas available.</li>"}</ul></article><details class="factory-debug-collapsed"><summary>Global idea registry debug</summary><p>${UI.escapeHtml(String(factoryPayload().stage_counts?.candidate_ideas??0))} global idea artifacts available. Open source artifacts only when debugging lineage.</p></details></div>`)}

function factoryCollapsedMaterialLibrary(materials,counts){return factorySection("Material Library","Compact by default; expand only for upload, selection, and batch runs",`<details class="factory-collapsed-section"><summary>Material Library / Current Batch (${materials.length})</summary>${factoryMaterialLibraryBody(materials,counts)}</details>`)}

function factoryCollapsedCandidateOutputs(candidates,portfolio,drafts){const current=factoryCurrentRunCandidates(candidates),historical=factoryHistoricalAlphaCandidates(candidates),prototype=factoryPrototypeCandidates(candidates);return factorySection("Candidate Outputs","Current run first; historical and prototype fallback are collapsed",`<section class="factory-current-output-compact"><h3>Current Run Candidates / Ideas</h3>${current.length?factoryCandidateCards(current,portfolio,drafts):'<p>No current selected-batch candidate loaded.</p>'}</section><details class="factory-collapsed-section"><summary>Historical Alpha Candidates (${historical.length})</summary><div class="factory-selection-toolbar"><strong>Historical Alpha Candidates</strong><span>${historical.length} total</span><label class="search-control"><span aria-hidden="true">&#9906;</span><input type="search" placeholder="Search/filter is local review only" aria-label="Search historical candidates"></label><span class="factory-artifact-note">View all</span></div><div class="factory-candidate-list">${factoryCandidateCards(historical,portfolio,drafts)}</div></details>${prototype.length?`<details class="factory-collapsed-section"><summary>Prototype Seed Fallback (${prototype.length})</summary><p>Fallback only; not derived from current selected materials.</p><div class="factory-candidate-list prototype-fallback">${factoryCandidateCards(prototype,portfolio,drafts)}</div></details>`:""}`)}

function factoryCandidatePortfolioCompact(portfolio,candidate,drafts,applied,f){const review=factoryVariantReviewPayload(f),allowed=review.best_variant?.candidate_allowed===true,disabledReason=allowed?"Explicit approval still required before admission.":review.candidate_gating?.reason||"candidate_allowed=false for current copper variants.";return factorySection("Candidate Portfolio / Paper Apply","Compact governance state; no ledger mutation",`<div class="factory-detail-grid readable"><div><span>Candidate portfolio count</span><b>${portfolio.length}</b></div><div><span>Allocation draft status</span><b>${drafts.length?`${drafts.length} draft(s)`:"No allocation draft"}</b></div><div><span>Paper apply status</span><b>${applied.length?`${applied.length} applied artifact(s)`:"Not applied"}</b></div><div><span>Disabled reason</span><b>${UI.escapeHtml(disabledReason)}</b></div></div><details class="factory-collapsed-section"><summary>View candidate portfolio drafts</summary>${factoryCandidatePortfolioPanel(portfolio,candidate)}</details>`)}

function strategyFactoryPage(){const f=factoryPayload(),materials=f.intake?.materials||[],candidate=selectedFactoryCandidate(f),candidates=f.candidates?.length?f.candidates:(candidate?[candidate]:[]),counts=f.backend_counts||{},portfolio=f.candidate_portfolio||[],drafts=f.allocation_drafts||[],applied=f.applied_paper_strategies||[];return `<main class="main-stage"><div class="page workflow-page strategy-factory-page readable-layout operator-workflow">${pageTitle("Strategy Factory","Current-run evidence workflow: run summary, variant ranking, selected evidence, then supporting libraries")}${secondaryStageNote("Strategy Factory safety boundary",[["PROTOTYPE_ONLY","Research candidates are not live or institutionally validated strategies."],["BATCH_SCOPE","Run Selected Batch uses only checked materials; historical uploads stay collapsed."],["USER_CONFIRMATION","Portfolio admission remains disabled when candidate_allowed=false; brokerage execution remains disabled."]])}${factoryCurrentRunSummaryPanel(f,candidate,portfolio,drafts,applied)}${factoryFullPipelineStatusCompact(f)}${factorySection("Variant Ranking / Best Variant","Prominent review of existing Gate 3B/Gate 4 artifacts",factoryVariantReviewPanel(f))}${factorySection("Selected Variant Detail","Click a ranking row to inspect one variant",factoryVariantDetail(f))}${factoryLatestEvidencePanel(f,candidate)}${factoryCandidatePortfolioCompact(portfolio,candidate,drafts,applied,f)}${factoryCurrentRunIdeasPanel(candidate)}${factoryCollapsedMaterialLibrary(materials,counts)}${factoryCollapsedCandidateOutputs(candidates,portfolio,drafts)}</div></main>`}

function factoryVariantReviewPanel(f){const review=factoryVariantReviewPayload(f);return `${factoryVariantRankingPanel(f)}${factoryVariantTable(f)}${review.ranking_report_path?`<p class="factory-artifact-note">Ranking artifact: ${UI.escapeHtml(review.ranking_report_path)}</p>`:""}`}

function factoryRunArtifacts(f){return f.latest_run?.generated_artifacts||{}}

function factoryRunId(f){const picked=selectedFactoryPickerCandidate(f);return picked?.run_id||picked?.source_run_id||f.latest_run?.current_run_id||f.latest_run?.run_id||factoryVariantReviewPayload(f).run_id||"Unavailable"}

function factoryRunHasArtifact(f,key){return !!factoryRunArtifacts(f)[key]}

function factoryPipelineSummary(f){const review=factoryVariantReviewPayload(f),best=review.best_variant||{},completed=factoryRunHasArtifact(f,"job_status")&&factoryRunHasArtifact(f,"backtest_run")&&factoryRunHasArtifact(f,"ml_diagnostics_run")&&factoryRunHasArtifact(f,"evidence_report");return {run_id:factoryRunId(f),status:completed?"COMPLETED":"NOT_STARTED",backtest:factoryRunHasArtifact(f,"backtest_run")?"COMPLETED":"NOT_STARTED",ml:factoryRunHasArtifact(f,"ml_diagnostics_run")?"COMPLETED":"NOT_STARTED",evidence:factoryRunHasArtifact(f,"evidence_report")?"COMPLETED":"NOT_STARTED",recommendation:best.final_recommendation||best.recommendation||"Unavailable",reason:completed?"Latest current-run job_status and required artifacts are present.":"Latest current-run job_status or required artifacts are missing.",candidate_allowed:best.candidate_allowed===true}}

function factoryBestVariantCard(f){const picked=selectedFactoryPickerCandidate(f);if(picked)return picked;const review=factoryVariantReviewPayload(f),best=review.best_variant||{};return (review.variant_cards||[]).find(x=>x.variant_id===best.variant_id)||null}

function factoryAdmissionDisabledReason(){return "Candidate admission disabled: proxy-only data and robustness/risk limitations."}

function factoryRunFolderLabel(f){const id=factoryRunId(f);return id==="Unavailable"?"Unavailable":`strategy_factory/runs/${id}`}

function factoryArtifactPathDetails(f,extra=""){const a=factoryRunArtifacts(f);return `<details class="factory-debug-collapsed"><summary>Show artifact paths</summary><div class="factory-detail-grid readable">${["job_status","run_log","backtest_run","ml_diagnostics_run","evidence_report"].map(k=>`<div><span>${UI.escapeHtml(k)}</span><b>${UI.escapeHtml(a[k]||"Unavailable")}</b></div>`).join("")}${extra}</div></details>`}

function factoryFullPipelinePanel(f){const p=factoryPipelineSummary(f),best=factoryVariantReviewPayload(f).best_variant||{};return `<section class="factory-data-status-panel factory-full-pipeline-operator"><div><span>Full Pipeline status</span><b>${UI.escapeHtml(p.status)}</b><em>${UI.escapeHtml(p.reason)}</em></div><div><span>Backtest</span><b>${UI.escapeHtml(p.backtest)}</b></div><div><span>ML</span><b>${UI.escapeHtml(p.ml)}</b></div><div><span>Evidence</span><b>${UI.escapeHtml(p.evidence)}</b></div><div><span>Recommendation</span><b>${UI.escapeHtml(p.recommendation)}</b><em>${UI.escapeHtml(best.reason||"")}</em></div><button type="button" class="tool-button" data-factory-full-run ${state.strategyFactoryBusy||!f.latest_run?"disabled":""}>Run Full Pipeline</button></section>`}

function factoryCurrentRunSummaryPanel(f,candidate,portfolio,drafts,applied){const run=f.latest_run||candidate?.current_run||{},review=factoryVariantReviewPayload(f),best=review.best_variant||{},selectedNames=run.selected_material_names||candidate?.current_run?.selected_material_names||[],p=factoryPipelineSummary(f),allowed=p.candidate_allowed,next=allowed?"Evidence supports review, but admission still requires explicit governance approval.":factoryAdmissionDisabledReason();return `<section class="panel factory-section factory-current-run-summary">${UI.SectionHeader({title:"Current Run Summary",meta:"Latest current_run/job_status source"})}<div class="factory-detail-grid readable"><div><span>current_run_id</span><b>${UI.escapeHtml(p.run_id)}</b></div><div><span>Selected materials</span><b>${UI.escapeHtml(selectedNames.join(", ")||"Unavailable")}</b></div><div><span>Latest output folder</span><b>${UI.escapeHtml(factoryRunFolderLabel(f))}</b></div><div><span>Full Pipeline status</span><b>${UI.escapeHtml(p.status)}</b></div><div><span>Best variant</span><b>${UI.escapeHtml(best.variant_name||best.variant_id||"Unavailable")}</b></div><div><span>Recommendation</span><b>${UI.escapeHtml(p.recommendation)}</b></div><div><span>candidate_allowed</span><b>${UI.escapeHtml(String(allowed))}</b></div><div><span>Next action</span><b>${UI.escapeHtml(next)}</b></div></div><div class="factory-operator-actions"><button class="tool-button" type="button" data-factory-full-run ${state.strategyFactoryBusy?"disabled":""}>Run Full Pipeline</button><button class="tool-button factory-disabled" type="button" disabled title="${UI.escapeHtml(next)}">Add to Candidate Portfolio disabled</button><span class="factory-artifact-note">Candidate portfolio ${portfolio.length}; allocation drafts ${drafts.length}; paper apply ${applied.length}.</span></div>${factoryArtifactPathDetails(f)}</section>`}

function factoryFullPipelineStatusCompact(f){return factorySection("Full Pipeline Status","Same latest current-run source as summary",`${factoryFullPipelinePanel(f)}<details class="factory-debug-collapsed"><summary>Global stage status details</summary>${factoryWorkflowStrip(f)}${factoryStatusBanner(f)}${factoryStageStatusPanel(f)}</details>`)}

function factoryVariantRankingPanel(f){const review=factoryVariantReviewPayload(f),best=review.best_variant||{},bestCard=factoryBestVariantCard(f),gating=review.candidate_gating||{},report=review.ranking_report_url?`<a class="tool-button" href="${UI.escapeHtml(review.ranking_report_url)}" target="_blank" rel="noreferrer">Open Ranking Report</a>`:`<span class="factory-artifact-note">Ranking report unavailable</span>`,evidence=bestCard?.evidence_report_url?`<a class="tool-button" href="${UI.escapeHtml(bestCard.evidence_report_url)}" target="_blank" rel="noreferrer">Open Best Variant Evidence</a>`:`<span class="factory-artifact-note">Best variant evidence unavailable</span>`;return `<section class="factory-data-status-panel factory-variant-ranking-panel primary-result"><div><span>Best variant</span><b>${UI.escapeHtml(best.variant_name||best.variant_id||"Unavailable")}</b><em>${UI.escapeHtml(best.variant_id||"")}</em></div><div><span>Evidence score</span><b>${factoryVariantMetricValue(best.evidence_score,"ratio")}</b><em>Composite evidence, not Sharpe-only</em></div><div><span>Recommendation</span><b>${UI.escapeHtml(best.final_recommendation||best.recommendation||"Unavailable")}</b><em>${UI.escapeHtml(best.reason||"")}</em></div><div><span>candidate_allowed</span><b>${UI.escapeHtml(String(!!best.candidate_allowed))}</b><em>${UI.escapeHtml(gating.reason||factoryAdmissionDisabledReason())}</em></div><div><span>Why not Candidate</span><b>${UI.escapeHtml(factoryAdmissionDisabledReason())}</b></div><div><span>Reports</span><span class="factory-actions">${report}${evidence}</span></div><button type="button" class="tool-button factory-disabled" disabled title="${UI.escapeHtml(factoryAdmissionDisabledReason())}">Add to Candidate Portfolio disabled</button></section>`}

function factoryCurrentRunIdeasPanel(candidate){const run=factoryPayload().latest_run||candidate?.current_run||{},ideas=run.generated_artifacts?.candidate_ideas||candidate?.report_sections?.["Extracted Strategy Ideas"]||[],names=run.selected_material_names||[],top=Array.isArray(ideas)?ideas.slice(0,3):[];return factorySection("Current Run Ideas",`${Array.isArray(ideas)?ideas.length:0} generated idea(s); cards collapsed by default`,`<div class="factory-detail-grid readable"><div><span>Idea count</span><b>${Array.isArray(ideas)?ideas.length:0}</b></div><div><span>Top 3 ideas</span><b>${UI.escapeHtml(top.join(", ")||"Unavailable")}</b></div><div><span>Source material</span><b>${UI.escapeHtml(names.join(", ")||"Unavailable")}</b></div></div><details class="factory-collapsed-section"><summary>View all current-run ideas</summary><ul>${Array.isArray(ideas)&&ideas.length?ideas.map(x=>`<li>${UI.escapeHtml(String(x))}</li>`).join(""):"<li>No current-run ideas available.</li>"}</ul></details><details class="factory-debug-collapsed"><summary>Global idea registry debug</summary><p>${UI.escapeHtml(String(factoryPayload().stage_counts?.candidate_ideas??0))} global idea artifacts available.</p></details>`)}

function factoryCollapsedMaterialLibrary(materials,counts){const selected=(state.selectedFactoryMaterialIds||[]).length;return factorySection("Material Library","Collapsed after current run exists",`<details class="factory-collapsed-section"><summary>Material Library / Current Batch (${materials.length} materials) | Selected: ${selected} | Expand</summary>${factoryMaterialLibraryBody(materials,counts)}</details>`)}

function factoryCollapsedCandidateOutputs(candidates,portfolio,drafts){const current=factoryCurrentRunCandidates(candidates),historical=factoryHistoricalAlphaCandidates(candidates),prototype=factoryPrototypeCandidates(candidates);return factorySection("Collapsed Candidate Archives","Intermediate/stale cards are hidden by default",`<details class="factory-collapsed-section"><summary>Current Run Candidate Cards (${current.length})</summary><p>Intermediate candidate cards are hidden to keep the operator view focused on variant ranking.</p><div class="factory-candidate-list current-run-output">${factoryCandidateCards(current,portfolio,drafts)}</div></details><details class="factory-collapsed-section"><summary>Historical Alpha Candidates (${historical.length})</summary><div class="factory-selection-toolbar"><strong>Historical Alpha Candidates</strong><span>${historical.length} total</span><label class="search-control"><span aria-hidden="true">&#9906;</span><input type="search" placeholder="Search/filter is local review only" aria-label="Search historical candidates"></label><span class="factory-artifact-note">View all</span></div><div class="factory-candidate-list">${factoryCandidateCards(historical,portfolio,drafts)}</div></details><details class="factory-collapsed-section"><summary>Prototype Seed Fallback (${prototype.length})</summary><p>Fallback only; hidden whenever current_run or variant ranking exists.</p><div class="factory-candidate-list prototype-fallback">${factoryCandidateCards(prototype,portfolio,drafts)}</div></details>`)}

function factoryCandidatePortfolioCompact(portfolio,candidate,drafts,applied,f){const allowed=factoryPipelineSummary(f).candidate_allowed,disabledReason=allowed?"Explicit approval still required before admission.":factoryAdmissionDisabledReason();return factorySection("Candidate Portfolio / Paper Apply","Compact and honest; no ledger mutation",`<div class="factory-detail-grid readable"><div><span>Candidate portfolio count</span><b>${portfolio.length}</b></div><div><span>Allocation draft status</span><b>${drafts.length?`${drafts.length} draft(s)`:"No allocation draft"}</b></div><div><span>Paper apply status</span><b>${applied.length?`${applied.length} applied artifact(s)`:"Not applied"}</b></div><div><span>Admission disabled reason</span><b>${UI.escapeHtml(disabledReason)}</b></div></div><button class="tool-button factory-disabled" type="button" disabled title="${UI.escapeHtml(disabledReason)}">Add to Candidate Portfolio disabled</button><details class="factory-collapsed-section"><summary>View candidate portfolio drafts</summary>${factoryCandidatePortfolioPanel(portfolio,candidate)}</details>`)}

function factoryLatestEvidencePanel(f,candidate){const review=factoryVariantReviewPayload(f),bestCard=factoryBestVariantCard(f),selected=selectedFactoryVariant(f),links=[];if(review.ranking_report_url)links.push(`<a class="tool-button" href="${UI.escapeHtml(review.ranking_report_url)}" target="_blank" rel="noreferrer">Open Ranking Report</a>`);if(bestCard?.evidence_report_url)links.push(`<a class="tool-button" href="${UI.escapeHtml(bestCard.evidence_report_url)}" target="_blank" rel="noreferrer">Open Best Variant Evidence</a>`);if(selected?.evidence_report_url&&selected.variant_id!==bestCard?.variant_id)links.push(`<a class="tool-button" href="${UI.escapeHtml(selected.evidence_report_url)}" target="_blank" rel="noreferrer">Open Selected Variant Evidence</a>`);return factorySection("Latest Evidence / Report Links","No raw paths by default",`<div class="factory-actions">${links.join("")||'<span class="factory-artifact-note">No evidence links available yet.</span>'}</div>${factoryArtifactPathDetails(f,`<div><span>ranking_report</span><b>${UI.escapeHtml(review.ranking_report_path||"Unavailable")}</b></div><div><span>selected_variant_evidence</span><b>${UI.escapeHtml(selected?.evidence_report_path||"Unavailable")}</b></div>`)}`)}

function strategyFactoryPage(){const f=factoryPayload(),materials=f.intake?.materials||[],candidate=selectedFactoryCandidate(f),candidates=f.candidates?.length?f.candidates:(candidate?[candidate]:[]),counts=f.backend_counts||{},portfolio=f.candidate_portfolio||[],drafts=f.allocation_drafts||[],applied=f.applied_paper_strategies||[];return `<main class="main-stage"><div class="page workflow-page strategy-factory-page readable-layout operator-workflow">${pageTitle("Strategy Factory","Operator view: latest run, best variant, recommendation, evidence, then collapsed archives")}${secondaryStageNote("Strategy Factory safety boundary",[["PROTOTYPE_ONLY","Research candidates are not live or institutionally validated strategies."],["BATCH_SCOPE","Run Selected Batch uses only checked materials; historical uploads stay collapsed."],["USER_CONFIRMATION","Candidate admission remains disabled when candidate_allowed=false; brokerage execution remains disabled."]])}${factoryCurrentRunSummaryPanel(f,candidate,portfolio,drafts,applied)}${factorySection("Variant Ranking / Best Variant","Primary result from existing Gate 3B/Gate 4 artifacts",factoryVariantReviewPanel(f))}${factoryFullPipelineStatusCompact(f)}${factorySection("Selected Variant Detail","Click one ranking row to inspect exactly one variant",factoryVariantDetail(f))}${factoryLatestEvidencePanel(f,candidate)}${factoryCandidatePortfolioCompact(portfolio,candidate,drafts,applied,f)}${factoryCurrentRunIdeasPanel(candidate)}${factoryCollapsedMaterialLibrary(materials,counts)}${factoryCollapsedCandidateOutputs(candidates,portfolio,drafts)}</div></main>`}

function factoryEvidenceButton(label,url,path,title,variantId=""){if(!url)return `<span class="factory-artifact-note">${UI.escapeHtml(label)} unavailable</span>`;return `<button type="button" class="tool-button" data-factory-report-url="${UI.escapeHtml(url)}" data-factory-report-path="${UI.escapeHtml(path||url)}" data-factory-report-title="${UI.escapeHtml(title||label)}" data-factory-report-variant="${UI.escapeHtml(variantId)}">${UI.escapeHtml(label)}</button>`}

function factoryMarkdownPreview(text){const body=UI.escapeHtml(text||"").replace(/^### (.*)$/gm,"<h4>$1</h4>").replace(/^## (.*)$/gm,"<h3>$1</h3>").replace(/^# (.*)$/gm,"<h2>$1</h2>").replace(/\*\*(.*?)\*\*/g,"<strong>$1</strong>").replace(/\n\n+/g,"</p><p>").replace(/\n/g,"<br>");return `<article class="factory-markdown-preview"><p>${body}</p></article>`}

function factorySelectedEvidencePanel(f){const report=state.selectedFactoryReport||{},selected=selectedFactoryVariant(f)||{},title=report.title||"Selected Evidence",variantName=report.variantName||selected.variant_name||selected.variant_id||"No variant selected",decision=selected.decision?.recommendation||selected.ranking?.final_recommendation||"Unavailable",path=report.path||selected.evidence_report_path||"Unavailable";let body;if(report.status==="LOADING")body=`<div class="na-block"><strong>Loading evidence report</strong><span>${UI.escapeHtml(title)}</span></div>`;else if(report.status==="ERROR")body=`<div class="na-block"><strong>Evidence load error</strong><span>${UI.escapeHtml(report.error||"Unable to load report.")}</span></div>`;else if(report.content)body=factoryMarkdownPreview(report.content);else body=`<div class="na-block"><strong>No evidence report opened yet</strong><span>Click View Evidence or Open Ranking Report to show the report here.</span></div>`;return factorySection("Selected Evidence","Inline report viewer; no new tab and no hash jump",`<div class="factory-detail-grid readable"><div><span>Report</span><b>${UI.escapeHtml(title)}</b></div><div><span>Variant</span><b>${UI.escapeHtml(variantName)}</b></div><div><span>Decision</span><b>${UI.escapeHtml(decision)}</b></div></div>${body}<details class="factory-debug-collapsed"><summary>Show artifact path</summary><div class="factory-detail-grid readable"><div><span>report_path</span><b>${UI.escapeHtml(path)}</b></div></div></details>`)}

function factorySetCandidate(id,tab="Overview"){state.selectedFactoryCandidateId=id||state.strategyFactory?.latest_candidate?.strategy_id||"";state.selectedFactoryDetailTab=tab;state.factoryCandidateWorkspaceVisible=true;state.strategyFactoryStatusMessage=`Viewing ${state.selectedFactoryDetailTab} for ${state.selectedFactoryCandidateId}.`}

function factoryCandidateActionPanel(candidate,portfolio=[],drafts=[],applied=[]){if(!state.factoryCandidateWorkspaceVisible)return factorySection("Candidate Action Panel","Hidden until View Candidate / Backtest / Report / Charts is clicked",`<div class="na-block"><strong>Candidate workspace hidden</strong><span>Current-run candidate cards are collapsed. Expand them only when debugging candidate-level artifacts.</span></div>`);if(!candidate)return factorySection("Candidate Action Panel","No current candidate loaded",`<div class="na-block"><strong>No candidate selected</strong><span>Run or select a current-run candidate first.</span></div>`);const portfolioDraft=portfolio.find(x=>x.strategy_id===candidate.strategy_id)||{},allocation=drafts.find(x=>x.strategy_id===candidate.strategy_id)||{},paper=applied.find(x=>x.strategy_id===candidate.strategy_id)||{};return `<section id="factoryCandidateWorkspace" class="panel factory-section factory-candidate-workspace readable">${UI.SectionHeader({title:"Selected Candidate Workspace",meta:`${UI.escapeHtml(state.selectedFactoryDetailTab||"Overview")} view; candidate-level artifact inspection`})}<article><header><div><strong>${UI.escapeHtml(candidate.name||candidate.strategy_id)}</strong><span>${UI.escapeHtml(candidate.strategy_id)} / ${UI.escapeHtml(candidate.pipeline_stage||"Pipeline unavailable")}</span></div>${factoryBadges(candidate.safety_labels)}</header>${factoryDetailTabs()}<div class="factory-tab-body">${factoryCandidateDetailContent(candidate,portfolioDraft,allocation,paper)}</div></article></section>`}

function factoryVariantRankingPanel(f){const review=factoryVariantReviewPayload(f),best=review.best_variant||{},bestCard=factoryBestVariantCard(f),gating=review.candidate_gating||{},report=factoryEvidenceButton("Open Ranking Report",review.ranking_report_url,review.ranking_report_path,"Variant Ranking Report"),evidence=factoryEvidenceButton("Open Best Variant Evidence",bestCard?.evidence_report_url,bestCard?.evidence_report_path,`${bestCard?.variant_name||best.variant_name||"Best Variant"} Evidence`,bestCard?.variant_id||best.variant_id||"");return `<section class="factory-data-status-panel factory-variant-ranking-panel primary-result"><div><span>Best variant</span><b>${UI.escapeHtml(best.variant_name||best.variant_id||"Unavailable")}</b><em>${UI.escapeHtml(best.variant_id||"")}</em></div><div><span>Evidence score</span><b>${factoryVariantMetricValue(best.evidence_score,"ratio")}</b><em>Composite evidence, not Sharpe-only</em></div><div><span>Recommendation</span><b>${UI.escapeHtml(best.final_recommendation||best.recommendation||"Unavailable")}</b><em>${UI.escapeHtml(best.reason||"")}</em></div><div><span>candidate_allowed</span><b>${UI.escapeHtml(String(!!best.candidate_allowed))}</b><em>${UI.escapeHtml(gating.reason||factoryAdmissionDisabledReason())}</em></div><div><span>Why not Candidate</span><b>${UI.escapeHtml(factoryAdmissionDisabledReason())}</b></div><div><span>Reports</span><span class="factory-actions">${report}${evidence}</span></div><button type="button" class="tool-button factory-disabled" disabled title="${UI.escapeHtml(factoryAdmissionDisabledReason())}">Add to Candidate Portfolio disabled</button></section>`}

function factoryVariantRows(cards){return (cards||[]).map(v=>{const m=v.metrics||{},ml=v.ml_diagnostics||{},r=v.robustness||{},d=v.decision||{},selected=(state.selectedFactoryVariantId||"")===v.variant_id;return `<tr class="${selected?"selected":""}" data-factory-variant-id="${UI.escapeHtml(v.variant_id)}"><td>${UI.escapeHtml(String(v.rank??"N/A"))}</td><td><strong>${UI.escapeHtml(v.variant_name||v.variant_id)}</strong><small>${UI.escapeHtml(v.variant_id)}</small></td><td>${factoryVariantMetricValue(m.sharpe,"ratio")}</td><td>${factoryVariantMetricValue(m.annual_return,"percent")}</td><td>${factoryVariantMetricValue(m.max_drawdown,"percent")}</td><td>${UI.escapeHtml(ml.summary||ml.status||"Unavailable")}</td><td>${UI.escapeHtml(r.overall||r.status||"Unavailable")}</td><td>${UI.escapeHtml(d.recommendation||"Unavailable")}</td><td>${factoryEvidenceButton("View Evidence",v.evidence_report_url,v.evidence_report_path,`${v.variant_name||v.variant_id} Evidence`,v.variant_id)}</td></tr>`}).join("")||'<tr><td colspan="9">No variant ranking artifacts available.</td></tr>'}

function factoryVariantDetail(f){const v=selectedFactoryVariant(f);if(!v)return `<div class="na-block"><strong>No selected variant</strong><span>Run Gate 3B and Gate 4 artifacts before reviewing variants.</span></div>`;const m=v.metrics||{},ml=v.ml_diagnostics||{},r=v.robustness||{},d=v.decision||{},ranking=v.ranking||{},evidence=factoryEvidenceButton("View Evidence",v.evidence_report_url,v.evidence_report_path,`${v.variant_name||v.variant_id} Evidence`,v.variant_id);return `<article class="factory-variant-detail"><header><div><strong>${UI.escapeHtml(v.variant_name||v.variant_id)}</strong><span>${UI.escapeHtml(v.variant_id)} / Rank ${UI.escapeHtml(String(v.rank??"N/A"))} / ${UI.escapeHtml(d.recommendation||"Unavailable")}</span></div><button class="tool-button factory-disabled" disabled title="${UI.escapeHtml(d.reason||factoryAdmissionDisabledReason())}">Candidate admission disabled</button></header><div class="factory-detail-grid readable"><div><span>Thesis</span><b>${UI.escapeHtml(v.thesis||"Unavailable")}</b></div><div><span>Signal</span><b>${UI.escapeHtml(v.signal_formula||"Unavailable")}</b></div><div><span>Universe/proxy</span><b>${UI.escapeHtml((v.universe_or_proxy||[]).join(", ")||"Unavailable")}</b></div><div><span>Benchmark</span><b>${UI.escapeHtml(v.benchmark||"Unavailable")}</b></div><div><span>Features</span><b>${UI.escapeHtml((v.features||[]).join(", ")||"Unavailable")}</b></div><div><span>Evidence score</span><b>${factoryVariantMetricValue(ranking.evidence_score,"ratio")}</b></div><div><span>Sharpe</span><b>${factoryVariantMetricValue(m.sharpe,"ratio")}</b></div><div><span>Annual return</span><b>${factoryVariantMetricValue(m.annual_return,"percent")}</b></div><div><span>Max drawdown</span><b>${factoryVariantMetricValue(m.max_drawdown,"percent")}</b></div><div><span>ML summary</span><b>${UI.escapeHtml(ml.summary||"Unavailable")}</b></div><div><span>Robustness</span><b>${UI.escapeHtml([r.overall,r.cost_sensitivity,r.lookback_sensitivity,r.benchmark_status].filter(Boolean).join(" / ")||"Unavailable")}</b></div><div><span>Decision reason</span><b>${UI.escapeHtml(d.reason||ranking.reason||"Unavailable")}</b></div><div><span>Evidence report</span>${evidence}</div></div></article>`}

function factoryLatestEvidencePanel(f,candidate){const review=factoryVariantReviewPayload(f),bestCard=factoryBestVariantCard(f),selected=selectedFactoryVariant(f),buttons=[];buttons.push(factoryEvidenceButton("Open Ranking Report",review.ranking_report_url,review.ranking_report_path,"Variant Ranking Report"));buttons.push(factoryEvidenceButton("Open Best Variant Evidence",bestCard?.evidence_report_url,bestCard?.evidence_report_path,`${bestCard?.variant_name||"Best Variant"} Evidence`,bestCard?.variant_id||""));if(selected?.evidence_report_url&&selected.variant_id!==bestCard?.variant_id)buttons.push(factoryEvidenceButton("Open Selected Variant Evidence",selected.evidence_report_url,selected.evidence_report_path,`${selected.variant_name||selected.variant_id} Evidence`,selected.variant_id));return factorySection("Latest Evidence / Report Links","Reports open inline below; no raw paths by default",`<div class="factory-actions">${buttons.join("")}</div>${factoryArtifactPathDetails(f,`<div><span>ranking_report</span><b>${UI.escapeHtml(review.ranking_report_path||"Unavailable")}</b></div><div><span>selected_variant_evidence</span><b>${UI.escapeHtml(selected?.evidence_report_path||"Unavailable")}</b></div>`)}`)}

function factoryCandidatePortfolioPanel(portfolio,candidate){return `<div class="factory-candidate-portfolio-list">${portfolio.map(x=>{const selected=(state.selectedFactoryCandidateId||candidate?.strategy_id)===x.strategy_id,hasBacktest=!!candidate?.backtest_metrics;return `<article class="factory-portfolio-row readable ${selected?"selected":""}" data-factory-select="${UI.escapeHtml(x.strategy_id)}" tabindex="0" role="button" aria-label="View candidate ${UI.escapeHtml(x.strategy_id)}"><header><div><strong>${UI.escapeHtml(x.candidate_name||x.strategy_id)}</strong><span>${UI.escapeHtml(x.strategy_id)} / ${UI.escapeHtml(x.status)}</span></div><b>${UI.escapeHtml(candidate?.pipeline_stage||"Pipeline")}</b></header><p>${UI.escapeHtml(x.strategy_thesis||"No thesis recorded.")}</p><div class="factory-portfolio-metrics"><span>${hasBacktest?`Sharpe ${factoryMetric(candidate.backtest_metrics.sharpe,"ratio")}`:factoryStageState("BACKTEST_RUN").status}</span><span>${hasBacktest?`Return ${factoryMetric(candidate.backtest_metrics.annual_return,"percent")}`:"Metrics locked"}</span><span>${UI.escapeHtml(x.updated_at||x.created_at||"Timestamp unavailable")}</span></div><footer><button type="button" class="tool-button" data-factory-view="Overview" data-strategy-id="${UI.escapeHtml(x.strategy_id)}">View Candidate</button><button type="button" class="tool-button" data-factory-view="Report" data-strategy-id="${UI.escapeHtml(x.strategy_id)}">View Report</button><button type="button" class="tool-button" data-factory-view="Charts" data-strategy-id="${UI.escapeHtml(x.strategy_id)}">View Charts</button><button type="button" class="tool-button" data-factory-action="allocation" data-strategy-id="${UI.escapeHtml(x.strategy_id)}">Generate Allocation Draft</button><button type="button" class="tool-button factory-remove-button" data-factory-action="remove" data-strategy-id="${UI.escapeHtml(x.strategy_id)}">Remove from Candidate Portfolio</button></footer><details class="factory-debug-collapsed"><summary>Show artifact path</summary><code>${UI.escapeHtml(x.artifact_path||"candidate_portfolio_draft.json")}</code></details></article>`}).join("")||"<p>No candidate portfolio drafts.</p>"}</div>`}

