function factoryPortfolioAdmissionPanel(f,portfolio,drafts,applied){const p=factoryPipelineSummary(f),allowed=!!p.candidate_allowed,reason=allowed?"Admission requires explicit governance review before any paper workflow.":factoryAdmissionDisabledReason(),disabled=allowed?"":"disabled";return factorySection("Portfolio Admission / Paper Apply Flow","Contract only; no paper ledger mutation",`<div class="factory-detail-grid readable"><div><span>Candidate allowed?</span><b>${UI.escapeHtml(String(allowed))}</b></div><div><span>Candidate drafts count</span><b>${portfolio.length}</b></div><div><span>Allocation draft status</span><b>${drafts.length?`${drafts.length} draft(s)`:"No allocation draft"}</b></div><div><span>Paper apply status</span><b>${applied.length?`${applied.length} applied artifact(s)`:"Not applied"}</b></div><div><span>Admission reason</span><b>${UI.escapeHtml(reason)}</b></div></div><div class="factory-actions"><button class="tool-button ${allowed?"":"factory-disabled"}" type="button" ${disabled} title="${UI.escapeHtml(reason)}">Add to Candidate Portfolio</button><button class="tool-button ${allowed?"":"factory-disabled"}" type="button" ${disabled} title="${UI.escapeHtml(reason)}">Generate Allocation Draft</button><button class="tool-button factory-disabled" type="button" disabled title="Paper apply always requires a future explicit confirmation step.">Apply to Paper Portfolio</button></div><div class="memo"><p>Candidate allowed strategy: Add to Candidate Portfolio -> Generate Allocation Draft -> Review Weight / Cost / Risk Impact -> Confirm Apply to Paper Portfolio -> Combined recompute -> transaction cost / portfolio risk updated.</p><p>No paper ledger mutation is performed from this operator view cleanup.</p></div><details class="factory-collapsed-section"><summary>Expand old drafts</summary>${factoryCandidatePortfolioPanel(portfolio,selectedFactoryCandidate(f))}</details>`)}

