function strategyFactoryPage(){const f=factoryPayload(),materials=f.intake?.materials||[],candidate=selectedFactoryCandidate(f),candidates=f.candidates?.length?f.candidates:(candidate?[candidate]:[]),counts=f.backend_counts||{},portfolio=f.candidate_portfolio||[],drafts=f.allocation_drafts||[],applied=f.applied_paper_strategies||[],mode=factoryHasReviewMode(f)?"Review Mode":"Run Mode";return `<main class="main-stage"><div class="page workflow-page strategy-factory-page readable-layout operator-workflow">${pageTitle("Strategy Factory",`${mode}: upload/select if needed, then review ranked evidence and admission status`)}${secondaryStageNote("Strategy Factory safety boundary",[["PROTOTYPE_ONLY","Research candidates are not live or institutionally validated strategies."],["BATCH_SCOPE","Run Selected Batch uses only checked materials; historical uploads stay collapsed."],["USER_CONFIRMATION","Candidate admission remains disabled when candidate_allowed=false; brokerage execution remains disabled."]])}${factoryIntakeRunControlPanel(materials,counts,f)}${factoryCurrentRunSummaryPanel(f,candidate,portfolio,drafts,applied)}${factoryFullPipelineStatusCompact(f)}${factorySection("Variant Ranking / Best Variant","Primary result from existing Gate 3B/Gate 4 artifacts",factoryVariantReviewPanel(f))}${factorySelectedEvidencePanel(f)}${factorySection("Selected Variant Detail","Click one ranking row to inspect exactly one variant",factoryVariantDetail(f))}${factoryResultProvenancePanel(f)}${factoryPortfolioAdmissionPanel(f,portfolio,drafts,applied)}${factoryCandidateActionPanel(candidate,portfolio,drafts,applied)}${factoryArchivesDebugPanel(f,candidates,portfolio,drafts)}</div></main>`}

