function factorySelectedVariantWorkspace(f){const tab=state.selectedFactoryWorkspaceTab||"Summary",v=selectedFactoryVariant(f);if(!v)return factorySection("Selected Variant / Evidence Workspace","No selected variant",`<div class="na-block"><strong>No selected variant</strong><span>Run variant ranking artifacts before review.</span></div>`);let body;if(tab==="Evidence")body=factorySelectedEvidencePanel(f);else if(tab==="Backtest"){const m=v.metrics||{};body=factorySection("Backtest","Artifact-bound metrics",`<div class="factory-report-metrics readable"><span><b>Sharpe</b>${factoryEvidenceValue(m.sharpe,v.artifact_paths?.metrics,"ratio")}</span><span><b>Annual return</b>${factoryEvidenceValue(m.annual_return,v.artifact_paths?.metrics,"percent")}</span><span><b>Max drawdown</b>${factoryEvidenceValue(m.max_drawdown,v.artifact_paths?.metrics,"percent")}</span><span><b>Date range</b>${UI.escapeHtml(m.date_range||"Missing Evidence")}</span></div>`)}else if(tab==="ML"){const ml=v.ml_diagnostics||{};body=factorySection("ML","Diagnostics artifact summary",`<div class="factory-detail-grid readable"><div><span>Model</span><b>${factoryEvidenceValue(ml.model,v.artifact_paths?.ml_diagnostics)}</b></div><div><span>IC</span><b>${factoryEvidenceValue(ml.ic,v.artifact_paths?.ml_diagnostics,"ratio")}</b></div><div><span>Hit rate</span><b>${factoryEvidenceValue(ml.hit_rate,v.artifact_paths?.ml_diagnostics,"percent")}</b></div><div><span>Status</span><b>${factoryEvidenceValue(ml.status,v.artifact_paths?.ml_diagnostics)}</b></div></div>`)}else if(tab==="Robustness"){const r=v.robustness||{};body=factorySection("Robustness","Core robustness outputs",`<div class="factory-detail-grid readable"><div><span>Overall</span><b>${factoryEvidenceValue(r.overall||r.status,v.artifact_paths?.robustness)}</b></div><div><span>Cost sensitivity</span><b>${factoryEvidenceValue(r.cost_sensitivity,v.artifact_paths?.robustness)}</b></div><div><span>Lookback sensitivity</span><b>${factoryEvidenceValue(r.lookback_sensitivity,v.artifact_paths?.robustness)}</b></div><div><span>Benchmark status</span><b>${factoryEvidenceValue(r.benchmark_status,v.artifact_paths?.robustness)}</b></div></div>`)}else if(tab==="Provenance")body=factoryResultProvenancePanel(f);else body=factorySection("Summary","Selected ranked variant",factoryVariantDetail(f));return factorySection("Selected Variant / Evidence Workspace","One selected workspace for Summary, Evidence, Backtest, ML, Robustness, and Provenance",`<nav class="factory-workspace-tabs">${factoryWorkspaceTabButton("Summary","Summary")}${factoryWorkspaceTabButton("Evidence","Evidence")}${factoryWorkspaceTabButton("Backtest","Backtest")}${factoryWorkspaceTabButton("ML","ML")}${factoryWorkspaceTabButton("Robustness","Robustness")}${factoryWorkspaceTabButton("Provenance","Provenance")}</nav><div class="factory-workspace-body">${body}</div>`)}

function factoryPortfolioAdmissionPanel(f,portfolio,drafts,applied){const p=factoryPipelineSummary(f),allowed=!!p.candidate_allowed,reason=allowed?"Admission requires explicit governance review before any paper workflow.":factoryAdmissionDisabledReason(),disabled=allowed?"":"disabled";return factorySection("Portfolio Admission State","Current best variant admission only; old drafts collapsed",`<div class="factory-admission-compact"><div><span>Current best variant admission</span><b>${allowed?"Review required":"Disabled"}</b><em>${UI.escapeHtml(reason)}</em></div><div class="factory-actions"><button class="tool-button ${allowed?"":"factory-disabled"}" type="button" ${disabled} title="${UI.escapeHtml(reason)}">Add to Candidate Portfolio</button><button class="tool-button ${allowed?"":"factory-disabled"}" type="button" ${disabled} title="${UI.escapeHtml(reason)}">Generate Allocation Draft</button><button class="tool-button factory-disabled" type="button" disabled>Apply to Paper Portfolio</button></div><p>Future eligible flow: Add Candidate -> Allocation Draft -> Paper Apply -> Combined recompute.</p><details class="factory-collapsed-section"><summary>Existing old drafts (${portfolio.length})</summary>${factoryCandidatePortfolioPanel(portfolio,selectedFactoryCandidate(f))}</details></div>`)}

