if(!window.__strategyFactoryWorkspaceTabsDelegated){window.__strategyFactoryWorkspaceTabsDelegated=true;document.addEventListener("click",e=>{const tab=e.target.closest?.("[data-factory-workspace-tab]");if(!tab||state.selectedPage!=="Strategy Factory")return;e.preventDefault();e.stopPropagation();state.selectedFactoryWorkspaceTab=tab.dataset.factoryWorkspaceTab||"Summary";factoryRenderStable()})}

if(!window.__strategyFactoryMaterialLibraryDelegated){window.__strategyFactoryMaterialLibraryDelegated=true;document.addEventListener("click",e=>{const summary=e.target.closest?.(".factory-review-intake > summary");if(!summary||state.selectedPage!=="Strategy Factory")return;e.preventDefault();e.stopPropagation();state.factoryMaterialLibraryExpanded=!state.factoryMaterialLibraryExpanded;factoryRenderStable()})}

function factoryDateRangeLabel(value){if(!value)return "Missing Evidence";if(typeof value==="string")return value;if(typeof value==="object"){const start=value.start||value.from||value.begin||value.first_date,end=value.end||value.to||value.finish||value.last_date;if(start&&end)return `${UI.escapeHtml(String(start))} to ${UI.escapeHtml(String(end))}`}return "Missing Evidence"}

function factoryEvidenceSummaryFallback(variant){const paths=variant?.artifact_paths||{},hasEvidence=!!(paths.metrics||paths.ml_diagnostics||paths.robustness||paths.decision||paths.evidence_report);if(!hasEvidence)return "Missing Evidence";const recommendation=variant?.decision?.recommendation||variant?.ranking?.final_recommendation||"Watch";return `${UI.escapeHtml(recommendation)} \u2014 proxy-only evidence and robustness/risk limitations prevent Candidate admission.`}

function factoryStyledReportViewer(text,variant,f){let summary=factoryMarkdownSection(text,["executive summary","summary","thesis"]);if(summary==="Missing Evidence")summary=factoryEvidenceSummaryFallback(variant);const backtest=factoryMarkdownSection(text,["backtest","metrics"]),ml=factoryMarkdownSection(text,["ml diagnostics","ml","machine learning"]),robust=factoryMarkdownSection(text,["robustness","stress"]),limits=factoryMarkdownSection(text,["limitations","limit"]),decision=factoryMarkdownSection(text,["final decision","recommendation","decision"]);return `<div class="factory-styled-report-viewer">${factoryEvidenceMetricCards(f,variant)}<div class="factory-report-section-grid">${factoryReadableMarkdownBlock("Executive Summary",summary)}${factoryReadableMarkdownBlock("Variant",variant?.variant_name||variant?.variant_id||"Missing Evidence")}${factoryReadableMarkdownBlock("Backtest",backtest)}${factoryReadableMarkdownBlock("ML Diagnostics",ml)}${factoryReadableMarkdownBlock("Robustness",robust)}${factoryReadableMarkdownBlock("Limitations",limits)}${factoryReadableMarkdownBlock("Final Decision",decision)}</div><details class="factory-debug-collapsed"><summary>Raw markdown</summary>${factoryMarkdownPreview(text)}</details></div>`}

function factoryResultProvenancePanel(f){const review=factoryVariantReviewPayload(f),v=selectedFactoryVariant(f)||{},m=v.metrics||{},paths=v.artifact_paths||{},source=review.source_artifacts||{},symbols=[...(v.universe_or_proxy||[]),v.benchmark].filter(Boolean),dataDecision=v.decision?.candidate_allowed?"READY_FOR_GOVERNANCE_REVIEW":"PROXY_ONLY / WATCH";return factorySection("Result Provenance","Every displayed value must resolve to an artifact source",`<div class="factory-detail-grid readable"><div><span>Source run id</span><b>${UI.escapeHtml(review.run_id||factoryRunId(f)||"Missing Evidence")}</b></div><div><span>Variant id</span><b>${UI.escapeHtml(v.variant_id||"Missing Evidence")}</b></div><div><span>Data mode</span><b>${UI.escapeHtml((m.prototype_proxy_only||String(v.decision?.reason||"").toLowerCase().includes("proxy"))?"PROXY_ONLY":"LOCAL_ARTIFACT")}</b></div><div><span>Data decision</span><b>${UI.escapeHtml(dataDecision)}</b></div><div><span>Symbols used</span><b>${UI.escapeHtml(symbols.join(", ")||"Missing Evidence")}</b></div><div><span>Date range</span><b>${factoryDateRangeLabel(m.date_range)}</b></div><div><span>Metrics source artifact</span><b>${UI.escapeHtml(paths.metrics||"Missing Evidence")}</b></div><div><span>ML source artifact</span><b>${UI.escapeHtml(paths.ml_diagnostics||"Missing Evidence")}</b></div><div><span>Robustness source artifact</span><b>${UI.escapeHtml(paths.robustness||"Missing Evidence")}</b></div><div><span>Evidence source artifact</span><b>${UI.escapeHtml(paths.evidence_report||v.evidence_report_path||"Missing Evidence")}</b></div><div><span>Ranking source artifact</span><b>${UI.escapeHtml(source.variant_ranking||review.ranking_report_path||"Missing Evidence")}</b></div><div><span>Candidate decision source artifact</span><b>${UI.escapeHtml(paths.decision||"Missing Evidence")}</b></div></div>`)}

function factorySelectedVariantWorkspace(f){const tab=state.selectedFactoryWorkspaceTab||"Summary",v=selectedFactoryVariant(f);if(!v)return factorySection("Selected Variant / Evidence Workspace","No selected variant",`<div class="na-block"><strong>No selected variant</strong><span>Run variant ranking artifacts before review.</span></div>`);let body;if(tab==="Evidence")body=factorySelectedEvidencePanel(f);else if(tab==="Backtest"){const m=v.metrics||{};body=factorySection("Backtest","Artifact-bound metrics",`<div class="factory-report-metrics readable"><span><b>Sharpe</b>${factoryEvidenceValue(m.sharpe,v.artifact_paths?.metrics,"ratio")}</span><span><b>Annual return</b>${factoryEvidenceValue(m.annual_return,v.artifact_paths?.metrics,"percent")}</span><span><b>Max drawdown</b>${factoryEvidenceValue(m.max_drawdown,v.artifact_paths?.metrics,"percent")}</span><span><b>Date range</b>${factoryDateRangeLabel(m.date_range)}</span></div>`)}else if(tab==="ML"){const ml=v.ml_diagnostics||{};body=factorySection("ML","Diagnostics artifact summary",`<div class="factory-detail-grid readable"><div><span>Model</span><b>${factoryEvidenceValue(ml.model,v.artifact_paths?.ml_diagnostics)}</b></div><div><span>IC</span><b>${factoryEvidenceValue(ml.ic,v.artifact_paths?.ml_diagnostics,"ratio")}</b></div><div><span>Hit rate</span><b>${factoryEvidenceValue(ml.hit_rate,v.artifact_paths?.ml_diagnostics,"percent")}</b></div><div><span>Status</span><b>${factoryEvidenceValue(ml.status,v.artifact_paths?.ml_diagnostics)}</b></div></div>`)}else if(tab==="Robustness"){const r=v.robustness||{};body=factorySection("Robustness","Core robustness outputs",`<div class="factory-detail-grid readable"><div><span>Overall</span><b>${factoryEvidenceValue(r.overall||r.status,v.artifact_paths?.robustness)}</b></div><div><span>Cost sensitivity</span><b>${factoryEvidenceValue(r.cost_sensitivity,v.artifact_paths?.robustness)}</b></div><div><span>Lookback sensitivity</span><b>${factoryEvidenceValue(r.lookback_sensitivity,v.artifact_paths?.robustness)}</b></div><div><span>Benchmark status</span><b>${factoryEvidenceValue(r.benchmark_status,v.artifact_paths?.robustness)}</b></div></div>`)}else if(tab==="Provenance")body=factoryResultProvenancePanel(f);else body=factorySection("Summary","Selected ranked variant",factoryVariantDetail(f));return factorySection("Selected Variant / Evidence Workspace","One selected workspace for Summary, Evidence, Backtest, ML, Robustness, and Provenance",`<nav class="factory-workspace-tabs">${factoryWorkspaceTabButton("Summary","Summary")}${factoryWorkspaceTabButton("Evidence","Evidence")}${factoryWorkspaceTabButton("Backtest","Backtest")}${factoryWorkspaceTabButton("ML","ML")}${factoryWorkspaceTabButton("Robustness","Robustness")}${factoryWorkspaceTabButton("Provenance","Provenance")}</nav><div class="factory-workspace-body">${body}</div>`)}

function factoryArtifactField(value,artifact,type){if(!artifact)return "Missing Evidence";if(value==null||value==="")return "Field unavailable in artifact";if(type==="date_range")return factoryDateRangeLabel(value);return type?factoryVariantMetricValue(value,type):UI.escapeHtml(String(value))}

function factoryDataQualityBadges(raw){if(!raw)return "Missing Evidence";const text=String(raw),parts=[];if(text.includes("PUBLIC_FALLBACK"))parts.push("PUBLIC FALLBACK");if(text.includes("NOT_PIT")||text.includes("NOT_POINT_IN_TIME"))parts.push("NOT PIT");if(text.includes("NOT_SURVIVORSHIP"))parts.push("NOT SURVIVORSHIP-FREE");if(!parts.length)parts.push(text.replaceAll("_"," "));return `<span class="factory-badge-row" title="${UI.escapeHtml(text)}">${parts.map(x=>`<span class="status-badge warning">${UI.escapeHtml(x)}</span>`).join("")}</span>`}

function factoryTurnoverYears(m){const rows=Number(m?.rows);if(Number.isFinite(rows)&&rows>0)return rows/252.0;const range=m?.date_range||{};const start=Date.parse(range.start||range.from||""),end=Date.parse(range.end||range.to||"");if(Number.isFinite(start)&&Number.isFinite(end)&&end>start)return (end-start)/(365.25*24*60*60*1000);return null}

function factoryTurnoverDisplay(m,artifact){if(!artifact)return "Missing Evidence";const unit=String(m?.turnover_unit||"").toUpperCase();const definition=m?.turnover_definition||"Turnover definition unavailable";if(unit==="MISSING_EVIDENCE")return "Missing Evidence";if(unit==="ANNUALIZED_ONE_WAY_MULTIPLE"){const annualized=Number(m?.annualized_turnover??m?.turnover_value??m?.turnover);if(!Number.isFinite(annualized))return "Turnover definition unavailable";return `<span title="${UI.escapeHtml(`${definition} Average rebalance turnover: ${m?.average_rebalance_turnover??"Missing Evidence"}; frequency/year: ${m?.rebalance_frequency_per_year??"Missing Evidence"}.`)}">${UI.displayNumber(annualized,{minimumFractionDigits:2,maximumFractionDigits:2})}x / year</span>`}const raw=Number(m?.turnover);if(!Number.isFinite(raw))return "Turnover definition unavailable";const years=factoryTurnoverYears(m);if(!years||years<=0)return `<span title="Raw cumulative one-way turnover from artifact: ${UI.escapeHtml(String(m.turnover))}x">Turnover definition unavailable</span>`;const annualized=raw/years;return `<span title="Raw artifact turnover is cumulative one-way turnover: ${UI.escapeHtml(String(m.turnover))}x over ${UI.escapeHtml(String(m.rows||"unknown"))} rows. UI displays raw / backtest years.">${UI.displayNumber(annualized,{minimumFractionDigits:1,maximumFractionDigits:1})}x / year</span>`}

function factoryDataModeForVariant(v){const m=v?.metrics||{},reason=String(v?.decision?.reason||v?.ranking?.reason||"").toLowerCase();return (m.prototype_proxy_only||reason.includes("proxy"))?"PROXY_ONLY":"LOCAL_ARTIFACT"}

function factoryWorkspaceInterpretation(kind,v){if(kind==="ml")return "ML diagnostics are mixed/weak; not sufficient for Candidate.";if(kind==="robustness")return "Robustness is WATCH, so Candidate admission remains blocked.";return "Watch - proxy-only evidence and robustness/risk limitations prevent Candidate admission."}

function factoryAvailabilityChecklist(paths){return `<div class="factory-detail-grid readable">${[["Variant spec",paths.variant_spec],["Metrics",paths.metrics],["ML diagnostics",paths.ml_diagnostics],["Robustness",paths.robustness],["Evidence report",paths.evidence_report],["Decision",paths.decision]].map(([k,v])=>`<div><span>${UI.escapeHtml(k)}</span><b>${v?"Available":"Missing Evidence"}</b></div>`).join("")}</div>`}

function factoryCompactPathDetails(paths,extra=""){return `<details class="factory-debug-collapsed"><summary>Show artifact paths</summary><div class="factory-detail-grid readable">${Object.entries(paths||{}).map(([k,v])=>`<div><span>${UI.escapeHtml(k)}</span><b>${UI.escapeHtml(v||"Missing Evidence")}</b></div>`).join("")}${extra}</div></details>`}

