function factorySandboxPayload(f){return f.sandbox||{state:"NOT_ADDED",status:"NOT_ADDED",sandbox:{},artifacts:{}}}

function factorySandboxState(f){const s=factorySandboxPayload(f);return s.state||s.status||s.sandbox?.status||"NOT_ADDED"}

function factorySandboxAdmission(f){const s=factorySandboxPayload(f);return s.sandbox_admission||s.sandbox||{}}

function factorySandboxDownstream(f){return factorySandboxAdmission(f).downstream_targets||{"Strategy Monitor":"PENDING_NEXT_PAPER_REFRESH","Allocation/Rebalance":"PENDING_NEXT_PAPER_REFRESH","Portfolio NAV/P&L":"PENDING_NEXT_PAPER_REFRESH","Risk Contribution":"PENDING_RISK_RECALCULATION","Correlation":"PENDING_NEXT_PAPER_REFRESH","Combined Strategy":"PENDING_COMBINED_RECOMPUTE"}}

function factorySandboxRecommendation(v){return String(v?.ranking?.final_recommendation||v?.decision?.recommendation||v?.final_recommendation||"").trim()}

function factorySandboxMetricsExist(v){const m=v?.metrics||{};return m.status!=="BLOCKED"&&(m.sharpe!=null||m.annual_return!=null||m.max_drawdown!=null)}

function factorySandboxEligibility(f){const v=factoryAdmissionVariant(f),rec=factorySandboxRecommendation(v),lower=rec.toLowerCase(),metrics=factorySandboxMetricsExist(v);if(["reject","blocked","block"].includes(lower))return {eligible:false,reason:"Paper sandbox disabled: rejected or blocked variants cannot be monitored.",variant:v,recommendation:rec};if(!["watch","modify"].includes(lower))return {eligible:false,reason:"Paper sandbox requires a Watch or Modify research recommendation.",variant:v,recommendation:rec};if(!metrics)return {eligible:false,reason:"Paper sandbox disabled: backtest/metrics evidence is required.",variant:v,recommendation:rec};return {eligible:true,reason:"Eligible for user-confirmed paper-only sandbox monitoring.",variant:v,recommendation:rec}}

function factorySandboxProposedWeight(v){const score=Number(v?.ranking?.evidence_score||0),sharpe=Number(v?.metrics?.sharpe||0);return score>=55&&sharpe>=0.25?0.01:0.005}

function factorySandboxCost(weight){return 1000000*weight*0.0005}

function factorySandboxEvidenceField(value,type){if(value==null||value==="")return "Missing Evidence";return type==="percent"?UI.percent(value,2):type==="money"?UI.money(value):type==="ratio"?UI.displayNumber(value,{maximumFractionDigits:2}):UI.escapeHtml(String(value))}

function factorySandboxKey(f){const review=factoryVariantReviewPayload(f),variant=factoryAdmissionVariant(f);return {runId:review.run_id||factoryRunId(f)||"",variantId:variant.variant_id||""}}

function factorySandboxConfirmationActive(f){const key=factorySandboxKey(f);return !!state.factorySandboxConfirmationChecked&&state.factorySandboxConfirmationRunId===key.runId&&state.factorySandboxConfirmationVariantId===key.variantId}

function factorySandboxDisplayState(f){const raw=factorySandboxState(f),elig=factorySandboxEligibility(f);if(raw==="SANDBOX_MONITORING")return "SANDBOX_MONITORING";if(!elig.eligible)return "BLOCKED";return factorySandboxConfirmationActive(f)?"READY_FOR_CONFIRMATION":"NOT_ADDED"}

