async function factoryRunSandboxAction(button){const snap=factoryViewportSnapshot(),f=factoryPayload(),review=factoryVariantReviewPayload(f),variant=factoryAdmissionVariant(f),runId=review.run_id||factoryRunId(f),variantId=variant.variant_id;if(!runId||!variantId){toast("Run id and variant id required for portfolio monitor action.","negative");return}if(factorySandboxState(f)==="SANDBOX_MONITORING"){state.selectedPage="Strategy Monitor";render();factoryRestoreViewport(snap);return}if(!factorySandboxConfirmationActive(f)){state.strategyFactoryStatusMessage="Add to Portfolio requires explicit simulated/research confirmation. No artifact was written.";factoryRenderStable();factoryRestoreViewport(snap);toast("Confirm simulated monitoring first.","warning");return}const weight=Math.min(factorySandboxProposedWeight(variant),0.01);try{state.strategyFactoryBusy=true;factoryRenderStable();factoryRestoreViewport(snap);const result=await strategyFactoryApi("/api/strategy-factory/sandbox/add",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({run_id:runId,variant_id:variantId,user_confirmation:true,target_weight:weight,paper_only:true,live_trading:false,override_reason:"User confirmed Add to Portfolio for simulated research monitoring."})});state.strategyFactoryStatusMessage=result.message||"Strategy added to Portfolio Monitor.";toast(state.strategyFactoryStatusMessage,"positive")}catch(err){state.strategyFactoryStatusMessage=err.message;toast(err.message,"negative")}finally{state.strategyFactoryBusy=false;await refreshStrategyFactory();factoryRenderStable();factoryRestoreViewport(snap)}}

