  ctx.strokeStyle="#48676d";ctx.lineWidth=1.2;ctx.beginPath();ctx.moveTo(p.l,zeroY+.5);ctx.lineTo(w-p.r,zeroY+.5);ctx.stroke();

  const grad=ctx.createLinearGradient(0,p.t,0,zeroY);grad.addColorStop(0,"#19aef530");grad.addColorStop(1,"#19aef500");ctx.beginPath();ctx.moveTo(pts[0].x,zeroY);pts.forEach(q=>ctx.lineTo(q.x,q.y));ctx.lineTo(pts.at(-1).x,zeroY);ctx.closePath();ctx.fillStyle=grad;ctx.fill();

