  if(hasIntr){const last=pts.at(-1),ix=p.l+plotW,iy=p.t+(max-intrNav)/range*(plotH*.66),ipnl=Number(intr.estimated_pnl);commandPoints.push({x:ix,y:iy,row:null,index:rows.length,intraday:true});ctx.setLineDash([6,5]);ctx.beginPath();ctx.moveTo(last.x,last.y);ctx.lineTo(ix,iy);ctx.strokeStyle="#e6b94f";ctx.lineWidth=2;ctx.stroke();ctx.setLineDash([]);if(hasIntrPnl){const barH=Math.max(3,Math.abs(ipnl)/maxPnl*(plotH*.18));ctx.fillStyle=ipnl>=0?"#23d47766":"#ff4f3d66";ctx.fillRect(ix-5,ipnl>=0?zeroY-barH:zeroY,10,barH)}ctx.beginPath();ctx.arc(ix,iy,4.6,0,Math.PI*2);ctx.fillStyle="#e6b94f";ctx.fill();ctx.strokeStyle="#f7df8a";ctx.lineWidth=1.4;ctx.stroke();ctx.fillStyle="#e6b94f";ctx.textAlign="center";ctx.fillText(sessionLabel(c),ix,h-12);ctx.font="bold 15px Arial Narrow";const estLabel=UI.money(intrNav),tw=ctx.measureText(estLabel).width+14,lx=Math.min(ix+7,w-tw-3);ctx.fillStyle="#e6b94f";ctx.fillRect(lx,iy-11,tw,22);ctx.fillStyle="#1b1300";ctx.fillText(estLabel,lx+tw/2,iy)}

  canvas.__commandChartPoints=commandPoints;

