async function fetchSnapshotPayload(){const controller=new AbortController(),timer=setTimeout(()=>controller.abort(),SNAPSHOT_LOAD_TIMEOUT_MS);try{const r=await fetch(`/api/operational-snapshot?ts=${Date.now()}`,{cache:"no-store",headers:{"Cache-Control":"no-store"},signal:controller.signal});if(!r.ok)throw new Error(`Operational snapshot unavailable (${r.status})`);const text=await r.text();try{return JSON.parse(text)}catch(e){throw new Error(`Operational snapshot invalid JSON: ${e.message}`)}}catch(e){if(e?.name==="AbortError")throw new Error(`Operational snapshot timed out after ${SNAPSHOT_LOAD_TIMEOUT_MS/1000}s`);throw e}finally{clearTimeout(timer)}}
async function fetchSummaryPayload(){const controller=new AbortController(),timer=setTimeout(()=>controller.abort(),12000);try{const r=await fetch(`/api/snapshot-summary?ts=${Date.now()}`,{cache:"no-store",headers:{"Cache-Control":"no-store"},signal:controller.signal});if(!r.ok)throw new Error(`Snapshot summary unavailable (${r.status})`);const text=await r.text();try{return JSON.parse(text)}catch(e){throw new Error(`Snapshot summary invalid JSON: ${e.message}`)}}catch(e){if(e?.name==="AbortError")throw new Error("Snapshot summary timed out after 12s");throw e}finally{clearTimeout(timer)}}
